    var avgCohesion = groups.length ? Math.round(groups.reduce(function(total, row) { return total + row.cohesion; }, 0) / groups.length) : 0;
    var membersTotal = groups.reduce(function(total, row) { return total + row.members.length; }, 0);
    var thresholdTotal = groups.reduce(function(total, row) { return total + row.thresholds; }, 0);
    return { field: field, label: interestGroupLabel(field), groups: groups, types: types, total: rows.length, avgInfluence: avgInfluence, avgCohesion: avgCohesion, membersTotal: membersTotal, thresholdTotal: thresholdTotal, config: config };
