    var redistributionRate = economyRatio(root.redistributionRate != null ? root.redistributionRate : root.tributeAdjustment, 0.3);
    var taxRate = economyRatio(root.taxRate, 0.1);
    var inflationRate = economyRatio(root.inflationRate, 0.02);
    var tradeBonus = economyRatio(root.tradeBonus, 0.1);
    var agricultureMultiplier = economyNumber(root.agricultureMultiplier, 1);
