    var productiveIndex = Math.round(((agricultureMultiplier + commerceMultiplier) / 2) * 100);
    var pressureIndex = Math.round((tributeRatio * 45) + (taxRate * 130) + (inflationRate * 160));
    var circulationIndex = Math.round((tradeBonus * 100) + (redistributionRate * 60) + (commerceMultiplier * 18));
    var risks = [];
    var cycle = String(root.economicCycle || '').toLowerCase();
    if (/recession|depression|declin|crisis|衰|危|萧/.test(cycle)) risks.push('经济周期偏弱，开局财政承压');
