      var text = String(label || '').trim();
      if (!text) return null;
      var key = type + ':' + text;
      if (nodeMap[key]) return nodeMap[key];
      var node = { id: key, label: text, type: type, familyIndex: familyIndex, degree: 0, x: 0, y: 0 };
      nodeMap[key] = node;
