    for (var i = 0; i < parts.length - 1; i += 1) {
      if (node == null) return root;
      node = /^\d+$/.test(parts[i]) ? node[Number(parts[i])] : node[parts[i]];
    }
    if (node == null) return root;
    var last = parts[parts.length - 1];
