  function saveAiAuthoringWorkbench(options) {
    var sc = state.scenario || {};
    var defaults = aiAuthoringDefaults();
    sc.aiAutoEnrich = !!(document.querySelector('[data-ai-authoring-toggle="aiAutoEnrich"]') || {}).checked;
    sc.isFullyDetailed = !!(document.querySelector('[data-ai-authoring-toggle="isFullyDetailed"]') || {}).checked;
    var promptInput = document.querySelector('[data-ai-authoring-textarea="customPrompt"]');
    if (promptInput) sc.customPrompt = promptInput.value;
    var currentReq = isObject(sc.modelRequirements) ? clone(sc.modelRequirements) : {};
    var nextReq = clone(currentReq);
    Array.from(document.querySelectorAll('[data-ai-authoring-model-field]')).forEach(function(input) {
      var key = input.dataset.aiAuthoringModelField;
      var type = input.dataset.aiAuthoringKind || 'text';
      if (!key) return;
      if (type === 'boolean') nextReq[key] = !!input.checked;
      else if (type === 'number') nextReq[key] = input.value === '' ? '' : numberOr(input.value, nextReq[key] || 0);
      else if (type === 'list') nextReq[key] = splitList(input.value);
      else nextReq[key] = input.value;
    });
    sc.modelRequirements = Object.keys(nextReq).length ? nextReq : clone(defaults.modelRequirements);
    sc.customPresets = collectAiPresetRows(aiAuthoringArray(sc.customPresets));
    state.scenario = sc;
    state.selectedField = state.selectedField && isAiAuthoringField(state.selectedField) ? state.selectedField : 'customPrompt';
    state.selectedModuleId = inferModuleForField(state.selectedField);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存 AI 制作配置', 'ai authoring');
    if (!options || !options.silent) {
      renderAll();
      setStatus('AI 生成状态、模型门槛和预设已保存', 'good');
    }
    return {
      aiAutoEnrich: sc.aiAutoEnrich,
      isFullyDetailed: sc.isFullyDetailed,
      customPrompt: sc.customPrompt,
      modelRequirements: clone(sc.modelRequirements),
      customPresets: clone(sc.customPresets)
    };
  }

  function scaffoldAiAuthoringWorkbench(options) {
    var sc = state.scenario || {};
    var defaults = aiAuthoringDefaults();
    if (sc.aiAutoEnrich == null) sc.aiAutoEnrich = defaults.aiAutoEnrich;
    if (sc.isFullyDetailed == null) sc.isFullyDetailed = defaults.isFullyDetailed;
    if (sc.customPrompt == null) sc.customPrompt = defaults.customPrompt;
    if (!isObject(sc.modelRequirements)) sc.modelRequirements = {};
    Object.keys(defaults.modelRequirements).forEach(function(key) {
      if (sc.modelRequirements[key] == null || sc.modelRequirements[key] === '') sc.modelRequirements[key] = clone(defaults.modelRequirements[key]);
    });
    if (!Array.isArray(sc.customPresets)) sc.customPresets = aiAuthoringArray(sc.customPresets);
    if (!sc.customPresets.length) sc.customPresets.push(aiAuthoringDefaultPreset());
    state.scenario = sc;
    state.selectedField = state.selectedField && isAiAuthoringField(state.selectedField) ? state.selectedField : 'customPrompt';
    state.selectedModuleId = inferModuleForField(state.selectedField);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('补齐 AI 制作配置', 'ai authoring');
    if (!options || !options.silent) {
      renderAll();
      setStatus('已补齐 AI 生成状态、模型门槛和预设骨架', 'good');
    }
    return {
      aiAutoEnrich: sc.aiAutoEnrich,
      isFullyDetailed: sc.isFullyDetailed,
      customPrompt: sc.customPrompt,
      modelRequirements: clone(sc.modelRequirements),
      customPresets: clone(sc.customPresets)
    };
  }

  function addAiPresetRow() {
    if (document.querySelector('[data-structured-kind="ai-authoring"]')) saveAiAuthoringWorkbench({ silent: true });
    if (!Array.isArray(state.scenario.customPresets)) state.scenario.customPresets = aiAuthoringArray(state.scenario.customPresets);
    state.scenario.customPresets.push(aiAuthoringDefaultPreset());
    state.selectedField = 'customPresets';
    state.selectedModuleId = inferModuleForField('customPresets');
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('新增 AI 预设', 'customPresets');
    renderAll();
    setStatus('已新增 AI 生成预设', 'good');
    return clone(state.scenario.customPresets[state.scenario.customPresets.length - 1]);
  }

  function isExternalForceField(field) {
    return field === 'externalForces';
  }

  function externalForceDefault() {
    return {
      id: uniqueId('force'),
      name: '新外部势力',
      type: 'neighbor',
      stance: 'neutral',
      relation: '未定',
      threatLevel: 25,
      desc: '待补外部势力背景、对本剧本的压力与可互动空间。',
      goals: [],
      triggers: [],
      note: ''
    };
  }

  function externalForceRows(value) {
    if (Array.isArray(value)) return clone(value);
    if (value == null || value === '') return [];
    if (isObject(value)) {
      return Object.keys(value).map(function(key) {
        var raw = value[key];
        var item = isObject(raw) ? clone(raw) : { desc: raw };
        if (!item.id) item.id = key;
        if (!item.name) item.name = key;
        return item;
      });
    }
    return String(value).split(/\n+/).map(function(line, index) {
      return { id: uniqueId('force'), name: '外部势力 #' + (index + 1), desc: line.trim(), threatLevel: 0 };
    }).filter(function(item) { return item.desc; });
  }

  function externalForceValue(item, keys, fallback) {
    if (!isObject(item)) return fallback || '';
    for (var i = 0; i < keys.length; i += 1) {
      var key = keys[i];
      if (item[key] != null && item[key] !== '') return item[key];
    }
    return fallback || '';
  }

  function externalForceThreat(item) {
    var raw = externalForceValue(item, ['threatLevel', 'threat', 'pressure', 'risk'], 0);
    var value = numberOr(raw, 0);
    if (value < 0) value = 0;
    if (value > 100) value = 100;
    return value;
  }

  function externalForceListValue(item, keys) {
    var value = externalForceValue(item, keys, []);
    if (Array.isArray(value)) return value;
    if (value == null || value === '') return [];
    return splitList(value);
  }

  function buildExternalForcesPreview(value) {
    var rows = externalForceRows(value);
    var totalThreat = rows.reduce(function(sum, item) { return sum + externalForceThreat(item); }, 0);
    var highThreat = rows.filter(function(item) { return externalForceThreat(item) >= 70; });
    var named = rows.filter(function(item) { return !!String(externalForceValue(item, ['name', 'title', 'id'], '')).trim(); });
    var top = rows.slice().sort(function(a, b) { return externalForceThreat(b) - externalForceThreat(a); })[0] || null;
    var warnings = [];
    if (!rows.length) warnings.push('尚未登记外部势力，边患、藩属和外交压力会缺少制作入口。');
    if (rows.length && named.length < rows.length) warnings.push('有外部势力缺少名称，建议补齐以便事件和外交引用。');
    if (highThreat.length >= 2) warnings.push('高威胁外部势力较多，建议为每个势力写清触发条件和玩家可应对动作。');
    return {
      total: rows.length,
      highThreat: highThreat.length,
      avgThreat: rows.length ? Math.round(totalThreat / rows.length) : 0,
      topName: top ? externalForceValue(top, ['name', 'title', 'id'], '未命名势力') : '',
      topThreat: top ? externalForceThreat(top) : 0,
      rows: rows,
      warnings: warnings
    };
  }

  function collectExternalForceRows(existing) {
    var rows = [];
    Array.from(document.querySelectorAll('[data-external-force-row]')).forEach(function(row) {
      if (row.querySelector('[data-external-force-delete]') && row.querySelector('[data-external-force-delete]').checked) return;
      var index = Number(row.dataset.externalForceIndex);
      var original = Number.isFinite(index) && Array.isArray(existing) && isObject(existing[index]) ? clone(existing[index]) : {};
      ['id', 'name', 'type', 'stance', 'relation', 'desc', 'note'].forEach(function(key) {
        var input = row.querySelector('[data-external-force-field="' + key + '"]');
        if (input) original[key] = input.value;
      });
      var threat = row.querySelector('[data-external-force-field="threatLevel"]');
      if (threat) original.threatLevel = threat.value === '' ? '' : numberOr(threat.value, original.threatLevel || 0);
      ['goals', 'triggers'].forEach(function(key) {
        var input = row.querySelector('[data-external-force-field="' + key + '"]');
        if (input) original[key] = splitList(input.value);
      });
      if (!original.id) original.id = uniqueId('force');
      rows.push(original);
    });
    return rows;
  }

  function saveExternalForcesWorkbench(options) {
    var existing = externalForceRows(state.scenario.externalForces);
    state.scenario.externalForces = collectExternalForceRows(existing);
    state.selectedField = 'externalForces';
    state.selectedModuleId = inferModuleForField('externalForces');
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存外部势力', state.scenario.externalForces.length + ' 个势力');
    if (!options || !options.silent) {
      renderAll();
      setStatus('外部势力已保存：' + state.scenario.externalForces.length + ' 个', 'good');
    }
    return clone(state.scenario.externalForces);
  }

  function addExternalForceRow() {
    if (document.querySelector('[data-structured-kind="external-forces"]')) saveExternalForcesWorkbench({ silent: true });
    if (!Array.isArray(state.scenario.externalForces)) state.scenario.externalForces = externalForceRows(state.scenario.externalForces);
    state.scenario.externalForces.push(externalForceDefault());
    state.selectedField = 'externalForces';
    state.selectedModuleId = inferModuleForField('externalForces');
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('新增外部势力', 'externalForces[' + (state.scenario.externalForces.length - 1) + ']');
    renderAll();
    setStatus('已新增外部势力', 'good');
    return clone(state.scenario.externalForces[state.scenario.externalForces.length - 1]);
  }

  var RELATION_SEED_FIELDS = ['initialEnYuan', 'initialPatronNetwork'];

  function isRelationSeedField(field) {
    return RELATION_SEED_FIELDS.indexOf(field) >= 0;
  }

  function relationSeedActiveField(field) {
    if (isRelationSeedField(field)) return field;
    if (isRelationSeedField(state.selectedField)) return state.selectedField;
    return 'initialEnYuan';
  }

  function relationSeedSchema(field) {
    var key = relationSeedActiveField(field);
    if (key === 'initialPatronNetwork') {
      return {
        key: key,
        label: '初始靠山网络',
        shortLabel: '靠山网络',
        actorKey: 'patron',
        targetKey: 'client',
        actorLabel: '靠山/庇护者',
        targetLabel: '门生/被庇护者',
        actorPlaceholder: '赵构 / 张浚 / 秦桧',
        targetPlaceholder: '秦桧 / 门生集团',
        defaultType: 'patronage',
        defaultReason: '待补靠山关系',
        idPrefix: 'patron',
        addLabel: '新增靠山',
        emptyText: '暂无靠山网络。可以先补皇帝、宰执、主将与门生故吏的依附关系。'
      };
    }
    return {
      key: 'initialEnYuan',
      label: '初始恩怨',
      shortLabel: '恩怨种子',
      actorKey: 'source',
      targetKey: 'target',
      actorLabel: '发起者',
      targetLabel: '对象',
      actorPlaceholder: '岳飞 / 秦桧 / 金使',
      targetPlaceholder: '秦桧 / 岳飞 / 主战派',
      defaultType: 'resentment',
      defaultReason: '待补恩怨缘由',
      idPrefix: 'enyuan',
      addLabel: '新增恩怨',
      emptyText: '暂无初始恩怨。可以先补主战主和、旧案牵连、私怨与派系冲突。'
    };
  }

  function relationSeedDefault(field) {
    var schema = relationSeedSchema(field);
    var item = {
      id: uniqueId(schema.idPrefix),
      type: schema.defaultType,
      value: 50,
      reason: schema.defaultReason,
      trigger: '',
      note: ''
    };
    item[schema.actorKey] = '';
    item[schema.targetKey] = '';
    return item;
  }

  function relationSeedRows(field, value) {
    var schema = relationSeedSchema(field);
    if (Array.isArray(value)) return clone(value);
    if (value == null || value === '') return [];
    if (isObject(value)) {
      return Object.keys(value).map(function(key) {
        var raw = value[key];
        var item = isObject(raw) ? clone(raw) : { reason: raw };
        if (!item.id) item.id = key;
        if (!relationSeedValue(item, [schema.actorKey, 'source', 'patron', 'from', 'actor', 'person'], '')) item[schema.actorKey] = key;
        return item;
      });
    }
    return String(value).split(/\n+/).map(function(line) {
      var item = relationSeedDefault(schema.key);
      item.reason = line.trim();
      return item;
    }).filter(function(item) { return item.reason; });
  }

  function relationSeedValue(item, keys, fallback) {
    if (!isObject(item)) return fallback || '';
    for (var i = 0; i < keys.length; i += 1) {
      var key = keys[i];
      if (item[key] != null && item[key] !== '') return item[key];
    }
    return fallback || '';
  }

  function relationSeedActor(item, schema) {
    return relationSeedValue(item, [schema.actorKey, 'source', 'patron', 'from', 'actor', 'person', 'name'], '');
  }

  function relationSeedTarget(item, schema) {
    return relationSeedValue(item, [schema.targetKey, 'target', 'client', 'to', 'subject', 'receiver'], '');
  }

  function relationSeedStrength(item) {
    var raw = relationSeedValue(item, ['value', 'strength', 'score', 'weight', 'intensity'], 0);
    var value = numberOr(raw, 0);
    if (value < 0) value = 0;
    if (value > 100) value = 100;
    return value;
  }

  function relationSeedTone(item) {
    var text = String(relationSeedValue(item, ['type', 'kind', 'category', 'relation'], '') + ' ' +
      relationSeedValue(item, ['reason', 'desc', 'description', 'summary'], '')).toLowerCase();
    if (/怨|仇|恨|敌|嫌|罪|resent|enmity|hostile|offend|rival/.test(text)) return 'negative';
    if (/恩|亲|援|护|庇|靠山|信任|ally|favor|grace|patron|support|trust/.test(text)) return 'positive';
    return 'neutral';
  }

  function buildRelationSeedPreview(field, value) {
    var schema = relationSeedSchema(field);
    var rows = relationSeedRows(schema.key, value);
    var totalStrength = rows.reduce(function(sum, item) { return sum + relationSeedStrength(item); }, 0);
    var strong = rows.filter(function(item) { return relationSeedStrength(item) >= 70; });
    var missingEndpoints = rows.filter(function(item) {
      return !String(relationSeedActor(item, schema)).trim() || !String(relationSeedTarget(item, schema)).trim();
    });
    var positive = rows.filter(function(item) { return relationSeedTone(item) === 'positive'; }).length;
    var negative = rows.filter(function(item) { return relationSeedTone(item) === 'negative'; }).length;
    var top = rows.slice().sort(function(a, b) { return relationSeedStrength(b) - relationSeedStrength(a); })[0] || null;
    var topPair = '';
    if (top) {
      var actor = relationSeedActor(top, schema) || '未命名';
      var target = relationSeedTarget(top, schema) || '未命名';
      topPair = actor + ' -> ' + target;
    }
    var warnings = [];
    if (!rows.length) warnings.push(schema.label + '尚未登记，正式启动时相关系统缺少开局种子。');
    if (missingEndpoints.length) warnings.push(missingEndpoints.length + ' 条关系缺少双方名称，事件和人物引用会变弱。');
    if (strong.length >= 3) warnings.push('强关系较多，建议逐条写清触发条件，避免开局关系一次性过载。');
    if (schema.key === 'initialEnYuan' && rows.length && !negative) warnings.push('初始恩怨中尚未标记明显冲突，可补 type/reason 以便恩怨系统识别。');
    return {
      field: schema.key,
      label: schema.label,
      total: rows.length,
      strong: strong.length,
      missingEndpoints: missingEndpoints.length,
      positive: positive,
      negative: negative,
      avgStrength: rows.length ? Math.round(totalStrength / rows.length) : 0,
      topPair: topPair,
      topStrength: top ? relationSeedStrength(top) : 0,
      rows: rows,
      warnings: warnings
    };
  }

  function collectRelationSeedRows(field, existing) {
    var schema = relationSeedSchema(field);
    var rows = [];
    Array.from(document.querySelectorAll('[data-relation-seed-row]')).forEach(function(row) {
      if (row.querySelector('[data-relation-seed-delete]') && row.querySelector('[data-relation-seed-delete]').checked) return;
      var index = Number(row.dataset.relationSeedIndex);
      var original = Number.isFinite(index) && Array.isArray(existing) && isObject(existing[index]) ? clone(existing[index]) : {};
      ['id', 'type', 'reason', 'trigger', 'note'].forEach(function(key) {
        var input = row.querySelector('[data-relation-seed-field="' + key + '"]');
        if (input) original[key] = input.value;
      });
      var actor = row.querySelector('[data-relation-seed-field="actor"]');
      var target = row.querySelector('[data-relation-seed-field="target"]');
      var strength = row.querySelector('[data-relation-seed-field="value"]');
      if (actor) original[schema.actorKey] = actor.value;
      if (target) original[schema.targetKey] = target.value;
      if (strength) original.value = strength.value === '' ? '' : numberOr(strength.value, original.value || 0);
      if (!original.id) original.id = uniqueId(schema.idPrefix);
      rows.push(original);
    });
    return rows;
  }

  function saveRelationSeedWorkbench(field, options) {
    var key = relationSeedActiveField(field);
    var existing = relationSeedRows(key, state.scenario[key]);
    state.scenario[key] = collectRelationSeedRows(key, existing);
    state.selectedField = key;
    state.selectedModuleId = inferModuleForField(key);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存开局关系种子', key + ' · ' + state.scenario[key].length + ' 条');
    if (!options || !options.silent) {
      renderAll();
      setStatus('开局关系种子已保存：' + state.scenario[key].length + ' 条', 'good');
    }
    return clone(state.scenario[key]);
  }

  function addRelationSeedRow(field) {
    var panel = document.querySelector('[data-relation-seed-panel]');
    var key = relationSeedActiveField(field || (panel && panel.dataset.relationSeedField) || state.selectedField);
    if (panel) saveRelationSeedWorkbench(key, { silent: true });
    if (!Array.isArray(state.scenario[key])) state.scenario[key] = relationSeedRows(key, state.scenario[key]);
    state.scenario[key].push(relationSeedDefault(key));
    state.selectedField = key;
    state.selectedModuleId = inferModuleForField(key);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('新增开局关系种子', key + '[' + (state.scenario[key].length - 1) + ']');
    renderAll();
    setStatus('已新增开局关系种子', 'good');
    return clone(state.scenario[key][state.scenario[key].length - 1]);
  }

  var EVENT_LIBRARY_FIELDS = ['events', 'rigidHistoryEvents'];

  function isEventLibraryField(field) {
    return EVENT_LIBRARY_FIELDS.indexOf(field) >= 0;
  }

  function eventLibraryActiveField(field) {
    if (isEventLibraryField(field)) return field;
    if (isEventLibraryField(state.selectedField)) return state.selectedField;
    return 'events';
  }

  function eventLibrarySchema(field) {
    var key = eventLibraryActiveField(field);
    if (key === 'rigidHistoryEvents') {
      return {
        key: key,
        label: '硬历史事件',
        shortLabel: '硬历史',
        addLabel: '新增硬历史',
        defaultType: 'historical',
        defaultImportance: '关键',
        emptyText: '暂无硬历史事件。可以先补必发史实、锁定节点和必须触发的历史结果。'
      };
    }
    return {
      key: 'events',
      label: '事件库',
      shortLabel: '事件',
      addLabel: '新增事件',
      defaultType: 'historical',
      defaultImportance: '普通',
      emptyText: '暂无事件。可以先补开局事件、历史节点、条件事件和随机事件。'
    };
  }

  function eventLibraryDefault(field) {
    var schema = eventLibrarySchema(field);
    return {
      id: uniqueId('evt'),
      name: schema.addLabel,
      type: schema.defaultType,
      category: schema.defaultType,
      importance: schema.defaultImportance,
      trigger: '待定',
      effect: '待定',
      description: '待补事件说明',
      linkedChars: [],
      linkedFactions: [],
      triggered: false
    };
  }

  function eventLibraryValue(item, keys, fallback) {
    if (!isObject(item)) return fallback || '';
    for (var i = 0; i < keys.length; i += 1) {
      var key = keys[i];
      if (item[key] != null && item[key] !== '') return item[key];
    }
    return fallback || '';
  }

  function eventLibraryListValue(item, keys) {
    var value = eventLibraryValue(item, keys, []);
    if (Array.isArray(value)) return value.filter(Boolean);
    if (value == null || value === '') return [];
    return splitList(value);
  }

  function eventLibraryRows(field, value) {
    if (Array.isArray(value)) return clone(value);
    if (value == null || value === '') return [];
    if (isObject(value)) {
      var rows = [];
      Object.keys(value).forEach(function(key) {
        var raw = value[key];
        if (Array.isArray(raw)) {
          raw.forEach(function(item, index) {
            var row = isObject(item) ? clone(item) : { description: item };
            if (!row.id) row.id = key + '_' + index;
            if (!row.category) row.category = key;
            rows.push(row);
          });
          return;
        }
        var item = isObject(raw) ? clone(raw) : { description: raw };
        if (!item.id) item.id = key;
        if (!item.name) item.name = key;
        rows.push(item);
      });
      return rows;
    }
    return String(value).split(/\n+/).map(function(line, index) {
      var item = eventLibraryDefault(field);
      item.name = '事件 #' + (index + 1);
      item.description = line.trim();
      return item;
    }).filter(function(item) { return item.description; });
  }

  function buildEventLibraryPreview(field, value) {
    var schema = eventLibrarySchema(field);
    var rows = eventLibraryRows(schema.key, value);
    var timed = 0;
    var keyEvents = 0;
    var triggered = 0;
    var missingTrigger = 0;
    var linkedChars = 0;
    var linkedFactions = 0;
    var categories = {};
    rows.forEach(function(item, index) {
      var sort = eventTimelineSortKey(item, index);
      if (sort && (sort.dated || sort.bucket === 1)) timed += 1;
      if (eventTimelineTone(item) === 'major') keyEvents += 1;
      if (item && item.triggered) triggered += 1;
      if (!String(eventLibraryValue(item, ['trigger', 'condition', 'when', 'date', 'time'], '')).trim()) missingTrigger += 1;
      linkedChars += eventLibraryListValue(item, ['linkedChars', 'characters', 'chars']).length;
      linkedFactions += eventLibraryListValue(item, ['linkedFactions', 'factions', 'forces']).length;
      var category = eventLibraryValue(item, ['category', 'type', 'kind'], 'uncategorized');
      categories[category] = (categories[category] || 0) + 1;
    });
    var topCategories = Object.keys(categories).sort(function(a, b) {
      return categories[b] - categories[a] || a.localeCompare(b);
    }).slice(0, 5).map(function(key) {
      return { key: key, count: categories[key] };
    });
    var warnings = [];
    if (!rows.length) warnings.push(schema.label + '尚未建立，正式推演会缺少事件素材。');
    if (missingTrigger) warnings.push(missingTrigger + ' 条事件缺少触发条件，建议先补 trigger/date/turn。');
    if (rows.length && timed < Math.max(1, Math.ceil(rows.length / 3))) warnings.push('有明确时间或回合的事件偏少，时间线排序会不够稳定。');
    return {
      field: schema.key,
      label: schema.label,
      total: rows.length,
      timed: timed,
      keyEvents: keyEvents,
      triggered: triggered,
      missingTrigger: missingTrigger,
      linkedChars: linkedChars,
      linkedFactions: linkedFactions,
      categories: topCategories,
      rows: rows,
      warnings: warnings
    };
  }

  function renderEventLibraryEmptyState(schema) {
    var template = eventLibraryDefault(schema.key);
    template.id = 'evt_template';
    var keys = ['id', 'name', 'type', 'importance', 'trigger', 'effect', 'description'];
    var chips = keys.map(function(key) {
      var value = template[key];
      return '<span class="event-library-template-chip" data-event-library-template-field="' + escapeHtml(key) + '"><b>' + escapeHtml(key) + '</b><em>' + escapeHtml(value == null ? '' : String(value)) + '</em></span>';
    }).join('');
    return '<div class="event-library-empty" data-event-library-empty data-event-library-empty-field="' + escapeHtml(schema.key) + '">' +
      '<div class="event-library-empty-head"><div><b>' + escapeHtml(schema.label) + '为空</b><span>' + escapeHtml(schema.key) + ' · 0 条 · 首条模板已备好</span></div><em>先做一个触发点，再补结果和引用</em></div>' +
      '<div class="event-library-template-grid">' + chips + '</div>' +
      '<div class="event-library-empty-actions"><button class="ai-button" data-editor-command="add-event-library" data-event-library-add="' + escapeHtml(schema.key) + '">' + escapeHtml(schema.addLabel) + '</button><button class="mini-ai" data-ai-action="validate" data-field-ai="' + escapeHtml(schema.key) + '">AI 检查事件链</button></div>' +
    '</div>';
  }

  function collectEventLibraryRows(field, existing) {
    var rows = [];
    Array.from(document.querySelectorAll('[data-event-library-row]')).forEach(function(row) {
      if (row.querySelector('[data-event-library-delete]') && row.querySelector('[data-event-library-delete]').checked) return;
      var index = Number(row.dataset.eventLibraryIndex);
      var original = Number.isFinite(index) && Array.isArray(existing) && isObject(existing[index]) ? clone(existing[index]) : {};
      ['id', 'name', 'type', 'category', 'importance', 'trigger', 'effect', 'description'].forEach(function(key) {
        var input = row.querySelector('[data-event-library-field="' + key + '"]');
        if (input) original[key] = input.value;
      });
      ['year', 'month', 'day', 'turn'].forEach(function(key) {
        var input = row.querySelector('[data-event-library-field="' + key + '"]');
        if (!input) return;
        if (input.value !== '' || Object.prototype.hasOwnProperty.call(original, key)) {
          original[key] = input.value === '' ? '' : numberOr(input.value, original[key] || 0);
        }
      });
      ['linkedChars', 'linkedFactions'].forEach(function(key) {
        var input = row.querySelector('[data-event-library-field="' + key + '"]');
        if (input) original[key] = splitList(input.value);
      });
      var triggeredInput = row.querySelector('[data-event-library-field="triggered"]');
      if (triggeredInput) original.triggered = !!triggeredInput.checked;
      if (!original.id) original.id = uniqueId('evt');
      rows.push(original);
    });
    return rows;
  }

  function saveEventLibraryWorkbench(field, options) {
    var key = eventLibraryActiveField(field);
    var existing = eventLibraryRows(key, state.scenario[key]);
    state.scenario[key] = collectEventLibraryRows(key, existing);
    state.selectedField = key;
    state.selectedModuleId = inferModuleForField(key);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存事件库', key + ' · ' + state.scenario[key].length + ' 条');
    if (!options || !options.silent) {
      renderAll();
      setStatus('事件库已保存：' + state.scenario[key].length + ' 条', 'good');
    }
    return clone(state.scenario[key]);
  }

  function addEventLibraryRow(field) {
    var panel = document.querySelector('[data-event-library-panel]');
    var key = eventLibraryActiveField(field || (panel && panel.dataset.eventLibraryField) || state.selectedField);
    if (panel) saveEventLibraryWorkbench(key, { silent: true });
    if (!Array.isArray(state.scenario[key])) state.scenario[key] = eventLibraryRows(key, state.scenario[key]);
    state.scenario[key].push(eventLibraryDefault(key));
    state.selectedField = key;
    state.selectedModuleId = inferModuleForField(key);
    state.selectedEntityIndex = state.scenario[key].length - 1;
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('新增事件', key + '[' + state.selectedEntityIndex + ']');
    renderAll();
    setStatus('已新增事件条目', 'good');
    return clone(state.scenario[key][state.selectedEntityIndex]);
  }

  function saveGameSettingsWorkbench() {
    var current = isObject(state.scenario.gameSettings) ? clone(state.scenario.gameSettings) : {};
    current.startYear = numberOr(formValue('sg-startYear'), current.startYear || state.scenario.startYear || 0);
    current.startMonth = numberOr(formValue('sg-startMonth'), current.startMonth || 1);
    current.startDay = numberOr(formValue('sg-startDay'), current.startDay || 1);
    current.daysPerTurn = numberOr(formValue('sg-daysPerTurn'), current.daysPerTurn || 30);
    current.turnDuration = numberOr(formValue('sg-turnDuration'), current.turnDuration || 1);
    current.turnUnit = formValue('sg-turnUnit') || current.turnUnit || '月';
    current.eraName = formValue('sg-eraName') || current.eraName || '';
    current.enableGanzhi = formChecked('sg-enableGanzhi');
    current.enableGanzhiDay = formChecked('sg-enableGanzhiDay');
    current.enableEraName = formChecked('sg-enableEraName');
    current.enabledSystems = isObject(current.enabledSystems) ? current.enabledSystems : {};
    Object.keys(current.enabledSystems).forEach(function(key) {
      current.enabledSystems[key] = formChecked('sg-system-' + key);
    });
    state.scenario.gameSettings = current;
    state.scenario.startYear = current.startYear;
    state.scenario.startMonth = current.startMonth;
    state.scenario.time = buildTimeConfigFromGameSettings(current, state.scenario.time);
    state.selectedField = 'gameSettings';
    state.selectedModuleId = inferModuleForField('gameSettings');
    recordHistory('保存开局时间设置', 'gameSettings + time');
    renderAll();
    setStatus('开局时间、启用系统与运行态历法已保存', 'good');
    return clone(current);
  }

  function timeCalendarInput(key) {
    return document.querySelector('[data-time-calendar-field="' + key + '"]');
  }

  function timeInputNumber(key, fallback) {
    var input = timeCalendarInput(key);
    if (!input) return fallback;
    if (input.value == null || String(input.value).trim() === '') return '';
    var n = Number(input.value);
    return Number.isFinite(n) ? n : fallback;
  }

  function collectTimeEraRows(existing) {
    var rows = Array.from(document.querySelectorAll('[data-time-era-row]'));
    var result = [];
    rows.forEach(function(row) {
      var del = row.querySelector('[data-time-era-field="delete"]');
      if (del && del.checked) return;
      var index = Number(row.dataset.timeEraIndex);
      var original = Number.isFinite(index) && Array.isArray(existing) && existing[index] != null ? clone(existing[index]) : {};
      var item = isObject(original) ? original : { name: timeEraLabel(original) };
      ['name', 'startYear', 'startMonth', 'startDay'].forEach(function(key) {
        var input = row.querySelector('[data-time-era-field="' + key + '"]');
        if (!input) return;
        if (key === 'name') item.name = input.value;
        else item[key] = input.value === '' ? '' : numberOr(input.value, item[key] || 0);
      });
      if (!item.name && !item.startYear) return;
      if (!item.name) item.name = '未命名年号';
      result.push(item);
    });
    return result;
  }

  function syncGameSettingsFromTime(time) {
    var current = isObject(state.scenario.gameSettings) ? clone(state.scenario.gameSettings) : {};
    if (time.year !== '') current.startYear = Number(time.year) || time.year;
    if (time.startMonth !== '') current.startMonth = Number(time.startMonth) || time.startMonth;
    if (time.startDay !== '') current.startDay = Number(time.startDay) || time.startDay;
    if (time.daysPerTurn !== '') current.daysPerTurn = Number(time.daysPerTurn) || time.daysPerTurn;
    current.enableGanzhi = !!time.enableGanzhi;
    current.enableGanzhiDay = !!time.enableGanzhiDay;
    current.enableEraName = !!time.enableEraName;
    if (Array.isArray(time.eraNames)) {
      current.eraNames = clone(time.eraNames);
      var first = time.eraNames[0];
      var firstName = timeEraLabel(first);
      if (firstName) current.eraName = firstName;
    }
    state.scenario.gameSettings = current;
    if (time.year !== '') state.scenario.startYear = Number(time.year) || time.year;
    if (time.startMonth !== '') state.scenario.startMonth = Number(time.startMonth) || time.startMonth;
  }

  function saveTimeWorkbench(options) {
    var current = timeConfigRoot(state.scenario.time);
    var next = clone(current);
    ['year', 'startMonth', 'startDay', 'startLunarMonth', 'startLunarDay', 'daysPerTurn', 'startS'].forEach(function(key) {
      var value = timeInputNumber(key, next[key]);
      if (value === '') {
        if (key === 'startLunarMonth' || key === 'startLunarDay') next[key] = '';
      } else {
        next[key] = value;
      }
    });
    ['prefix', 'suffix', 'display', 'template'].forEach(function(key) {
      var input = timeCalendarInput(key);
      if (input) next[key] = input.value;
    });
    ['enableGanzhi', 'enableGanzhiDay', 'enableEraName'].forEach(function(key) {
      var input = timeCalendarInput(key);
      if (input) next[key] = !!input.checked;
    });
    var seasonsInput = timeCalendarInput('seasons');
    if (seasonsInput) next.seasons = splitList(seasonsInput.value);
    next.eraNames = collectTimeEraRows(current.eraNames);
    if (!next.seasons.length) next.seasons = ['春', '夏', '秋', '冬'];
    if (!next.daysPerTurn) next.daysPerTurn = 30;
    if (!next.prefix) next.prefix = Number(next.year) < 0 ? '公元前' : '公元';
    if (!next.suffix) next.suffix = '年';
    if (!next.display) next.display = 'year_season';
    if (!next.template) next.template = '{reign}{ry}年 {season}';
    state.scenario.time = next;
    syncGameSettingsFromTime(next);
    state.selectedField = 'time';
    state.selectedModuleId = inferModuleForField('time');
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存历法配置', 'time + gameSettings');
    if (!options || !options.silent) {
      renderAll();
      setStatus('历法配置已保存，并同步开局时间', 'good');
    }
    return clone(state.scenario.time);
  }

