    if (!isObject(state.scenario.time)) state.scenario.time = buildTimeConfigFromGameSettings(state.scenario.gameSettings, state.scenario.time);
    if (!Array.isArray(state.scenario.time.eraNames)) state.scenario.time.eraNames = [];
    var year = state.scenario.time.year || (state.scenario.gameSettings && state.scenario.gameSettings.startYear) || '';
    var item = { name: '新年号', startYear: year, startMonth: 1, startDay: 1 };
    state.scenario.time.eraNames.push(item);
    state.selectedField = 'time';
