  function collectInstitutionRows(field, existingRows) {
    var rows = Array.from(document.querySelectorAll('[data-institution-row]'));
    var kept = [];
    rows.forEach(function(row) {
      var del = row.querySelector('[data-institution-row-delete]');
      if (del && del.checked) return;
      var index = Number(row.dataset.institutionRowIndex);
      var original = Number.isFinite(index) && Array.isArray(existingRows) && existingRows[index] != null ? clone(existingRows[index]) : institutionSystemDefaultRow(field);
      if (field === 'keju') {
        var subjectInput = row.querySelector('[data-institution-row-field="name"]');
        var subject = subjectInput ? subjectInput.value.trim() : '';
        if (subject) kept.push(subject);
        return;
      }
      var item = isObject(original) ? original : { name: String(original == null ? '' : original) };
      institutionSystemRowFields(field).forEach(function(def) {
        var input = row.querySelector('[data-institution-row-field="' + def.key + '"]');
        if (!input) return;
        setEntityProp(item, def.key, input.value, field);
      });
      var label = readEntityProp(item, 'name') || readEntityProp(item, 'title') || readEntityProp(item, 'officialTitle') || readEntityProp(item, 'vassalType');
      if (!label && !readEntityProp(item, 'desc') && !readEntityProp(item, 'description')) return;
      kept.push(item);
    });
    return kept;
  }

  function saveInstitutionSystemWorkbench(options) {
    var field = state.selectedField;
    if (!isInstitutionSystemField(field)) return null;
    var root = institutionSystemRoot(field, state.scenario[field]);
    Array.from(document.querySelectorAll('[data-institution-metric] [data-institution-field]')).forEach(function(input) {
      var key = input.dataset.institutionField;
      var kind = input.dataset.institutionKind || 'text';
      if (!key) return;
      if (kind === 'boolean') root[key] = !!input.checked;
      else if (kind === 'number') root[key] = numberOr(input.value, root[key] || 0);
      else root[key] = input.value;
    });
    Array.from(document.querySelectorAll('[data-institution-textarea]')).forEach(function(input) {
      var key = input.dataset.institutionTextarea;
      if (key) root[key] = input.value;
    });
    var path = institutionSystemRowPath(field);
    var existingRows = pathGet(root, path) || [];
    pathSet(root, path, collectInstitutionRows(field, existingRows));
    state.scenario[field] = root;
    state.selectedModuleId = inferModuleForField(field);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存制度系统', field);
    if (!options || !options.silent) {
      renderAll();
      setStatus('制度系统工坊已保存：' + institutionSystemTitle(field), 'good');
    }
    return clone(root);
  }

  function scaffoldInstitutionSystemWorkbench(options) {
    var field = state.selectedField;
    if (!isInstitutionSystemField(field)) return null;
    var defaults = institutionSystemDefaults(field);
    var root = institutionSystemRoot(field, state.scenario[field]);
    Object.keys(defaults).forEach(function(key) {
      if (root[key] === undefined || root[key] === null || root[key] === '') root[key] = clone(defaults[key]);
      if (Array.isArray(defaults[key]) && (!Array.isArray(root[key]) || !root[key].length)) root[key] = clone(defaults[key]);
      if (isObject(defaults[key]) && !isObject(root[key])) root[key] = clone(defaults[key]);
    });
    var path = institutionSystemRowPath(field);
    var rows = pathGet(root, path);
    if (!Array.isArray(rows) || !rows.length) pathSet(root, path, [institutionSystemDefaultRow(field)]);
    state.scenario[field] = root;
    state.selectedModuleId = inferModuleForField(field);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('补齐制度系统', field);
    if (!options || !options.silent) {
      renderAll();
      setStatus('已补齐制度系统默认骨架：' + institutionSystemTitle(field), 'good');
    }
    return clone(root);
  }

  function addInstitutionSystemRow() {
    var field = state.selectedField;
    if (!isInstitutionSystemField(field)) return null;
    if (document.querySelector('[data-structured-kind="institution-system"]')) saveInstitutionSystemWorkbench({ silent: true });
    var root = institutionSystemRoot(field, state.scenario[field]);
    var path = institutionSystemRowPath(field);
    var rows = pathGet(root, path);
    if (!Array.isArray(rows)) {
      pathSet(root, path, []);
      rows = pathGet(root, path);
    }
    var item = institutionSystemDefaultRow(field);
    rows.push(item);
    state.scenario[field] = root;
    state.selectedModuleId = inferModuleForField(field);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('新增制度条目', field + '.' + path);
    renderAll();
    setStatus('已新增制度条目：' + institutionSystemTitle(field), 'good');
    return clone(item);
  }

  function savePlayerInfoWorkbench() {
    var current = isObject(state.scenario.playerInfo) ? clone(state.scenario.playerInfo) : {};
    [
      ['playerRole', 'pi-playerRole'],
      ['factionName', 'pi-factionName'],
      ['factionType', 'pi-factionType'],
      ['factionLeader', 'pi-factionLeader'],
      ['factionLeaderTitle', 'pi-factionLeaderTitle'],
      ['characterName', 'pi-characterName'],
      ['characterTitle', 'pi-characterTitle'],
      ['characterFaction', 'pi-characterFaction'],
      ['characterAge', 'pi-characterAge'],
      ['characterGender', 'pi-characterGender'],
      ['characterPersonality', 'pi-characterPersonality'],
      ['factionGoal', 'pi-factionGoal'],
      ['factionDesc', 'pi-factionDesc'],
      ['characterBio', 'pi-characterBio']
    ].forEach(function(pair) {
      current[pair[0]] = formValue(pair[1]);
    });
    current.leaderIsPlayer = formChecked('pi-leaderIsPlayer');
    state.scenario.playerInfo = current;
    state.selectedField = 'playerInfo';
    state.selectedModuleId = inferModuleForField('playerInfo');
    recordHistory('保存玩家设定', 'playerInfo');
    renderAll();
    setStatus('玩家势力与角色设定已保存', 'good');
    return clone(current);
  }

  function upsertByNameOrId(rows, names, factory, updater) {
    if (!Array.isArray(rows)) return null;
    var found = rows.find(function(row) {
      return row && names.some(function(name) { return name && (row.name === name || row.id === name || row.sid === name); });
    });
    if (!found) {
      found = factory();
      rows.push(found);
    }
    updater(found);
    return found;
  }

  function syncPlayerProfile() {
    savePlayerInfoWorkbench();
    var info = state.scenario.playerInfo || {};
    if (!Array.isArray(state.scenario.factions)) state.scenario.factions = [];
    if (!Array.isArray(state.scenario.characters)) state.scenario.characters = [];
    var faction = upsertByNameOrId(
      state.scenario.factions,
      [info.factionName, info.characterFaction],
      function() { return Object.assign(buildEntityTemplate('factions'), { id: uniqueId('player_faction') }); },
      function(row) {
        row.name = info.factionName || row.name || '玩家势力';
        row.leader = info.factionLeader || info.characterName || row.leader || '';
        row.type = info.factionType || row.type || 'player';
        row.desc = info.factionDesc || row.desc || '';
        row.goal = info.factionGoal || row.goal || '';
        row.isPlayer = true;
      }
    );
    var character = upsertByNameOrId(
      state.scenario.characters,
      [info.characterName, info.factionLeader],
      function() { return Object.assign(buildEntityTemplate('characters'), { id: uniqueId('player_char') }); },
      function(row) {
        row.name = info.characterName || info.factionLeader || row.name || '玩家角色';
        row.title = info.characterTitle || info.factionLeaderTitle || row.title || '';
        row.officialTitle = info.factionLeaderTitle || row.officialTitle || '';
        row.faction = faction && faction.name || info.factionName || info.characterFaction || row.faction || '';
        row.age = numberOr(info.characterAge, row.age || 0);
        row.gender = info.characterGender || row.gender || '';
        row.personality = info.characterPersonality || row.personality || '';
        row.bio = info.characterBio || row.bio || row.desc || '';
        row.desc = info.characterBio || row.desc || '';
        row.isPlayer = true;
        row.alive = row.alive !== false;
      }
    );
    state.selectedField = 'playerInfo';
    state.selectedModuleId = inferModuleForField('playerInfo');
    recordHistory('同步玩家入口', (faction && faction.name || '-') + ' / ' + (character && character.name || '-'));
    renderAll();
    setStatus('已同步玩家势力与玩家角色到实体库', 'good');
    return { faction: clone(faction), character: clone(character) };
  }

  function saveRelationMatrix() {
    var rows = Array.from(document.querySelectorAll('[data-relation-index]'));
    if (!Array.isArray(state.scenario.factionRelations)) state.scenario.factionRelations = [];
    rows.forEach(function(row) {
      var index = Number(row.dataset.relationIndex);
      if (!Number.isFinite(index) || !state.scenario.factionRelations[index]) return;
      var relation = state.scenario.factionRelations[index];
      relation.from = (row.querySelector('[data-relation-field="from"]') || {}).value || relation.from || '';
      relation.to = (row.querySelector('[data-relation-field="to"]') || {}).value || relation.to || '';
      relation.type = (row.querySelector('[data-relation-field="type"]') || {}).value || relation.type || 'neutral';
      relation.value = numberOr((row.querySelector('[data-relation-field="value"]') || {}).value, relation.value || 0);
      relation.desc = (row.querySelector('[data-relation-field="desc"]') || {}).value || '';
      relation._delete = !!(row.querySelector('[data-relation-field="delete"]') || {}).checked;
    });
    state.scenario.factionRelations = state.scenario.factionRelations.filter(function(row) { return !(row && row._delete); }).map(function(row) {
      delete row._delete;
      return row;
    });
    state.selectedField = 'factionRelations';
    state.selectedModuleId = inferModuleForField('factionRelations');
    recordHistory('保存势力关系矩阵', state.scenario.factionRelations.length + ' 条关系');
    renderAll();
    setStatus('势力关系矩阵已保存', 'good');
    return clone(state.scenario.factionRelations);
  }

  function addRelationRow() {
    if (!Array.isArray(state.scenario.factionRelations)) state.scenario.factionRelations = [];
    var factions = state.scenario.factions || [];
    state.scenario.factionRelations.push({
      from: factions[0] && (factions[0].name || factions[0].id) || '',
      to: factions[1] && (factions[1].name || factions[1].id) || '',
      type: 'neutral',
      value: 0,
      desc: '待补关系说明'
    });
    state.selectedField = 'factionRelations';
    state.selectedModuleId = inferModuleForField('factionRelations');
    recordHistory('新增势力关系', 'factionRelations');
    renderAll();
  }

  function presetRelationsRoot(value) {
    if (isObject(value) && !Array.isArray(value)) {
      return {
        npc: Array.isArray(value.npc) ? value.npc : [],
        faction: Array.isArray(value.faction) ? value.faction : []
      };
    }
    if (Array.isArray(value)) return { npc: value, faction: [] };
    return { npc: [], faction: [] };
  }

  function ensurePresetRelationsRoot() {
    var root = state.scenario.presetRelations;
    if (!isObject(root) || Array.isArray(root)) {
      root = presetRelationsRoot(root);
      state.scenario.presetRelations = root;
    }
    if (!Array.isArray(root.npc)) root.npc = [];
    if (!Array.isArray(root.faction)) root.faction = [];
    return root;
  }

  function presetRelationFieldValue(row, selector, fallback) {
    var input = row.querySelector(selector);
    return input ? input.value : (fallback == null ? '' : fallback);
  }

  function savePresetRelationsWorkbench(options) {
    var opts = options || {};
    var root = ensurePresetRelationsRoot();
    [
      { kind: 'npc', rows: root.npc },
      { kind: 'faction', rows: root.faction }
    ].forEach(function(section) {
      Array.from(document.querySelectorAll('[data-preset-relation-kind="' + section.kind + '"]')).forEach(function(row) {
        var index = Number(row.dataset.presetRelationIndex);
        if (!Number.isFinite(index) || !section.rows[index]) return;
        var item = section.rows[index];
        if (section.kind === 'npc') {
          item.name = presetRelationFieldValue(row, '[data-preset-relation-field="name"]', item.name);
          item.value = numberOr(presetRelationFieldValue(row, '[data-preset-relation-field="value"]', item.value), item.value || 0);
          item.min = numberOr(presetRelationFieldValue(row, '[data-preset-relation-field="min"]', item.min), item.min == null ? -100 : item.min);
          item.max = numberOr(presetRelationFieldValue(row, '[data-preset-relation-field="max"]', item.max), item.max == null ? 100 : item.max);
          item.description = presetRelationFieldValue(row, '[data-preset-relation-field="description"]', item.description || item.desc || '');
        } else {
          item.facA = presetRelationFieldValue(row, '[data-preset-relation-field="facA"]', item.facA || item.from || '');
          item.facB = presetRelationFieldValue(row, '[data-preset-relation-field="facB"]', item.facB || item.to || '');
          item.type = presetRelationFieldValue(row, '[data-preset-relation-field="type"]', item.type || 'neutral');
          item.value = numberOr(presetRelationFieldValue(row, '[data-preset-relation-field="value"]', item.value), item.value || 0);
          item.desc = presetRelationFieldValue(row, '[data-preset-relation-field="desc"]', item.desc || item.description || '');
        }
        item._deletePresetRelation = !!(row.querySelector('[data-preset-relation-delete]') || {}).checked;
      });
      root[section.kind] = section.rows.filter(function(item) {
        return item && !item._deletePresetRelation;
      }).map(function(item) {
        delete item._deletePresetRelation;
        return item;
      });
    });
    state.scenario.presetRelations = root;
    state.selectedField = 'presetRelations';
    state.selectedModuleId = inferModuleForField('presetRelations');
    if (!opts.silent) {
      recordHistory('保存预置关系', root.npc.length + ' 个 NPC/状态 · ' + root.faction.length + ' 条势力关系');
      renderAll();
      setStatus('预置关系已保存', 'good');
    }
    return clone(root);
  }

  function addPresetRelationRow(kind) {
    if (document.querySelector('[data-structured-kind="preset-relations"]')) savePresetRelationsWorkbench({ silent: true });
    var root = ensurePresetRelationsRoot();
    var targetKind = kind === 'faction' ? 'faction' : 'npc';
    if (targetKind === 'faction') {
      root.faction.push({ facA: '', facB: '', type: 'neutral', value: 0, desc: '待补势力关系说明' });
    } else {
      root.npc.push({ name: '新预置关系', value: 0, min: -100, max: 100, description: '待补关系说明' });
    }
    state.selectedField = 'presetRelations';
    state.selectedModuleId = inferModuleForField('presetRelations');
    recordHistory('新增预置关系', targetKind);
    renderAll();
    setStatus(targetKind === 'faction' ? '已新增势力预置关系' : '已新增 NPC/状态预置关系', 'good');
    return clone(root[targetKind][root[targetKind].length - 1]);
  }

