    rows.forEach(function(row) {
      var index = Number(row.dataset.societyInfluenceIndex);
      if (!Number.isFinite(index) || !state.scenario[key][index]) return;
      var item = state.scenario[key][index];
      ['name', 'leader', 'stance', 'desc'].forEach(function(fieldName) {
        var input = row.querySelector('[data-society-field="' + fieldName + '"]');
        if (!input) return;
        if (fieldName === 'desc') {
          if (item.description != null && item.desc == null) item.description = input.value;
          else item.desc = input.value;
        } else if (fieldName === 'stance') {
          if (item.status != null && item.stance == null) item.status = input.value;
          else item.stance = input.value;
        } else {
          item[fieldName] = input.value;
        }
      });
      ['influence', 'satisfaction'].forEach(function(fieldName) {
        var input = row.querySelector('[data-society-field="' + fieldName + '"]');
        if (input) item[fieldName] = numberOr(input.value, item[fieldName] || 0);
      });
      var scaleInput = row.querySelector('[data-society-field="scale"]');
      if (scaleInput) {
        var scaleKey = row.dataset.societyScaleKey || societyScaleKey(key, item);
        var oldValue = item[scaleKey];
        item[scaleKey] = typeof oldValue === 'number' || /Estimate|Count/i.test(scaleKey) ? numberOr(scaleInput.value, oldValue || 0) : scaleInput.value;
      }
      item.id = item.id || uniqueId(key === 'classes' ? 'cls' : 'pty');
      item._delete = !!(row.querySelector('[data-society-field="delete"]') || {}).checked;
    });
    state.scenario[key] = state.scenario[key].filter(function(row) { return !(row && row._delete); }).map(function(row) {
      delete row._delete;
      return row;
    });
    state.selectedField = key;
