  function saveInterestGroupWorkbench(field, options) {
    var key = isInterestGroupField(field || state.selectedField) ? (field || state.selectedField) : 'influenceGroups';
    var rows = Array.from(document.querySelectorAll('[data-interest-group-index]'));
    var current = state.scenario[key];
    var sourceRows = interestGroupRows(key, current);
    var next = [];
    rows.forEach(function(row) {
      var index = Number(row.dataset.interestGroupIndex);
      var item = Object.assign({}, sourceRows[index] || buildEntityTemplate(key));
      ['id', 'name', 'type', 'leader', 'candidateBy'].forEach(function(fieldName) {
        var input = row.querySelector('[data-interest-group-field="' + fieldName + '"]');
        if (input) item[fieldName] = input.value;
      });
      var membersInput = row.querySelector('[data-interest-group-field="members"]');
      if (membersInput) item.members = splitList(membersInput.value);
      var officesInput = row.querySelector('[data-interest-group-field="keyOffices"]');
      if (officesInput) item.keyOffices = splitList(officesInput.value);
      var influenceInput = row.querySelector('[data-interest-group-field="influence"]');
      if (influenceInput) {
        if (item.initialInfluence != null || key === 'influenceGroups') item.initialInfluence = numberOr(influenceInput.value, item.initialInfluence || 0);
        else item.influence = numberOr(influenceInput.value, item.influence || 0);
      }
      var cohesionInput = row.querySelector('[data-interest-group-field="cohesion"]');
      if (cohesionInput) {
        if (item.initialCohesion != null || key === 'influenceGroups') item.initialCohesion = numberOr(cohesionInput.value, item.initialCohesion || 0);
        else item.cohesion = numberOr(cohesionInput.value, item.cohesion || 0);
      }
      var descInput = row.querySelector('[data-interest-group-field="desc"]');
      if (descInput) {
        if (item.description != null && item.desc == null) item.description = descInput.value;
        else item.desc = descInput.value;
      }
      var thresholdsInput = row.querySelector('[data-interest-group-field="thresholds"]');
      if (thresholdsInput) item.thresholds = parseInterestThresholds(thresholdsInput.value, item.thresholds || []);
      item.id = item.id || uniqueId(key === 'offendGroups' ? 'og' : 'ig');
      item._delete = !!(row.querySelector('[data-interest-group-field="delete"]') || {}).checked;
      if (!item._delete) {
        delete item._delete;
        next.push(item);
      }
    });
    if (key === 'offendGroups') {
      var cfg = interestGroupConfig(key, current);
      var enabledInput = document.querySelector('[data-interest-group-config="enabled"]');
      var decayInput = document.querySelector('[data-interest-group-config="decayRate"]');
      state.scenario.offendGroups = Object.assign(isObject(current) ? clone(current) : {}, {
        enabled: enabledInput ? !!enabledInput.checked : cfg.enabled,
        decayRate: decayInput ? numberOr(decayInput.value, cfg.decayRate) : cfg.decayRate,
        groups: next
      });
    } else {
      state.scenario.influenceGroups = next;
    }
    state.selectedField = key;
    state.selectedModuleId = inferModuleForField(key);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存' + interestGroupLabel(key) + '工坊', next.length + ' 个集团');
    if (!options || !options.silent) {
      renderAll();
      setStatus(interestGroupLabel(key) + '已保存：' + next.length + ' 个', 'good');
    }
    return clone(state.scenario[key]);
  }

