  function jumpImperialEdictTarget(name) {
    var key = String(name || '').trim();
    function matches(alias) {
      var text = String(alias || '').trim();
      return text && (text === key || (text.length >= 2 && key.indexOf(text) >= 0) || (key.length >= 2 && text.indexOf(key) >= 0));
    }
    var characters = state.scenario.characters || [];
    var charIndex = characters.findIndex(function(character) {
      return [character && character.name, character && character.id, character && character.sid, character && character.title, character && character.officialTitle].some(matches);
    });
    if (charIndex >= 0) {
      state.selectedField = 'characters';
      state.selectedModuleId = inferModuleForField('characters');
      state.selectedEntityIndex = charIndex;
      state.search = '';
      state.activeWorkbenchPanel = 'specialist-editor';
      renderAll();
      setStatus('已定位诏令目标人物：' + labelOf(characters[charIndex], charIndex), 'good');
      return { field: state.selectedField, index: state.selectedEntityIndex, value: clone(characters[charIndex]) };
    }
    var factions = state.scenario.factions || [];
    var factionIndex = factions.findIndex(function(faction) {
      return [faction && faction.name, faction && faction.id, faction && faction.sid, faction && faction.leader, faction && faction.capital].some(matches);
    });
    if (factionIndex >= 0) {
      state.selectedField = 'factions';
      state.selectedModuleId = inferModuleForField('factions');
      state.selectedEntityIndex = factionIndex;
      state.search = '';
      state.activeWorkbenchPanel = 'specialist-editor';
      renderAll();
      setStatus('已定位诏令目标势力：' + labelOf(factions[factionIndex], factionIndex), 'good');
      return { field: state.selectedField, index: state.selectedEntityIndex, value: clone(factions[factionIndex]) };
    }
    state.selectedField = 'imperialEdicts';
    state.selectedModuleId = inferModuleForField('imperialEdicts');
    state.activeWorkbenchPanel = 'structured-workbench';
    renderAll();
    setStatus('未找到诏令目标：' + key + '，已留在初始诏令工坊', 'warn');
    return null;
  }

  function savePoliticalActionWorkbench(field, options) {
    var key = isPoliticalActionField(field || state.selectedField) ? (field || state.selectedField) : 'schemeConfig';
    var current = state.scenario[key];
    var sourceRows = politicalActionRows(key, current);
    var next = [];
    Array.from(document.querySelectorAll('[data-political-action-index]')).forEach(function(row) {
      var index = Number(row.dataset.politicalActionIndex);
      var item = Object.assign({}, politicalActionItemObject(sourceRows[index], key, index));
      ['id', 'name', 'defenseAttr', 'description'].forEach(function(fieldName) {
        var input = row.querySelector('[data-political-action-field="' + fieldName + '"]');
        if (input) item[fieldName] = input.value;
      });
      if (key === 'schemeConfig') {
        ['baseSuccess', 'cooldownMonths', 'cost', 'discoveryChance', 'offenseWeight', 'defenseWeight'].forEach(function(fieldName) {
          var input = row.querySelector('[data-political-action-field="' + fieldName + '"]');
          if (!input) return;
          if (String(input.value || '').trim() === '') delete item[fieldName];
          else item[fieldName] = numberOr(input.value, item[fieldName] || 0);
        });
      } else {
        var conditionsInput = row.querySelector('[data-political-action-field="conditions"]');
        if (conditionsInput) item.conditions = parsePoliticalActionList(conditionsInput.value, item.conditions || []);
        var costInput = row.querySelector('[data-political-action-field="cost"]');
        if (costInput) item.cost = parsePoliticalActionObject(costInput.value, item.cost || {});
        var effectsInput = row.querySelector('[data-political-action-field="effects"]');
        if (effectsInput) item.effects = parsePoliticalActionList(effectsInput.value, item.effects || []);
      }
      item.id = item.id || ((key === 'schemeConfig' ? 'scheme' : 'decision') + '_' + (index + 1));
      item.name = item.name || politicalActionLabel(key) + ' #' + (index + 1);
      item._delete = !!(row.querySelector('[data-political-action-field="delete"]') || {}).checked;
      if (!item._delete) {
        delete item._delete;
        next.push(item);
      }
    });
    if (key === 'schemeConfig') {
      var enabledInput = document.querySelector('[data-political-action-config="enabled"]');
      state.scenario.schemeConfig = Object.assign(isObject(current) ? clone(current) : {}, {
        enabled: enabledInput ? !!enabledInput.checked : !(isObject(current) && current.enabled === false),
        schemeTypes: next
      });
    } else {
      state.scenario.decisionConfig = Object.assign(isObject(current) ? clone(current) : {}, {
        decisions: next
      });
    }
    state.selectedField = key;
    state.selectedModuleId = inferModuleForField(key);
    state.activeWorkbenchPanel = 'structured-workbench';
    state.selectedEntityIndex = Math.min(state.selectedEntityIndex || 0, Math.max(0, next.length - 1));
    recordHistory('保存' + politicalActionLabel(key) + '工坊', next.length + ' 条');
    if (!options || !options.silent) {
      renderAll();
      setStatus(politicalActionLabel(key) + '已保存：' + next.length + ' 条', 'good');
    }
    return clone(state.scenario[key]);
  }

