  function scaffoldWorldStateDefaults(field) {
    var key = isWorldStateField(field || state.selectedField) ? (field || state.selectedField) : 'eraState';
    if (key === 'worldview') {
      if (!hasText(state.scenario.worldview)) state.scenario.worldview = '待补世界观：请描述世界基本秩序、时代氛围、核心矛盾和玩家需要理解的底层设定。';
      state.selectedField = key;
      state.selectedModuleId = inferModuleForField(key);
      state.activeWorkbenchPanel = 'structured-workbench';
      recordHistory('补齐' + worldStateLabel(key) + '骨架', key);
      renderAll();
      setStatus(worldStateLabel(key) + '骨架已补齐', 'good');
      return clone(state.scenario.worldview);
    }
    if (!isObject(state.scenario[key])) state.scenario[key] = {};
    var root = state.scenario[key];
    var added = [];
    if (key === 'eraState') {
      WORLD_STATE_METRICS.forEach(function(metric) {
        if (metric.optional) return;
        if (!Object.prototype.hasOwnProperty.call(root, metric.key)) {
          root[metric.key] = metric.fallback;
          added.push(metric.key);
        }
      });
      WORLD_STATE_SELECTS.forEach(function(item) {
        if (!Object.prototype.hasOwnProperty.call(root, item.key)) {
          root[item.key] = item.options[0];
          added.push(item.key);
        }
      });
      if (!Object.prototype.hasOwnProperty.call(root, 'contextDescription')) {
        root.contextDescription = '';
        added.push('contextDescription');
      }
    } else {
      WORLD_SETTING_SECTIONS.forEach(function(section) {
        if (!Object.prototype.hasOwnProperty.call(root, section.key)) {
          root[section.key] = section.key === 'rules' ? [] : '';
          added.push(section.key);
        }
      });
    }
    state.selectedField = key;
    state.selectedModuleId = inferModuleForField(key);
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('补齐' + worldStateLabel(key) + '骨架', added.length ? added.join(', ') : '无新增字段');
    renderAll();
    setStatus(added.length ? ('已补齐' + worldStateLabel(key) + '：' + added.length + ' 项') : (worldStateLabel(key) + '骨架已完整'), added.length ? 'good' : 'neutral');
    return clone(root);
  }

