        if (influenceInput) item.motherClanInfluence = influenceInput.value === '' ? '' : numberOr(influenceInput.value, item.motherClanInfluence || 0);
        var bearInput = row.querySelector('[data-court-life-field="canBearHeir"]');
        if (bearInput) item.canBearHeir = !!bearInput.checked;
        var aliasInput = row.querySelector('[data-court-life-field="alias"]');
