  function savePopulationConfigWorkbench(options) {
    var current = isObject(state.scenario.populationConfig) ? state.scenario.populationConfig : {};
    var next = Object.assign({}, clone(current));
    if (!isObject(next.initial)) next.initial = {};
    if (!isObject(next.mobility)) next.mobility = {};
    var enabled = populationConfigInput('enabled');
    if (enabled) next.enabled = !!enabled.checked;
    ['nationalHouseholds', 'nationalMouths', 'nationalDing', 'hiddenPopulation'].forEach(function(key) {
      next.initial[key] = populationWorkbenchNumber(key, firstBudgetNumber([next.initial[key], next[key]], 0));
    });
    var note = populationConfigInput('note');
    if (note) next.initial.note = note.value;
    var start = populationWorkbenchNumber('dingStartAge', populationAgeRange(next).start);
    var end = populationWorkbenchNumber('dingEndAge', populationAgeRange(next).end);
    if (end < start) end = start;
    next.dingStartAge = start;
    next.dingEndAge = end;
    next.dingAgeRange = [start, end];
    next.sexRatio = populationWorkbenchNumber('sexRatio', economyNumber(next.sexRatio, 1.05));
    var grade = populationConfigInput('gradeSystem');
    if (grade) next.gradeSystem = grade.value;
    ['shangSheng', 'xiangxia'].forEach(function(key) {
      var input = populationConfigInput('mobility.' + key);
      if (input) next.mobility[key] = input.value;
    });
    var enabledCategories = [];
    var descriptions = {};
    Array.from(document.querySelectorAll('[data-population-category-row]')).forEach(function(row) {
      var idInput = row.querySelector('[data-population-category-field="id"]');
      var descInput = row.querySelector('[data-population-category-field="description"]');
      var enabledInput = row.querySelector('[data-population-category-field="enabled"]');
      var deleteInput = row.querySelector('[data-population-category-field="delete"]');
      var id = idInput ? idInput.value.trim() : '';
      if (!id || (deleteInput && deleteInput.checked)) return;
      if (!enabledInput || enabledInput.checked) enabledCategories.push(id);
      descriptions[id] = descInput ? descInput.value : '';
    });
    next.categoryEnabled = enabledCategories;
    next.categoryDescriptions = descriptions;
    state.scenario.populationConfig = next;
    state.selectedField = 'populationConfig';
    state.selectedModuleId = inferModuleForField('populationConfig');
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('保存人口户籍工坊', enabledCategories.length + ' 类户籍');
    if (!options || !options.silent) {
      renderAll();
      setStatus('人口户籍工坊已保存', 'good');
    }
    return clone(state.scenario.populationConfig);
  }

  function scaffoldPopulationConfigWorkbench(options) {
    var defaults = populationConfigDefaults();
    var current = isObject(state.scenario.populationConfig) ? state.scenario.populationConfig : {};
    var changed = 0;
    Object.keys(defaults).forEach(function(key) {
      if (key === 'initial' || key === 'categoryDescriptions' || key === 'mobility') return;
      if (!Object.prototype.hasOwnProperty.call(current, key) || current[key] == null) {
        current[key] = clone(defaults[key]);
        changed += 1;
      }
    });
    if (!isObject(current.initial)) {
      current.initial = clone(defaults.initial);
      changed += 1;
    } else {
      Object.keys(defaults.initial).forEach(function(key) {
        if (!Object.prototype.hasOwnProperty.call(current.initial, key) || current.initial[key] == null) {
          current.initial[key] = clone(defaults.initial[key]);
          changed += 1;
        }
      });
    }
    if (!isObject(current.categoryDescriptions)) {
      current.categoryDescriptions = clone(defaults.categoryDescriptions);
      changed += 1;
    }
    if (!isObject(current.mobility)) {
      current.mobility = clone(defaults.mobility);
      changed += 1;
    }
    state.scenario.populationConfig = current;
    state.selectedField = 'populationConfig';
    state.selectedModuleId = inferModuleForField('populationConfig');
    state.activeWorkbenchPanel = 'structured-workbench';
    recordHistory('补齐人口户籍默认项', changed + ' 项');
    if (!options || !options.silent) {
      renderAll();
      setStatus(changed ? ('已补齐人口户籍默认项：' + changed + ' 项') : '人口户籍配置已具备默认骨架', changed ? 'good' : 'neutral');
    }
    return clone(state.scenario.populationConfig);
  }

