  function readTreeValue(root, path) {
    if (!path) return root;
    return String(path).split('.').reduce(function(node, part) {
      if (node == null) return null;
      if (/^\d+$/.test(part)) return node[Number(part)];
      return node[part];
    }, root);
  }

  function collectTreeRows(value, prefix, rows, depth) {
    if (rows.length >= 80 || depth > 4) return rows;
    if (Array.isArray(value)) {
      value.forEach(function(item, index) {
        var path = prefix ? prefix + '.' + index : String(index);
        if (isObject(item)) {
          rows.push({ path: path, node: item, depth: depth, label: labelOf(item, index) });
          ['children', 'subs', 'positions', 'divisions', 'nodes', 'items'].forEach(function(key) {
            if (Array.isArray(item[key])) collectTreeRows(item[key], path + '.' + key, rows, depth + 1);
          });
        }
      });
      return rows;
    }
    if (isObject(value)) {
      Object.keys(value).forEach(function(key) {
        var child = value[key];
        var path = prefix ? prefix + '.' + key : key;
        if (Array.isArray(child)) collectTreeRows(child, path, rows, depth);
        else if (isObject(child)) {
          if (child.name || child.title || child.id) rows.push({ path: path, node: child, depth: depth, label: labelOf(child, 0) });
          collectTreeRows(child, path, rows, depth + 1);
        }
      });
    }
    return rows;
  }

  function treeDescription(node) {
    return node && (node.desc || node.description || node.effect || node.duties || node.note || '');
  }

  function treeNodeId(row) {
    var node = row && row.node || {};
    return String(node.id || node.key || node.name || node.title || row.path || '').trim();
  }

  function treeNodeLabel(row) {
    var node = row && row.node || {};
    return String(node.name || node.title || node.id || node.key || row.label || row.path || '').trim();
  }

  function compactTreeLabel(label) {
    var text = String(label || '');
    return text.length > 6 ? text.slice(0, 6) : text;
  }

  function treeDependencyList(node, keys) {
    var found = [];
    keys.forEach(function(key) {
      var value = node && node[key];
      if (value == null || value === '') return;
      if (Array.isArray(value)) {
        value.forEach(function(item) {
          if (item == null || item === '') return;
          if (isObject(item)) {
            var label = item.id || item.key || item.name || item.title;
            if (label != null && label !== '') found.push(String(label));
          } else {
            found.push(String(item));
          }
        });
        return;
      }
      if (isObject(value)) {
        Object.keys(value).forEach(function(itemKey) {
          if (value[itemKey]) found.push(String(itemKey));
        });
        return;
      }
      splitList(value).forEach(function(item) { found.push(item); });
    });
    return found.filter(function(item, index) { return item && found.indexOf(item) === index; });
  }

  function closestTreeParent(row, rows) {
    if (!row || !row.path) return null;
    var best = null;
    rows.forEach(function(candidate) {
      if (!candidate || candidate === row || !candidate.path) return;
      if (row.path.indexOf(candidate.path + '.') !== 0) return;
      if (!best || candidate.path.length > best.path.length) best = candidate;
    });
    return best;
  }

  function buildTreeDependencyGraph(field, value) {
    var rows = collectTreeRows(value, '', [], 0).slice(0, 80);
    var nodes = rows.map(function(row, index) {
      return {
        id: treeNodeId(row) || ('node_' + index),
        label: treeNodeLabel(row) || ('节点 #' + (index + 1)),
        path: row.path,
        depth: Math.max(0, row.depth || 0),
        node: row.node || {},
        degree: 0,
        x: 0,
        y: 0
      };
    });
    var byId = {};
    var byLabel = {};
    nodes.forEach(function(node) {
      if (!byId[node.id]) byId[node.id] = node;
      if (!byLabel[node.label]) byLabel[node.label] = node;
      if (!byLabel[node.path]) byLabel[node.path] = node;
    });
    function resolve(term) {
      var key = String(term || '').trim();
      return byId[key] || byLabel[key] || null;
    }
    var edges = [];
    function addEdge(from, to, source) {
      if (!from || !to || from.id === to.id) return;
      var key = from.id + '->' + to.id + ':' + source;
      if (edges.some(function(edge) { return edge.key === key; })) return;
      from.degree += 1;
      to.degree += 1;
      edges.push({ key: key, from: from.id, to: to.id, source: source || 'tree' });
    }
    nodes.forEach(function(node) {
      treeDependencyList(node.node, ['prereqs', 'prerequisites', 'requires', 'dependencies', 'parents']).forEach(function(term) {
        addEdge(resolve(term), node, 'declared');
      });
      treeDependencyList(node.node, ['unlocks', 'childrenUnlocked', 'leadsTo']).forEach(function(term) {
        addEdge(node, resolve(term), 'unlock');
      });
    });
    var declaredEdges = edges.length;
    if (!edges.length) {
      rows.forEach(function(row, index) {
        var parentRow = closestTreeParent(row, rows);
        if (!parentRow) return;
        addEdge(nodes[rows.indexOf(parentRow)], nodes[index], 'hierarchy');
      });
    }
    if (!edges.length && nodes.length > 1) {
      nodes.forEach(function(node, index) {
        if (index > 0) addEdge(nodes[index - 1], node, 'sequence');
      });
    }
    var visible = nodes.slice(0, 28);
    var visibleIds = {};
    visible.forEach(function(node) { visibleIds[node.id] = true; });
    var groups = {};
    visible.forEach(function(node) {
      var depth = Math.min(4, node.depth || 0);
      if (!groups[depth]) groups[depth] = [];
      groups[depth].push(node);
    });
    var depths = Object.keys(groups).map(Number).sort(function(a, b) { return a - b; });
    var maxDepth = depths.length ? Math.max.apply(null, depths) : 0;
    if (!maxDepth && visible.length > 4) {
      var cols = visible.length > 16 ? 5 : 4;
      visible.forEach(function(node, index) {
        var col = index % cols;
        var row = Math.floor(index / cols);
        node.x = Math.round(62 + col * (376 / Math.max(1, cols - 1)));
        node.y = Math.round(44 + row * 56);
      });
    } else {
      visible.forEach(function(node) {
        var depth = Math.min(4, node.depth || 0);
        var siblings = groups[depth] || [node];
        var index = siblings.indexOf(node);
        var span = Math.max(1, siblings.length + 1);
        node.x = Math.round(54 + (maxDepth ? (392 * depth / maxDepth) : 196));
        node.y = Math.round(34 + (222 * (index + 1) / span));
      });
    }
    var visibleById = {};
    visible.forEach(function(node) { visibleById[node.id] = node; });
    var visibleEdges = edges.filter(function(edge) { return visibleIds[edge.from] && visibleIds[edge.to]; }).slice(0, 48);
    return {
      field: field,
      nodes: visible,
      edges: visibleEdges,
      byId: visibleById,
      totalNodes: nodes.length,
      totalEdges: edges.length,
      declaredEdges: declaredEdges,
      hierarchyEdges: edges.filter(function(edge) { return edge.source === 'hierarchy'; }).length,
      sequenceEdges: edges.filter(function(edge) { return edge.source === 'sequence'; }).length
    };
  }

  function saveTreeWorkbench() {
    var field = state.selectedField;
    var value = state.scenario[field];
    Array.from(document.querySelectorAll('[data-tree-path]')).forEach(function(row) {
      var node = readTreeValue(value, row.dataset.treePath);
      if (!isObject(node)) return;
      var nameInput = row.querySelector('[data-tree-field="name"]');
      var metaInput = row.querySelector('[data-tree-field="meta"]');
      var descInput = row.querySelector('[data-tree-field="desc"]');
      if (nameInput) {
        if (Object.prototype.hasOwnProperty.call(node, 'name')) node.name = nameInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'title')) node.title = nameInput.value;
        else node.name = nameInput.value;
      }
      if (metaInput) {
        // Preserve vassalType (天启 schema) over type (绍宋 schema) when the
        // current tree workbench is editing a vassal container; otherwise the
        // generic-type branch would silently move the value out of vassalType
        // and leave the original key stale on save.
        if (Object.prototype.hasOwnProperty.call(node, 'rank')) node.rank = metaInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'vassalType')) node.vassalType = metaInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'type')) node.type = metaInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'level')) node.level = metaInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'era')) node.era = metaInput.value;
        else node.type = metaInput.value;
      }
      if (descInput) {
        if (Object.prototype.hasOwnProperty.call(node, 'desc')) node.desc = descInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'description')) node.description = descInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'effect')) node.effect = descInput.value;
        else if (Object.prototype.hasOwnProperty.call(node, 'duties')) node.duties = descInput.value;
        else node.desc = descInput.value;
      }
    });
    recordHistory('保存树状结构', field);
    renderAll();
    setStatus('树状结构快编已保存：' + field, 'good');
    return clone(state.scenario[field]);
  }

  function firstTreeArrayContainer(value, field) {
    if (Array.isArray(value)) return value;
    if (!isObject(value)) return null;
    if (field === 'adminHierarchy' && value.player && Array.isArray(value.player.divisions)) return value.player.divisions;
    var keys = Object.keys(value);
    for (var i = 0; i < keys.length; i += 1) {
      if (Array.isArray(value[keys[i]])) return value[keys[i]];
    }
    for (var j = 0; j < keys.length; j += 1) {
      var nested = firstTreeArrayContainer(value[keys[j]], field);
      if (nested) return nested;
    }
    return null;
  }

  function addTreeNode() {
    var field = state.selectedField;
    var value = state.scenario[field];
    var container = firstTreeArrayContainer(value, field);
    if (!container) {
      setStatus('当前字段没有可追加节点的数组容器：' + field, 'warn');
      return null;
    }
    var node;
    if (field === 'officeTree') node = { id: uniqueId('office'), name: '新机构', desc: '待补机构说明', positions: [], subs: [] };
    else if (field === 'adminHierarchy') node = { id: uniqueId('division'), name: '新区划', level: 'prefecture', description: '待补区划说明', children: [] };
    else node = { name: '新节点', desc: '待补节点说明', effect: '', era: '', prereqs: [], unlocked: false };
    container.push(node);
    recordHistory('新增树节点', field);
    renderAll();
    setStatus('已新增树节点：' + field, 'good');
    return clone(node);
  }

  function saveConfigWorkbench() {
    var field = state.selectedField;
    var root = state.scenario[field];
    if (!isObject(root)) {
      setStatus('当前字段不是配置对象：' + field, 'warn');
      return null;
    }
    Array.from(document.querySelectorAll('[data-config-path]')).forEach(function(input) {
      var path = input.dataset.configPath;
      var kind = input.dataset.configKind || configValueKind(pathGet(root, path));
      var oldValue = pathGet(root, path);
      var next = kind === 'boolean' ? input.checked : parseConfigValue(input.value, oldValue, kind);
      pathSet(root, path, next);
    });
    var touchedArrays = {};
    Array.from(document.querySelectorAll('[data-config-array-path]')).forEach(function(row) {
      var path = row.dataset.configArrayPath;
      var index = Number(row.dataset.configArrayIndex);
      var rows = pathGet(root, path);
      if (!Array.isArray(rows) || !Number.isFinite(index) || !rows[index]) return;
      touchedArrays[path] = true;
      var item = rows[index];
      row.querySelectorAll('[data-config-array-field]').forEach(function(input) {
        setEntityProp(item, input.dataset.configArrayField, input.value);
      });
      item._deleteFromConfigWorkbench = !!(row.querySelector('[data-config-array-delete]') || {}).checked;
    });
    Object.keys(touchedArrays).forEach(function(path) {
      var rows = pathGet(root, path);
      if (!Array.isArray(rows)) return;
      pathSet(root, path, rows.filter(function(item) { return !(item && item._deleteFromConfigWorkbench); }).map(function(item) {
        delete item._deleteFromConfigWorkbench;
        return item;
      }));
    });
    state.selectedModuleId = inferModuleForField(field);
    recordHistory('保存配置工坊', field);
    renderAll();
    setStatus('配置工坊已保存：' + field, 'good');
    return clone(state.scenario[field]);
  }

  function addConfigArrayRow(path) {
    var field = state.selectedField;
    var root = state.scenario[field];
    if (!isObject(root)) return null;
    var targetPath = path || firstConfigArrayPath(root);
    var rows = targetPath ? pathGet(root, targetPath) : null;
    if (!Array.isArray(rows)) {
      targetPath = 'items';
      root.items = [];
      rows = root.items;
    }
    rows.push(buildConfigArrayItem(rows[0] || rows[rows.length - 1], targetPath));
    recordHistory('新增配置条目', field + '.' + targetPath);
    renderAll();
    setStatus('已新增配置条目：' + field + '.' + targetPath, 'good');
    return clone(rows[rows.length - 1]);
  }

  function savePromptWorkbench() {
    var field = state.selectedField;
    var input = document.getElementById('prompt-workbench-value');
    if (!input) return null;
    state.scenario[field] = input.value;
    recordHistory('保存规则文本', field);
    renderAll();
    setStatus('规则文本已保存：' + field, 'good');
    return state.scenario[field];
  }

  function saveRuleListWorkbench() {
    var field = state.selectedField;
    if (!field) return null;
    var rows = Array.from(document.querySelectorAll('[data-rule-list-index]'));
    var kept = [];
    rows.forEach(function(row) {
      var del = row.querySelector('[data-rule-list-delete]');
      if (del && del.checked) return;
      var text = row.querySelector('[data-rule-list-text]');
      if (!text) return;
      var value = String(text.value == null ? '' : text.value).trim();
      if (!value) return;
      kept.push(value);
    });
    state.scenario[field] = kept;
    recordHistory('保存规则列表', field + ' · ' + kept.length + ' 条');
    renderAll();
    setStatus('规则列表已保存：' + field + ' · ' + kept.length + ' 条', 'good');
    return clone(state.scenario[field]);
  }

  function addRuleListRow() {
    var field = state.selectedField;
    if (!field) return null;
    if (!Array.isArray(state.scenario[field])) state.scenario[field] = [];
    state.scenario[field].push('待补规则条目');
    recordHistory('新增规则条目', field + '[' + (state.scenario[field].length - 1) + ']');
    renderAll();
    setStatus('已新增规则条目', 'good');
    return state.scenario[field].length - 1;
  }

  function restoreStructuredOriginal() {
    var field = state.selectedField;
    if (!field || !Object.prototype.hasOwnProperty.call(state.original || {}, field)) {
      setStatus('官方快照中没有可恢复字段：' + field, 'warn');
      return null;
    }
    state.scenario[field] = clone(state.original[field]);
    recordHistory('恢复官方字段', field);
    renderAll();
    setStatus('已恢复官方字段：' + field, 'good');
    return clone(state.scenario[field]);
  }

  function saveMapBindings() {
    var field = state.selectedField;
    var map = state.scenario[field];
    if (!isMapWorkbenchField(field, map)) {
      setStatus('当前字段不是地图绑定对象：' + field, 'warn');
      return null;
    }
    Array.from(document.querySelectorAll('[data-map-region-index]')).forEach(function(row) {
      var index = Number(row.dataset.mapRegionIndex);
      var region = map.regions[index];
      if (!region) return;
      var owner = row.querySelector('[data-map-field="ownerKey"]');
      var current = row.querySelector('[data-map-field="currentOwnerKey"]');
      var controller = row.querySelector('[data-map-field="controllerKey"]');
      var admin = row.querySelector('[data-map-field="adminBinding"]');
      var troops = row.querySelector('[data-map-field="troops"]');
      var prosperity = row.querySelector('[data-map-field="prosperity"]');
      var mood = row.querySelector('[data-map-field="mood"]');
      var unrest = row.querySelector('[data-map-field="unrest"]');
      if (owner) region.ownerKey = owner.value;
      if (current) region.currentOwnerKey = current.value;
      if (controller) region.controllerKey = controller.value;
      if (admin) region.adminBinding = admin.value;
      if (troops) region.troops = numberOr(troops.value, region.troops || 0);
      if (prosperity) region.prosperity = numberOr(prosperity.value, region.prosperity || 0);
      if (mood) region.mood = numberOr(mood.value, region.mood || 0);
      if (unrest) region.unrest = numberOr(unrest.value, region.unrest || 0);
      var label = mapFactionLabel(map, region.currentOwnerKey || region.ownerKey || region.controllerKey);
      region.factionName = label || region.factionName || '';
      region.ownerName = label || region.ownerName || '';
      if (!region.controller) region.controller = region.controllerKey || '';
      if (!region.currentOwner) region.currentOwner = region.currentOwnerKey || '';
      if (!region.owner) region.owner = region.ownerKey || '';
    });
    return applyMapPatch(function() {}, { field: field, normalize: false, label: '保存地图绑定', status: '地图地块归属与行政绑定已保存：' + field }) ? clone(state.scenario[field]) : null;
  }

  function normalizeMapBindings() {
    var field = state.selectedField;
    var map = state.scenario[field];
    if (!isMapWorkbenchField(field, map)) return null;
    return applyMapPatch(function() {}, { field: field, label: '智能匹配地图绑定', detail: field, status: '已按 ownerKey/name 智能补齐地图绑定：' + field }) ? clone(state.scenario[field]) : null;
  }

  function clearSelectedMapBindings() {
    var field = state.selectedField;
    var map = state.scenario[field];
    if (!isMapWorkbenchField(field, map)) return null;
    var cleared = 0;
    Array.from(document.querySelectorAll('[data-map-region-index]')).forEach(function(row) {
      var checkbox = row.querySelector('[data-map-clear]');
      if (!checkbox || !checkbox.checked) return;
      var region = map.regions[Number(row.dataset.mapRegionIndex)];
      if (!region) return;
      ['ownerKey', 'currentOwnerKey', 'controllerKey', 'adminBinding', 'factionName', 'ownerName', 'controller', 'currentOwner', 'owner'].forEach(function(key) {
        region[key] = '';
      });
      cleared += 1;
    });
    if (!cleared) {
      setStatus('请先勾选要清除映射的地块', 'warn');
      return null;
    }
    return applyMapPatch(function() {}, { field: field, normalize: false, label: '清除地图映射', detail: field + ' · ' + cleared + ' 地块', status: '已清除勾选地块映射：' + cleared + ' 个' }) ? clone(state.scenario[field]) : null;
  }

  function parseDelimitedLine(line, delimiter) {
    var out = [];
    var cell = '';
    var quoted = false;
    for (var i = 0; i < String(line || '').length; i += 1) {
      var ch = line[i];
      if (ch === '"') {
        if (quoted && line[i + 1] === '"') {
          cell += '"';
          i += 1;
        } else {
          quoted = !quoted;
        }
      } else if (ch === delimiter && !quoted) {
        out.push(cell);
        cell = '';
      } else {
        cell += ch;
      }
    }
    out.push(cell);
    return out;
  }

  function coerceBulkValue(key, raw) {
    var value = String(raw == null ? '' : raw).trim();
    if (!value) return '';
    if (/^(true|false)$/i.test(value)) return value.toLowerCase() === 'true';
    if (/^-?\d+(\.\d+)?$/.test(value)) return Number(value);
    if ((value[0] === '[' && value[value.length - 1] === ']') || (value[0] === '{' && value[value.length - 1] === '}')) {
      try { return JSON.parse(value); } catch (_) {}
    }
    if (/linked|traits|members|tags|goals|aliases/i.test(key) && /[|;；、]/.test(value)) {
      return value.split(/[|;；、]/).map(function(part) { return part.trim(); }).filter(Boolean);
    }
    return value;
  }

  function parseDelimitedRows(text) {
    var lines = String(text || '').split(/\r?\n/).map(function(line) { return line.trim(); }).filter(Boolean);
    if (lines.length < 2) return [];
    var delimiter = lines[0].indexOf('\t') >= 0 ? '\t' : ',';
    var headers = parseDelimitedLine(lines[0], delimiter).map(function(header) { return header.trim(); }).filter(Boolean);
    if (!headers.length) return [];
    return lines.slice(1).map(function(line) {
      var cells = parseDelimitedLine(line, delimiter);
      return headers.reduce(function(row, header, index) {
        row[header] = coerceBulkValue(header, cells[index]);
        return row;
      }, {});
    });
  }

  function extractBulkRows(payload, field) {
    if (Array.isArray(payload)) return payload;
    if (!isObject(payload)) return [];
    if (Array.isArray(payload.rows)) return payload.rows;
    if (Array.isArray(payload.items)) return payload.items;
    if (Array.isArray(payload.data)) return payload.data;
    if (field && Array.isArray(payload[field])) return payload[field];
    if (payload.scenario && field && Array.isArray(payload.scenario[field])) return payload.scenario[field];
    return [];
  }

  function parseBulkRows(input, field) {
    if (Array.isArray(input) || isObject(input)) return extractBulkRows(input, field).map(clone);
    var text = String(input == null ? '' : input).trim();
    if (!text) return [];
    if (text[0] === '[' || text[0] === '{') {
      return extractBulkRows(JSON.parse(text), field).map(clone);
    }
    var lines = text.split(/\r?\n/).map(function(line) { return line.trim(); }).filter(Boolean);
    if (lines.length && lines.every(function(line) { return line[0] === '{'; })) {
      return lines.map(function(line) { return JSON.parse(line); });
    }
    return parseDelimitedRows(text);
  }

  function bulkIdentity(item) {
    if (!isObject(item)) return '';
    var keys = ['id', 'sid', 'gid', 'key', 'name', 'title', 'ownerKey'];
    for (var i = 0; i < keys.length; i += 1) {
      if (item[keys[i]] != null && item[keys[i]] !== '') return keys[i] + ':' + String(item[keys[i]]);
    }
    return '';
  }

  function buildBulkImportReport(field, rows, mode) {
    var current = state.scenario[field];
    if (!Array.isArray(current)) throw new Error('Bulk import requires an array field: ' + field);
    var importMode = mode || 'merge';
    var indexByIdentity = {};
    current.forEach(function(item, index) {
      var id = bulkIdentity(item);
      if (id && indexByIdentity[id] == null) indexByIdentity[id] = index;
    });
    var report = {
      field: field,
      mode: importMode,
      rows: rows.map(clone),
      currentCount: current.length,
      incomingCount: rows.length,
      addCount: 0,
      updateCount: 0,
      unchangedCount: 0,
      replaceCount: importMode === 'replace' ? current.length : 0,
      preview: []
    };
    rows.forEach(function(row, rowIndex) {
      var id = bulkIdentity(row);
      var existingIndex = id ? indexByIdentity[id] : null;
      var status = 'add';
      if (importMode === 'append') status = 'add';
      else if (importMode === 'replace') status = 'replace';
      else if (existingIndex != null) status = stableString(current[existingIndex]) === stableString(row) ? 'unchanged' : 'update';
      if (status === 'update') report.updateCount += 1;
      else if (status === 'unchanged') report.unchangedCount += 1;
      else report.addCount += 1;
      report.preview.push({
        index: rowIndex,
        status: status,
        identity: id || 'row:' + rowIndex,
        label: labelOf(row, rowIndex),
        existingIndex: existingIndex
      });
    });
    return report;
  }

  function previewBulkImport(input, options) {
    var opts = options || {};
    var field = opts.field || state.selectedField;
    var mode = opts.mode || (document.getElementById('bulk-import-mode') && document.getElementById('bulk-import-mode').value) || 'merge';
    var raw = input != null ? input : (document.getElementById('bulk-import-input') && document.getElementById('bulk-import-input').value) || '';
    var rows = parseBulkRows(raw, field).filter(isObject);
    var report = buildBulkImportReport(field, rows, mode);
    state.bulkImportPreview = report;
    renderBulkDataWorkbench(field, state.scenario[field]);
    setStatus('批量导入预览：' + field + ' · ' + report.incomingCount + ' 条', report.incomingCount ? 'good' : 'warn');
    return clone(report);
  }

  function applyBulkImport(options) {
    var opts = options || {};
    var field = opts.field || state.selectedField;
    var report = opts.report || state.bulkImportPreview;
    if (!report || report.field !== field) report = previewBulkImport(Object.prototype.hasOwnProperty.call(opts, 'input') ? opts.input : undefined, opts);
    var current = state.scenario[field];
    if (!Array.isArray(current)) throw new Error('Bulk import requires an array field: ' + field);
    var rows = (report.rows || []).map(clone);
    var next = current.map(clone);
    if (report.mode === 'replace') {
      next = rows;
    } else if (report.mode === 'append') {
      next = next.concat(rows);
    } else {
      var indexByIdentity = {};
      next.forEach(function(item, index) {
        var id = bulkIdentity(item);
        if (id && indexByIdentity[id] == null) indexByIdentity[id] = index;
      });
      rows.forEach(function(row) {
        var id = bulkIdentity(row);
        if (id && indexByIdentity[id] != null) next[indexByIdentity[id]] = clone(row);
        else next.push(clone(row));
      });
    }
    state.scenario[field] = next;
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    state.selectedEntityIndex = Math.max(0, Math.min(next.length - 1, state.selectedEntityIndex));
    state.bulkImportPreview = null;
    recordHistory('批量导入', field + ' · ' + rows.length + ' 条 · ' + report.mode);
    renderAll();
    setStatus('批量导入完成：' + field + ' · ' + rows.length + ' 条', 'good');
    return clone({ field: field, mode: report.mode, importedCount: rows.length, totalCount: next.length });
  }

  function exportBulkField(field, options) {
    var key = field || state.selectedField;
    var value = state.scenario[key];
    if (!Array.isArray(value)) throw new Error('Bulk export requires an array field: ' + key);
    var pack = { format: 'tianming-scenario-editor-bulk-field', version: 1, exportedAt: new Date().toISOString(), field: key, count: value.length, rows: clone(value) };
    if (!options || options.download !== false) {
      var blob = new Blob([JSON.stringify(pack, null, 2)], { type: 'application/json;charset=utf-8' });
      var url = URL.createObjectURL(blob);
      var a = document.createElement('a');
      a.href = url;
      a.download = 'tianming-bulk-' + key + '.json';
      document.body.appendChild(a);
      a.click();
      a.remove();
      setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
    }
    setStatus('已导出批量字段：' + key + ' · ' + value.length + ' 条', 'good');
    return pack;
  }

  function buildScenarioDiff() {
    var keys = Array.from(new Set(Object.keys(state.original || {}).concat(Object.keys(state.scenario || {})))).sort();
    return keys.reduce(function(acc, key) {
      var inOriginal = Object.prototype.hasOwnProperty.call(state.original || {}, key);
      var inDraft = Object.prototype.hasOwnProperty.call(state.scenario || {}, key);
      var before = state.original ? state.original[key] : undefined;
      var after = state.scenario ? state.scenario[key] : undefined;
      if (inOriginal && inDraft && stableString(before) === stableString(after)) return acc;
      acc.push({
        key: key,
        status: !inOriginal ? 'added' : !inDraft ? 'removed' : 'changed',
        beforeType: inOriginal ? fieldType(before) : 'none',
        afterType: inDraft ? fieldType(after) : 'none',
        beforeCount: inOriginal ? fieldCount(before) : '0',
        afterCount: inDraft ? fieldCount(after) : '0'
      });
      return acc;
    }, []);
  }

  // Sources for the side-by-side scenario comparison panel. The 'draft' entry
  // is resolved from live state at compare time; the official entries come
  // from the eagerly-loaded TM_OFFICIAL_SCENARIOS bundle.
  var COMPARISON_SOURCES = [
    { id: 'draft', label: '当前草稿' },
    { id: 'tianqi7', label: '天启七年（官方）' },
    { id: 'shaosong', label: '绍宋·建炎元年（官方）' }
  ];

  function comparisonSourceScenario(id) {
    if (id === 'draft') return state.scenario || {};
    var bundle = global.TM_OFFICIAL_SCENARIOS;
    if (bundle && bundle[id]) return bundle[id];
    return null;
  }

  function buildOfficialComparison(leftId, rightId) {
    var left = comparisonSourceScenario(leftId);
    var right = comparisonSourceScenario(rightId);
    if (!left || !right) return { rows: [], summary: { error: '至少一个比较来源不可用' } };
    var keys = Array.from(new Set(Object.keys(left).concat(Object.keys(right)))).sort();
    var rows = [];
    var leftOnly = 0;
    var rightOnly = 0;
    var diff = 0;
    var same = 0;
    keys.forEach(function(key) {
      var hasLeft = Object.prototype.hasOwnProperty.call(left, key);
      var hasRight = Object.prototype.hasOwnProperty.call(right, key);
      if (!hasLeft) {
        rightOnly += 1;
        rows.push({ key: key, status: 'right-only', leftType: 'none', rightType: fieldType(right[key]), leftCount: '0', rightCount: fieldCount(right[key]) });
        return;
      }
      if (!hasRight) {
        leftOnly += 1;
        rows.push({ key: key, status: 'left-only', leftType: fieldType(left[key]), rightType: 'none', leftCount: fieldCount(left[key]), rightCount: '0' });
        return;
      }
      var leftType = fieldType(left[key]);
      var rightType = fieldType(right[key]);
      var equal = stableString(left[key]) === stableString(right[key]);
      if (equal) {
        same += 1;
        return;
      }
      diff += 1;
      rows.push({
        key: key,
        status: leftType !== rightType ? 'shape-diff' : 'value-diff',
        leftType: leftType,
        rightType: rightType,
        leftCount: fieldCount(left[key]),
        rightCount: fieldCount(right[key])
      });
    });
    return {
      rows: rows,
      summary: {
        keysTotal: keys.length,
        leftOnly: leftOnly,
        rightOnly: rightOnly,
        diff: diff,
        same: same
      }
    };
  }

  function renderOfficialComparison() {
    var mount = document.querySelector('[data-panel="official-comparison"]');
    if (!mount) return;
    if (!state.comparisonLeftId) state.comparisonLeftId = 'tianqi7';
    if (!state.comparisonRightId) state.comparisonRightId = 'shaosong';
    var options = COMPARISON_SOURCES.map(function(src) {
      return '<option value="' + escapeHtml(src.id) + '">' + escapeHtml(src.label) + '</option>';
    }).join('');
    var report = buildOfficialComparison(state.comparisonLeftId, state.comparisonRightId);
    var summary = report.summary || {};
    if (summary.error) {
      mount.innerHTML = '<h3>剧本对照</h3><p>' + escapeHtml(summary.error) + '</p>';
      return;
    }
    var leftIsDraft = state.comparisonLeftId === 'draft';
    var rightIsDraft = state.comparisonRightId === 'draft';
    var draftInPlay = leftIsDraft || rightIsDraft;
    var rowsHtml = report.rows.slice(0, 200).map(function(row) {
      var statusLabel = row.status === 'left-only' ? '仅左' :
                         row.status === 'right-only' ? '仅右' :
                         row.status === 'shape-diff' ? '形态不同' : '值不同';
      // Apply-side buttons: only show when the draft is one of the sides, and
      // only enable the side that is NOT the draft (we copy from official to
      // draft, never overwriting the draft *from itself*). The button text
      // changes to "撤回" if the source side is draft and field exists only
      // there — clicking deletes it (with confirm guard at handler level).
      var applyLeftBtn = '';
      var applyRightBtn = '';
      if (draftInPlay) {
        if (!leftIsDraft && row.status !== 'right-only') {
          applyLeftBtn = '<button class="mini-ai" data-editor-command="apply-comparison-side" data-comparison-field="' + escapeHtml(row.key) + '" data-comparison-from="left">采纳左</button>';
        }
        if (!rightIsDraft && row.status !== 'left-only') {
          applyRightBtn = '<button class="mini-ai" data-editor-command="apply-comparison-side" data-comparison-field="' + escapeHtml(row.key) + '" data-comparison-from="right">采纳右</button>';
        }
      }
      return '<div class="comparison-row" data-comparison-status="' + escapeHtml(row.status) + '">' +
        '<div class="comparison-row-key"><strong>' + escapeHtml(row.key) + '</strong>' + provenanceBadgeHtml(row.key) + '</div>' +
        '<div class="comparison-row-side">' + escapeHtml(row.leftType + ' · ' + row.leftCount) + (applyLeftBtn ? ' ' + applyLeftBtn : '') + '</div>' +
        '<div class="comparison-row-status">' + escapeHtml(statusLabel) + '</div>' +
        '<div class="comparison-row-side">' + escapeHtml(row.rightType + ' · ' + row.rightCount) + (applyRightBtn ? ' ' + applyRightBtn : '') + '</div>' +
        '<div class="comparison-row-jump"><button class="mini-ai" data-editor-command="select-comparison-field" data-comparison-field="' + escapeHtml(row.key) + '">定位</button></div>' +
      '</div>';
    }).join('');
    // Batch action bar: visible only when the draft is on one of the sides,
    // since these copy fields from the non-draft side into the draft.
    var batchBar = '';
    if (draftInPlay) {
      var leftOnlyCount = report.rows.filter(function(r) { return r.status === 'left-only'; }).length;
      var rightOnlyCount = report.rows.filter(function(r) { return r.status === 'right-only'; }).length;
      var shapeDiffCount = report.rows.filter(function(r) { return r.status === 'shape-diff'; }).length;
      var valueDiffCount = report.rows.filter(function(r) { return r.status === 'value-diff'; }).length;
      var batchParts = [];
      if (!leftIsDraft && leftOnlyCount) {
        batchParts.push('<button class="mini-ai" data-editor-command="apply-comparison-batch" data-batch-kind="left-only" data-comparison-from="left">采纳所有仅左 ' + leftOnlyCount + '</button>');
      }
      if (!rightIsDraft && rightOnlyCount) {
        batchParts.push('<button class="mini-ai" data-editor-command="apply-comparison-batch" data-batch-kind="right-only" data-comparison-from="right">采纳所有仅右 ' + rightOnlyCount + '</button>');
      }
      if (!leftIsDraft && shapeDiffCount) {
        batchParts.push('<button class="mini-ai" data-editor-command="apply-comparison-batch" data-batch-kind="shape-diff" data-comparison-from="left">采纳左侧形态 ' + shapeDiffCount + '</button>');
      }
      if (!rightIsDraft && shapeDiffCount) {
        batchParts.push('<button class="mini-ai" data-editor-command="apply-comparison-batch" data-batch-kind="shape-diff" data-comparison-from="right">采纳右侧形态 ' + shapeDiffCount + '</button>');
      }
      if (!leftIsDraft && valueDiffCount) {
        batchParts.push('<button class="mini-ai" data-editor-command="apply-comparison-batch" data-batch-kind="value-diff" data-comparison-from="left">采纳左侧值 ' + valueDiffCount + '</button>');
      }
      if (!rightIsDraft && valueDiffCount) {
        batchParts.push('<button class="mini-ai" data-editor-command="apply-comparison-batch" data-batch-kind="value-diff" data-comparison-from="right">采纳右侧值 ' + valueDiffCount + '</button>');
      }
      if (batchParts.length) {
        batchBar = '<div class="comparison-batch-bar"><span>批量采纳：</span>' + batchParts.join('') + '</div>';
      }
    }
    mount.innerHTML = [
      '<h3>剧本对照</h3>',
      '<div class="comparison-controls">',
      '<label>左侧：<select id="comparison-left-select" data-comparison-side="left">' + options + '</select></label>',
      '<label>右侧：<select id="comparison-right-select" data-comparison-side="right">' + options + '</select></label>',
      '<button class="mini-ai" data-editor-command="swap-comparison-sides">互换</button>',
      '<button class="mini-ai" data-editor-command="export-comparison-md">导出 MD</button>',
      '<button class="mini-ai" data-editor-command="copy-comparison-md">复制 MD</button>',
      '</div>',
      '<div class="comparison-summary"><span>共 ' + summary.keysTotal + ' 个字段</span><span>相同 ' + summary.same + '</span><span>形态/值不同 ' + summary.diff + '</span><span>仅左 ' + summary.leftOnly + '</span><span>仅右 ' + summary.rightOnly + '</span></div>',
      batchBar,
      '<div class="comparison-list">' + (rowsHtml || '<p>当前两侧字段完全一致。</p>') + '</div>'
    ].join('');
    var leftSel = document.getElementById('comparison-left-select');
    var rightSel = document.getElementById('comparison-right-select');
    if (leftSel) leftSel.value = state.comparisonLeftId;
    if (rightSel) rightSel.value = state.comparisonRightId;
  }

  function comparisonSourceLabel(id) {
    if (id === 'draft') return '当前草稿';
    var entry = OFFICIAL_SCENARIOS.find(function(e) { return e.id === id; });
    return entry ? entry.title : id;
  }

  function buildComparisonMarkdown(leftId, rightId) {
    var report = buildOfficialComparison(leftId, rightId);
    var leftLabel = comparisonSourceLabel(leftId);
    var rightLabel = comparisonSourceLabel(rightId);
    var summary = report.summary || {};
    var header = [
      '# 剧本对照 · ' + leftLabel + ' vs ' + rightLabel,
      '',
      '- 共有字段：' + (summary.keysTotal || 0),
      '- 相同：' + (summary.same || 0),
      '- 形态 / 值不同：' + (summary.diff || 0),
      '- 仅左：' + (summary.leftOnly || 0),
      '- 仅右：' + (summary.rightOnly || 0),
      '',
      '## 差异详情',
      '',
      '| 字段 | 状态 | 左 (' + leftLabel + ') | 右 (' + rightLabel + ') |',
      '|---|---|---|---|'
    ];
    var rows = report.rows.map(function(row) {
      var statusLabel = row.status === 'left-only' ? '仅左' :
                         row.status === 'right-only' ? '仅右' :
                         row.status === 'shape-diff' ? '形态不同' : '值不同';
      var leftCol = row.leftType === 'none' ? '—' : (row.leftType + ' / ' + row.leftCount);
      var rightCol = row.rightType === 'none' ? '—' : (row.rightType + ' / ' + row.rightCount);
      return '| ' + row.key + ' | ' + statusLabel + ' | ' + leftCol + ' | ' + rightCol + ' |';
    });
    return header.concat(rows).join('\n');
  }

  function exportComparisonMarkdown() {
    var md = buildComparisonMarkdown(state.comparisonLeftId, state.comparisonRightId);
    var filename = '剧本对照-' + (state.comparisonLeftId || 'left') + '-vs-' + (state.comparisonRightId || 'right') + '.md';
    var blob = new Blob([md], { type: 'text/markdown;charset=utf-8' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    a.remove();
    setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
    setStatus('已导出对照 Markdown：' + filename, 'good');
    return md;
  }

  function copyComparisonMarkdown() {
    var md = buildComparisonMarkdown(state.comparisonLeftId, state.comparisonRightId);
    if (global.navigator && global.navigator.clipboard) {
      global.navigator.clipboard.writeText(md).then(function() {
        setStatus('对照 Markdown 已复制到剪贴板', 'good');
      }).catch(function() {
        setStatus('剪贴板写入失败；改用 导出 MD 下载', 'warn');
      });
    } else {
      setStatus('当前环境不支持剪贴板，改用 导出 MD 下载', 'warn');
    }
    return md;
  }

  function swapComparisonSides() {
    var prev = state.comparisonLeftId;
    state.comparisonLeftId = state.comparisonRightId;
    state.comparisonRightId = prev;
    renderOfficialComparison();
  }

  function selectComparisonField(field) {
    if (!field || !Object.prototype.hasOwnProperty.call(state.scenario || {}, field)) {
      setStatus('当前草稿中没有字段：' + field, 'warn');
      return;
    }
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    state.activeWorkbenchPanel = 'field-editor';
    renderAll();
    setStatus('已定位到字段：' + field, 'good');
  }

  function applyComparisonBatch(kind, fromSide) {
    if (!fromSide && (kind === 'left-only' || kind === 'right-only')) {
      // For *-only batches the source side is implied by the row status.
      fromSide = kind === 'left-only' ? 'left' : 'right';
    }
    var leftIsDraft = state.comparisonLeftId === 'draft';
    var rightIsDraft = state.comparisonRightId === 'draft';
    if (!leftIsDraft && !rightIsDraft) {
      setStatus('批量采纳需要当前草稿作为一侧；先在剧本对照里把一侧设为「当前草稿」。', 'warn');
      return null;
    }
    if (fromSide && ((fromSide === 'left' && leftIsDraft) || (fromSide === 'right' && rightIsDraft))) {
      setStatus('请改成采纳另一侧；这一侧就是当前草稿。', 'warn');
      return null;
    }
    var report = buildOfficialComparison(state.comparisonLeftId, state.comparisonRightId);
    var targets;
    if (kind === 'left-only') targets = report.rows.filter(function(r) { return r.status === 'left-only'; });
    else if (kind === 'right-only') targets = report.rows.filter(function(r) { return r.status === 'right-only'; });
    else if (kind === 'shape-diff') targets = report.rows.filter(function(r) { return r.status === 'shape-diff'; });
    else if (kind === 'value-diff') targets = report.rows.filter(function(r) { return r.status === 'value-diff'; });
    else targets = [];
    if (!targets.length) {
      setStatus('没有匹配的字段可批量采纳：' + kind, 'warn');
      return null;
    }
    var sourceId = fromSide === 'left' ? state.comparisonLeftId : state.comparisonRightId;
    var source = comparisonSourceScenario(sourceId);
    if (!source) {
      setStatus('来源剧本不可用：' + sourceId, 'warn');
      return null;
    }
    var applied = 0;
    targets.forEach(function(row) {
      var hadField = Object.prototype.hasOwnProperty.call(source, row.key);
      if (!hadField) return; // batches never DELETE; skip rows the source lacks
      state.scenario[row.key] = clone(source[row.key]);
      applied += 1;
    });
    recordHistory('剧本对照·批量采纳', kind + '·' + applied + ' 项（来源 ' + sourceId + '）');
    renderAll();
    setStatus('已批量采纳 ' + applied + ' 个字段（' + kind + '·来源 ' + sourceId + '）', 'good');
    return applied;
  }

  // Events cross-scenario merge wizard. Lets a creator survey events from the
  // other official scenario and selectively merge them into the current draft
  // without losing existing entries. Match key for "already present" is
  // event.id (canonical) with a fallback to event.name + event.year combo so
  // pre-id legacy entries also dedupe.
  function eventMatchKey(event) {
    if (!event) return null;
    if (event.id) return 'id:' + String(event.id);
    var name = event.name || event.title;
    if (name) return 'name:' + String(name) + (event.year ? '|' + event.year : '');
    return null;
  }

  function collectMergeableEvents(sourceId) {
    var source = comparisonSourceScenario(sourceId);
    if (!source || !Array.isArray(source.events)) return [];
    var current = Array.isArray(state.scenario && state.scenario.events) ? state.scenario.events : [];
    var currentKeys = new Set();
    current.forEach(function(event) {
      var k = eventMatchKey(event);
      if (k) currentKeys.add(k);
    });
    return source.events.map(function(event, index) {
      var key = eventMatchKey(event);
      var present = key ? currentKeys.has(key) : false;
      return {
        sourceId: sourceId,
        index: index,
        key: key || ('idx:' + index),
        event: event,
        present: present
      };
    });
  }

  function toggleEventMergeSelection(sourceId, key) {
    if (!sourceId || !key) return;
    if (!state.eventsMergeSelection) state.eventsMergeSelection = {};
    var slot = sourceId + '|' + key;
    if (state.eventsMergeSelection[slot]) delete state.eventsMergeSelection[slot];
    else state.eventsMergeSelection[slot] = true;
    renderEventsMergeWizard();
  }

  function selectAllUnmergedFromSource(sourceId) {
    if (!sourceId) return;
    if (!state.eventsMergeSelection) state.eventsMergeSelection = {};
    var rows = collectMergeableEvents(sourceId).filter(function(r) { return !r.present; });
    rows.forEach(function(r) { state.eventsMergeSelection[sourceId + '|' + r.key] = true; });
    renderEventsMergeWizard();
    setStatus('已选中 ' + rows.length + ' 个待合并事件（' + sourceId + '）', 'good');
  }

  function clearMergeSelection() {
    state.eventsMergeSelection = {};
    renderEventsMergeWizard();
  }

  function mergeSelectedEvents() {
    var selection = state.eventsMergeSelection || {};
    var keys = Object.keys(selection).filter(function(k) { return selection[k]; });
    if (!keys.length) {
      setStatus('未选中任何事件。先勾选要合并的条目。', 'warn');
      return 0;
    }
    if (!Array.isArray(state.scenario.events)) state.scenario.events = [];
    var existing = state.scenario.events;
    var existingKeys = new Set();
    existing.forEach(function(event) {
      var k = eventMatchKey(event);
      if (k) existingKeys.add(k);
    });
    var added = 0;
    keys.forEach(function(slot) {
      var parts = slot.split('|');
      var sourceId = parts[0];
      var key = parts.slice(1).join('|');
      var rows = collectMergeableEvents(sourceId);
      var hit = rows.find(function(r) { return r.key === key; });
      if (!hit || hit.present) return;
      var cloned = clone(hit.event);
      // Tag the imported event with a provenance note so creators can track
      // where each merged entry came from later.
      if (!cloned._mergedFrom) cloned._mergedFrom = sourceId;
      existing.push(cloned);
      var k = eventMatchKey(cloned);
      if (k) existingKeys.add(k);
      added += 1;
    });
    if (!added) {
      setStatus('选中事件都已存在于当前草稿。', 'neutral');
      return 0;
    }
    state.eventsMergeSelection = {};
    recordHistory('合并事件', added + ' 项（来自其他剧本）');
    state.selectedField = 'events';
    state.selectedModuleId = inferModuleForField('events');
    renderAll();
    setStatus('已合并 ' + added + ' 个事件到当前草稿。', 'good');
    return added;
  }

  function renderEventsMergeWizard() {
    var mount = document.querySelector('[data-panel="events-merge-wizard"]');
    if (!mount) return;
    var selection = state.eventsMergeSelection || {};
    var totalSelected = Object.keys(selection).filter(function(k) { return selection[k]; }).length;
    var groupsHtml = OFFICIAL_SCENARIOS.map(function(entry) {
      // Skip the source if it IS the current draft (no point merging from
      // self). Detection: scenario.id substring match.
      var draftId = state.scenario && state.scenario.id || '';
      if (draftId && draftId.indexOf(entry.id) >= 0) {
        return '<section class="events-merge-group" data-events-merge-group="' + escapeHtml(entry.id) + '" data-self="true"><h4>' + escapeHtml(entry.title) + '</h4><p>当前草稿就是这个剧本（无可合并来源）。</p></section>';
      }
      var rows = collectMergeableEvents(entry.id);
      if (!rows.length) {
        return '<section class="events-merge-group" data-events-merge-group="' + escapeHtml(entry.id) + '"><h4>' + escapeHtml(entry.title) + '</h4><p>该剧本没有事件可合并。</p></section>';
      }
      var presentCount = rows.filter(function(r) { return r.present; }).length;
      var unmergedCount = rows.length - presentCount;
      var rowHtml = rows.slice(0, 80).map(function(row) {
        var slot = entry.id + '|' + row.key;
        var checked = !!selection[slot] && !row.present;
        var disabled = row.present ? ' disabled' : '';
        var name = row.event.name || row.event.title || row.event.id || '事件 #' + (row.index + 1);
        var type = row.event.type || row.event.category || '';
        var year = row.event.year != null ? row.event.year : (row.event.turn != null ? '回 ' + row.event.turn : '');
        var meta = [type, year].filter(Boolean).join(' · ');
        return '<label class="events-merge-row" data-events-merge-present="' + (row.present ? 'true' : 'false') + '">' +
          '<input type="checkbox" data-events-merge-source="' + escapeHtml(entry.id) + '" data-events-merge-key="' + escapeHtml(row.key) + '"' + (checked ? ' checked' : '') + disabled + '>' +
          '<span class="events-merge-row-text"><strong>' + escapeHtml(name) + '</strong>' + (meta ? '<small>' + escapeHtml(meta) + '</small>' : '') + '</span>' +
          (row.present ? '<em class="events-merge-row-status">已存在</em>' : '<em class="events-merge-row-status events-merge-row-status--new">可合并</em>') +
        '</label>';
      }).join('');
      return '<section class="events-merge-group" data-events-merge-group="' + escapeHtml(entry.id) + '">' +
        '<header class="events-merge-group-head"><h4>' + escapeHtml(entry.title) + '</h4><span>可合并 ' + unmergedCount + ' · 已存在 ' + presentCount + '</span><button class="mini-ai" data-editor-command="select-all-merge-source" data-events-merge-source="' + escapeHtml(entry.id) + '" ' + (unmergedCount ? '' : 'disabled') + '>全选未合并</button></header>' +
        '<div class="events-merge-list">' + rowHtml + '</div>' +
      '</section>';
    }).join('');
    mount.innerHTML = [
      '<h3>事件跨剧本合并</h3>',
      '<p class="events-merge-hint">从官方剧本挑选事件合并到当前草稿。已存在的事件（按 id 或 name+year 去重）不会重复加入。</p>',
      '<div class="events-merge-toolbar"><span>已选中 ' + totalSelected + ' 项</span><button class="ai-button" data-editor-command="merge-selected-events">合并选中</button><button class="mini-ai" data-editor-command="clear-merge-selection">清空选中</button></div>',
      groupsHtml
    ].join('');
  }

  function applyComparisonSide(field, fromSide) {
    if (!field || (fromSide !== 'left' && fromSide !== 'right')) return;
    var leftIsDraft = state.comparisonLeftId === 'draft';
    var rightIsDraft = state.comparisonRightId === 'draft';
    // The draft must be one of the two sides; otherwise neither side is the
    // editing target and the action is meaningless.
    if (!leftIsDraft && !rightIsDraft) {
      setStatus('采纳需要当前草稿作为一侧；先在剧本对照里把一侧设为「当前草稿」。', 'warn');
      return null;
    }
    // The source side cannot be the draft itself (you can't copy from draft
    // into draft).
    if ((fromSide === 'left' && leftIsDraft) || (fromSide === 'right' && rightIsDraft)) {
      setStatus('请改成采纳另一侧；这一侧就是当前草稿。', 'warn');
      return null;
    }
    var sourceId = fromSide === 'left' ? state.comparisonLeftId : state.comparisonRightId;
    var source = comparisonSourceScenario(sourceId);
    if (!source) {
      setStatus('来源剧本不可用：' + sourceId, 'warn');
      return null;
    }
    var hadField = Object.prototype.hasOwnProperty.call(source, field);
    if (!hadField) {
      // Source doesn't have it; treat as "remove from draft" with confirm via status text.
      if (!Object.prototype.hasOwnProperty.call(state.scenario || {}, field)) {
        setStatus('两侧都没有字段：' + field, 'warn');
        return null;
      }
      delete state.scenario[field];
      recordHistory('剧本对照·删除字段', field + '（来源 ' + sourceId + ' 没有此字段）');
      state.selectedField = (findModule(state.selectedModuleId).topLevelKeys || Object.keys(state.scenario || {}))[0];
      renderAll();
      setStatus('已根据 ' + sourceId + ' 移除字段：' + field, 'good');
      return null;
    }
    state.scenario[field] = clone(source[field]);
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    recordHistory('剧本对照·采纳字段', field + '（来源 ' + sourceId + '）');
    renderAll();
    setStatus('已采纳 ' + sourceId + ' 的字段：' + field, 'good');
    return clone(state.scenario[field]);
  }

  function revertField(field) {
    if (!field) return;
    if (Object.prototype.hasOwnProperty.call(state.original || {}, field)) state.scenario[field] = clone(state.original[field]);
    else delete state.scenario[field];
    state.selectedField = Object.prototype.hasOwnProperty.call(state.scenario || {}, field) ? field : ((findModule(state.selectedModuleId).topLevelKeys || Object.keys(state.scenario || {}))[0]);
    state.selectedEntityIndex = 0;
    recordHistory('撤回字段', field);
    renderAll();
    setStatus('已撤回字段：' + field, 'good');
  }

  function restoreEditSnapshot(entry, scenario, label) {
    state.scenario = clone(scenario || {});
    state.historyCheckpoint = clone(state.scenario || {});
    state.selectedField = entry.selectedField && Object.prototype.hasOwnProperty.call(state.scenario || {}, entry.selectedField)
      ? entry.selectedField
      : ((findModule(entry.selectedModuleId || state.selectedModuleId).topLevelKeys || Object.keys(state.scenario || {}))[0]);
    state.selectedModuleId = inferModuleForField(state.selectedField);
    var selectedValue = state.scenario[state.selectedField];
    state.selectedEntityIndex = Array.isArray(selectedValue) ? Math.max(0, Math.min(Number(entry.selectedEntityIndex) || 0, selectedValue.length - 1)) : 0;
    state.dirty = true;
    state.validationRan = false;
    pushHistoryLog(label, entry.type + ' · ' + entry.detail);
    writeStoredDraft();
    renderAll();
    setStatus(label + '：' + entry.type + ' · ' + entry.detail, 'good');
    return clone(state.scenario);
  }

  function undoEdit() {
    var entry = state.undoStack.shift();
    if (!entry) {
      setStatus('没有可撤销的编辑。', 'neutral');
      renderEditHistory();
      return null;
    }
    state.redoStack.unshift(entry);
    state.redoStack = state.redoStack.slice(0, 30);
    return restoreEditSnapshot(entry, entry.before, '已撤销');
  }

  function redoEdit() {
    var entry = state.redoStack.shift();
    if (!entry) {
      setStatus('没有可重做的编辑。', 'neutral');
      renderEditHistory();
      return null;
    }
    state.undoStack.unshift(entry);
    state.undoStack = state.undoStack.slice(0, 30);
    return restoreEditSnapshot(entry, entry.after, '已重做');
  }

  function collectNames(rows, keys) {
    var set = new Set();
    (rows || []).forEach(function(row) {
      keys.forEach(function(key) {
        if (row && row[key]) set.add(String(row[key]));
      });
    });
    return set;
  }

  function validateScenario() {
    var issues = [];
    var sc = state.scenario || {};
    ['id', 'name', 'characters', 'factions'].forEach(function(key) {
      if (sc[key] == null || sc[key] === '') issues.push({ level: 'error', text: '缺少关键字段：' + key });
    });
    if (!Array.isArray(sc.characters) || sc.characters.length < 1) issues.push({ level: 'error', text: 'characters 不是有效人物数组' });
    if (!Array.isArray(sc.factions) || sc.factions.length < 1) issues.push({ level: 'error', text: 'factions 不是有效势力数组' });
    var charNames = collectNames(sc.characters, ['name', 'id', 'sid']);
    var factionNames = collectNames(sc.factions, ['name', 'id', 'sid', 'key', 'ownerKey']);
    (Array.isArray(sc.characters) ? sc.characters : []).forEach(function(ch) {
      if (ch && ch.faction && !factionNames.has(ch.faction)) issues.push({ level: 'warn', text: '人物势力未匹配：' + (ch.name || ch.id) + ' -> ' + ch.faction });
    });
    ['characters', 'factions', 'events'].forEach(function(field) {
      var seen = new Set();
      (Array.isArray(sc[field]) ? sc[field] : []).forEach(function(row) {
        var key = row && (row.id || row.sid || row.name || row.title);
        if (!key) return;
        if (seen.has(key)) issues.push({ level: 'warn', text: field + ' 存在重复标识：' + key });
        seen.add(key);
      });
    });
    function validateRefs(rows, rowKind, refKey, known, targetKind) {
      (Array.isArray(rows) ? rows : []).forEach(function(row) {
        splitList(row && row[refKey]).forEach(function(ref) {
          if (!known.has(ref)) issues.push({ level: 'warn', text: rowKind + '引用未知' + targetKind + '：' + (row.name || row.id || '未命名') + ' -> ' + ref });
        });
      });
    }
    validateRefs(sc.events, '事件', 'linkedChars', charNames, '人物');
    validateRefs(sc.events, '事件', 'linkedFactions', factionNames, '势力');
    validateRefs(sc.rigidHistoryEvents, '硬历史事件', 'linkedChars', charNames, '人物');
    validateRefs(sc.rigidHistoryEvents, '硬历史事件', 'linkedFactions', factionNames, '势力');
    validateRefs(sc.factionRelations, '势力关系', 'from', factionNames, '势力');
    validateRefs(sc.factionRelations, '势力关系', 'to', factionNames, '势力');
    validateRefs(sc.relations, '人物关系', 'from', charNames, '人物');
    validateRefs(sc.relations, '人物关系', 'to', charNames, '人物');
    state.modules.forEach(function(module) {
      (module.topLevelKeys || []).forEach(function(key) {
        if (!(key in sc)) issues.push({ level: 'warn', text: moduleTitle(module) + ' 缺少字段：' + key });
      });
    });
    state.validations = issues;
    state.validationRan = true;
    renderValidation();
    renderScenarioDashboard();
    renderProductionDashboard();
    renderPreflightGate();
    setStatus(issues.length ? ('校验完成：' + issues.length + ' 项提示') : '校验通过：未发现关键问题', issues.length ? 'warn' : 'good');
    return issues;
  }

  function refAliases(entity) {
    if (!entity || typeof entity !== 'object') return [];
    var keys = ['id', 'sid', 'name', 'title', 'key', 'ownerKey'];
    var aliases = [];
    keys.forEach(function(key) {
      if (entity[key] != null && entity[key] !== '') aliases.push(String(entity[key]));
    });
    return Array.from(new Set(aliases));
  }

  function buildEntityIndex() {
    var index = {};
    ['characters', 'factions', 'families', 'events', 'rigidHistoryEvents', 'timeline'].forEach(function(field) {
      var list = state.scenario[field];
      if (!Array.isArray(list)) return;
      list.forEach(function(entity, entityIndex) {
        refAliases(entity).forEach(function(alias) {
          index[alias] = { field: field, index: entityIndex, entity: entity, label: labelOf(entity, entityIndex) };
        });
      });
    });
    return index;
  }

  function buildReferenceReport(field, entity) {
    var current = entity || currentEntity();
    var aliases = refAliases(current);
    var index = buildEntityIndex();
    var incoming = [];
    var outgoing = [];
    var missing = [];
    function pushOutgoing(ref, sourceField, detail) {
      if (!ref) return;
      var target = index[String(ref)];
      var row = { sourceField: sourceField, sourceLabel: String(ref), detail: detail, status: target ? 'ok' : 'missing', targetField: target && target.field, targetIndex: target ? target.index : -1 };
      outgoing.push(row);
      if (!target) missing.push(row);
    }
    if (current && typeof current === 'object') {
      ['faction', 'leader', 'founder', 'owner', 'linkedChars', 'linkedFactions', 'members'].forEach(function(key) {
        splitList(current[key]).forEach(function(ref) { pushOutgoing(ref, key, 'out:' + key); });
      });
    }
    ['characters', 'factions', 'families', 'events', 'rigidHistoryEvents', 'timeline', 'factionRelations', 'relations', 'parties', 'classes', 'items'].forEach(function(sourceField) {
      var list = state.scenario[sourceField];
      if (!Array.isArray(list)) return;
      list.forEach(function(row, idx) {
        ['faction', 'leader', 'founder', 'owner', 'linkedChars', 'linkedFactions', 'members', 'from', 'to'].forEach(function(key) {
          splitList(row && row[key]).forEach(function(ref) {
            if (aliases.indexOf(String(ref)) >= 0) {
              incoming.push({ sourceField: sourceField, sourceLabel: labelOf(row, idx), detail: key, status: 'ok', targetField: sourceField, targetIndex: idx });
            }
          });
        });
      });
    });
    return { field: field || state.selectedField, entity: current, aliases: aliases, incoming: incoming, outgoing: outgoing, missing: missing };
  }

  // 权威引用字段表：哪些集合的哪些字段引用实体(character/faction)。断裂扫描/删除清理/重命名传播三处共用——单一真源，杜绝盲区。
  var ENTITY_REF_FIELDS = [
    { field: 'characters', key: 'faction', kind: 'faction', shape: 'scalar' },
    { field: 'factions', key: 'leader', kind: 'character', shape: 'scalar' },
    { field: 'families', key: 'founder', kind: 'character', shape: 'scalar' },
    { field: 'families', key: 'members', kind: 'character', shape: 'list' },
    { field: 'parties', key: 'leader', kind: 'character', shape: 'scalar' },
    { field: 'classes', key: 'leader', kind: 'character', shape: 'scalar' },
    { field: 'events', key: 'linkedChars', kind: 'character', shape: 'list' },
    { field: 'events', key: 'linkedFactions', kind: 'faction', shape: 'list' },
    { field: 'rigidHistoryEvents', key: 'linkedChars', kind: 'character', shape: 'list' },
    { field: 'rigidHistoryEvents', key: 'linkedFactions', kind: 'faction', shape: 'list' },
    { field: 'timeline', key: 'linkedChars', kind: 'character', shape: 'list' },
    { field: 'timeline', key: 'linkedFactions', kind: 'faction', shape: 'list' },
    { field: 'items', key: 'owner', kind: 'character', shape: 'scalar' },
    { field: 'factionRelations', key: 'from', kind: 'faction', shape: 'relation' },
    { field: 'factionRelations', key: 'to', kind: 'faction', shape: 'relation' },
    { field: 'relations', key: 'from', kind: 'character', shape: 'relation' },
    { field: 'relations', key: 'to', kind: 'character', shape: 'relation' }
  ];

  // 修悬空引用：删 character/faction 后清理别处对它的引用。关系行(factionRelations/relations)from/to 指向被删者→删整行；
  // list 引用(linkedChars/members)→摘掉该别名；scalar 引用(faction/leader/founder/owner)→清空。返回清理处数。
  function cleanupEntityReferences(removed, kind) {
    if (!removed || (kind !== 'character' && kind !== 'faction')) return 0;
    var aliasSet = {};
    refAliases(removed).forEach(function (a) { aliasSet[String(a)] = true; });
    if (!Object.keys(aliasSet).length) return 0;
    var sc = state.scenario || {};
    var cleaned = 0;
    ENTITY_REF_FIELDS.forEach(function (rf) {
      if (rf.kind !== kind) return;
      var list = sc[rf.field];
      if (!Array.isArray(list)) return;
      if (rf.shape === 'relation') {
        for (var i = list.length - 1; i >= 0; i--) {
          var row = list[i];
          if (row && (aliasSet[String(row.from)] || aliasSet[String(row.to)])) { list.splice(i, 1); cleaned++; }
        }
      } else if (rf.shape === 'list') {
        list.forEach(function (row) {
          if (!row) return;
          var arr = splitList(row[rf.key]);
          var kept = arr.filter(function (ref) { return !aliasSet[String(ref)]; });
          if (kept.length !== arr.length) { row[rf.key] = kept; cleaned += (arr.length - kept.length); }
        });
      } else {
        list.forEach(function (row) {
          if (row && aliasSet[String(row[rf.key])]) { row[rf.key] = ''; cleaned++; }
        });
      }
    });
    return cleaned;
  }

  // 修引用断裂：重命名 character/faction 的 name/id 等别名后，按位置映射(name→name、id→id)同步改别处引用。
  function buildRenameMap(oldE, newE) {
    var map = {};
    ['id', 'sid', 'name', 'title', 'key', 'ownerKey'].forEach(function (k) {
      var ov = oldE && oldE[k], nv = newE && newE[k];
      if (ov != null && ov !== '' && nv != null && nv !== '' && String(ov) !== String(nv)) map[String(ov)] = String(nv);
    });
    return map;
  }
  function propagateRename(parentField, oldEntity, newEntity) {
    var kind = parentField === 'characters' ? 'character' : (parentField === 'factions' ? 'faction' : null);
    if (!kind) return 0;
    var map = buildRenameMap(oldEntity, newEntity);
    if (!Object.keys(map).length) return 0;
    var sc = state.scenario || {};
    var changed = 0;
    ENTITY_REF_FIELDS.forEach(function (rf) {
      if (rf.kind !== kind) return;
      var list = sc[rf.field];
      if (!Array.isArray(list)) return;
      list.forEach(function (row) {
        if (!row) return;
        if (rf.shape === 'list') {
          var arr = splitList(row[rf.key]); var hit = false;
          var mapped = arr.map(function (ref) { if (map[String(ref)]) { hit = true; return map[String(ref)]; } return ref; });
          if (hit) { row[rf.key] = mapped; changed++; }
        } else if (map[String(row[rf.key])]) { row[rf.key] = map[String(row[rf.key])]; changed++; }
      });
    });
    return changed;
  }

  function collectMissingReferences() {
    var sc = state.scenario || {};
    var known = {
      character: collectNames(sc.characters, ['name', 'id', 'sid']),
      faction: collectNames(sc.factions, ['name', 'id', 'sid', 'key', 'ownerKey'])
    };
    var rows = [];
    var seen = {};
    function add(kind, ref, sourceField, sourceIndex, refKey, sourceLabel) {
      var name = String(ref == null ? '' : ref).trim();
      if (!name) return;
      if (known[kind] && known[kind].has(name)) return;
      var id = kind + '|' + name;
      var row = seen[id];
      if (!row) {
        row = { kind: kind, ref: name, sourceCount: 0, sources: [] };
        seen[id] = row;
        rows.push(row);
      }
      row.sourceCount += 1;
      row.sources.push({ field: sourceField, index: sourceIndex, key: refKey, label: sourceLabel || (sourceField + '[' + sourceIndex + ']') });
    }
    function scan(field, mapping) {
      var list = sc[field];
      if (!Array.isArray(list)) return;
      list.forEach(function(item, index) {
        Object.keys(mapping).forEach(function(key) {
          splitList(item && item[key]).forEach(function(ref) {
            add(mapping[key], ref, field, index, key, labelOf(item, index));
          });
        });
      });
    }
    var _refByField = {};
    ENTITY_REF_FIELDS.forEach(function (rf) { (_refByField[rf.field] = _refByField[rf.field] || {})[rf.key] = rf.kind; });
    Object.keys(_refByField).forEach(function (f) { scan(f, _refByField[f]); });
    return rows.sort(function(a, b) {
      return b.sourceCount - a.sourceCount || a.kind.localeCompare(b.kind) || a.ref.localeCompare(b.ref);
    });
  }

  function referenceTargetKind(kind) {
    return kind === 'faction' ? 'faction' : 'character';
  }

  function referenceFieldForKind(kind) {
    return referenceTargetKind(kind) === 'faction' ? 'factions' : 'characters';
  }

  function buildReferencePlaceholder(kind, name) {
    var targetKind = referenceTargetKind(kind);
    if (targetKind === 'faction') {
      return { id: uniqueId('fac_missing'), name: name, leader: '', color: '#9b7a38', strength: 0, militaryStrength: 0, economy: 0, capital: '', ideology: '待补', traits: ['引用修复占位'], desc: '由断裂引用修复生成的待补势力，请补齐领袖、地盘、经济、军事与外交字段。' };
    }
    return { id: uniqueId('char_missing'), name: name, title: '待补人物', officialTitle: '', role: '引用修复占位', faction: '', age: 30, gender: '未知', alive: true, desc: '由断裂引用修复生成的待补人物，请补齐身份、派系、履历、性格与关系字段。', aiPersona: { style: '待补', goals: [] } };
  }

  function findReferencePlaceholderIndex(kind, name) {
    var field = referenceFieldForKind(kind);
    var list = state.scenario[field];
    if (!Array.isArray(list)) return -1;
    return list.findIndex(function(item) {
      return refAliases(item).indexOf(name) >= 0;
    });
  }

  function createReferencePlaceholder(kind, ref) {
    var targetKind = referenceTargetKind(kind);
    var name = String(ref == null ? '' : ref).trim();
    if (!name) throw new Error('缺少引用名称');
    var field = referenceFieldForKind(targetKind);
    if (!Array.isArray(state.scenario[field])) state.scenario[field] = [];
    var existingIndex = state.scenario[field].findIndex(function(item) {
      return refAliases(item).indexOf(name) >= 0;
    });
    if (existingIndex >= 0) {
      state.selectedField = field;
      state.selectedModuleId = inferModuleForField(field);
      state.selectedEntityIndex = existingIndex;
      renderAll();
      return state.scenario[field][existingIndex];
    }
    var entity = targetKind === 'faction'
      ? { id: uniqueId('fac_missing'), name: name, leader: '', color: '#9b7a38', strength: 0, militaryStrength: 0, economy: 0, capital: '', ideology: '待补', traits: ['引用修复占位'], desc: '由断裂引用修复生成的待补势力，请补齐领袖、地盘、经济、军事与外交字段。' }
      : { id: uniqueId('char_missing'), name: name, title: '待补人物', officialTitle: '', role: '引用修复占位', faction: '', age: 30, gender: '未知', alive: true, desc: '由断裂引用修复生成的待补人物，请补齐身份、派系、履历、性格与关系字段。', aiPersona: { style: '待补', goals: [] } };
    state.scenario[field].push(entity);
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    state.selectedEntityIndex = state.scenario[field].length - 1;
    recordHistory('补齐断裂引用', targetKind + ': ' + name);
    renderAll();
    setStatus('已生成引用占位：' + name, 'good');
    return entity;
  }

  function createAllReferencePlaceholders(kind) {
    var scope = String(kind || 'all').trim();
    var rows = collectMissingReferences().filter(function(row) {
      return scope === 'all' || row.kind === scope;
    });
    var created = [];
    rows.forEach(function(row) {
      var targetKind = referenceTargetKind(row.kind);
      var name = String(row.ref || '').trim();
      if (!name) return;
      var field = referenceFieldForKind(targetKind);
      if (!Array.isArray(state.scenario[field])) state.scenario[field] = [];
      if (findReferencePlaceholderIndex(targetKind, name) >= 0) return;
      var entity = buildReferencePlaceholder(targetKind, name);
      state.scenario[field].push(entity);
      created.push({ kind: targetKind, field: field, name: name, index: state.scenario[field].length - 1 });
    });
    if (!created.length) {
      renderReferenceRepairWorkbench();
      setStatus('当前范围内没有需要批量生成的断裂引用占位', 'neutral');
      return { created: [], scope: scope };
    }
    var first = created[0];
    state.selectedField = first.field;
    state.selectedModuleId = inferModuleForField(first.field);
    state.selectedEntityIndex = first.index;
    state.search = '';
    state.activeWorkbenchPanel = 'specialist-editor';
    recordHistory('批量补齐断裂引用', created.length + ' 项 · ' + created.slice(0, 8).map(function(row) { return row.name; }).join(', '));
    renderAll();
    setStatus('已批量生成断裂引用占位：' + created.length + ' 项', 'good');
    return { created: clone(created), scope: scope };
  }

  function buildPreflightReport() {
    var items = [];
    var diff = buildScenarioDiff();
    var pendingDrafts = state.drafts.filter(function(draft) { return draft.status !== 'accepted'; });
    if (!state.validationRan) validateScenario();
    state.validations.slice(0, 10).forEach(function(issue) {
      items.push({ level: issue.level === 'error' ? 'error' : 'warn', title: issue.level === 'error' ? '基础校验错误' : '基础校验提示', detail: issue.text, command: 'validate', actionLabel: '复核' });
    });
    if (!items.length) items.push({ level: 'ok', title: '基础校验通过', detail: '关键字段、重复标识和基础引用未发现阻断问题。' });
    items.push({ level: diff.length ? 'warn' : 'ok', title: diff.length ? '存在本地改动' : '变更清册干净', detail: diff.length + ' 个顶层字段与基线不同。', command: diff.length ? 'select-diff-field' : '', diffField: diff[0] && diff[0].key, actionLabel: '查看' });
    items.push({ level: pendingDrafts.length ? 'warn' : 'ok', title: pendingDrafts.length ? 'AI 草稿待审阅' : 'AI 草稿已处理', detail: pendingDrafts.length + ' 条生成内容待确认。', command: pendingDrafts.length ? 'compare-draft' : '', draftId: pendingDrafts[0] && pendingDrafts[0].id, actionLabel: '审阅' });
    var errors = items.filter(function(item) { return item.level === 'error'; }).length;
    var warnings = items.filter(function(item) { return item.level === 'warn'; }).length;
    return { items: items, errors: errors, warnings: warnings, canExport: errors === 0, pendingDrafts: pendingDrafts.length, changedFields: diff.length };
  }

  function releaseNoteLine(item) {
    var statusMap = { added: '新增', removed: '移除', changed: '调整' };
    return (statusMap[item.status] || item.status) + ' ' + item.key + '：' + item.beforeType + ' ' + item.beforeCount + ' -> ' + item.afterType + ' ' + item.afterCount;
  }

  function buildReleaseNotes(options) {
    var opts = options || {};
    var diff = buildScenarioDiff();
    var report = buildPreflightReport();
    var scenarioName = state.scenario.name || '未命名剧本';
    var title = scenarioName + ' 发布说明';
    var changes = diff.map(function(item) {
      return {
        key: item.key,
        status: item.status,
        beforeType: item.beforeType,
        afterType: item.afterType,
        beforeCount: item.beforeCount,
        afterCount: item.afterCount,
        summary: releaseNoteLine(item)
      };
    });
    var checklist = report.items.map(function(item) {
      return {
        level: item.level,
        title: item.title,
        detail: item.detail
      };
    });
    var highlights = [];
    if (changes.length) highlights.push('本次改动 ' + changes.length + ' 个顶层字段。');
    else highlights.push('当前草稿与基线一致，尚无字段级改动。');
    if (report.pendingDrafts) highlights.push(report.pendingDrafts + ' 条 AI 草稿仍需审阅。');
    if (report.errors) highlights.push(report.errors + ' 项发布错误需要先修复。');
    else highlights.push('未发现阻断导出的结构错误。');
    var markdown = [
      '# ' + title,
      '',
      '- 剧本 id：' + (state.scenario.id || '未填写'),
      '- 生成时间：' + new Date().toISOString(),
      '- 改动字段：' + changes.length,
      '- 发布预检：' + report.errors + ' 错误 / ' + report.warnings + ' 提醒',
      '',
      '## 摘要',
      highlights.map(function(line) { return '- ' + line; }).join('\n'),
      '',
      '## 字段变更',
      (changes.length ? changes.map(function(item) { return '- ' + item.summary; }).join('\n') : '- 无字段级变更'),
      '',
      '## 发布检查',
      (checklist.length ? checklist.map(function(item) { return '- [' + item.level + '] ' + item.title + '：' + item.detail; }).join('\n') : '- 暂无检查项')
    ].join('\n');
    var result = {
      title: title,
      scenarioId: state.scenario.id || '',
      scenarioName: scenarioName,
      generatedAt: new Date().toISOString(),
      summary: {
        changedFields: changes.length,
        validationErrors: report.errors,
        validationWarnings: report.warnings,
        pendingDrafts: report.pendingDrafts,
        canExport: report.canExport
      },
      highlights: highlights,
      changes: changes,
      checklist: checklist,
      markdown: markdown
    };
    if (opts.plainText) return markdown;
    return result;
  }

  function runPreflight() {
    validateScenario();
    var report = buildPreflightReport();
    renderPreflightGate(report);
    renderReleaseNotes();
    setStatus(report.canExport ? ('发布预检通过：' + report.warnings + ' 项提醒') : ('发布预检阻断：' + report.errors + ' 项错误'), report.canExport ? (report.warnings ? 'warn' : 'good') : 'error');
    return report;
  }

  function preflightExport() {
    var report = runPreflight();
    if (!report.canExport) {
      setStatus('导出已拦截：请先处理发布预检中的错误项。', 'error');
      return null;
    }
    return exportScenario();
  }

  function scenarioRuntimeCounts(sc) {
    var scenario = sc || state.scenario || {};
    var map = scenario.map && Array.isArray(scenario.map.regions) ? scenario.map : scenario.mapData;
    return {
      fields: Object.keys(scenario).length,
      characters: countCollection(scenario.characters),
      factions: countCollection(scenario.factions),
      events: countCollection(scenario.events) + countCollection(scenario.rigidHistoryEvents),
      mapRegions: countCollection(map)
    };
  }

  function findPlayerCharacter(sc) {
    var scenario = sc || state.scenario || {};
    var info = isObject(scenario.playerInfo) ? scenario.playerInfo : {};
    var playerName = info.characterName || info.factionLeader || '';
    return (scenario.characters || []).find(function(ch) {
      return ch && (ch.isPlayer || (playerName && ch.name === playerName));
    }) || null;
  }

  function findPlayerFaction(sc) {
    var scenario = sc || state.scenario || {};
    var info = isObject(scenario.playerInfo) ? scenario.playerInfo : {};
    var factionName = info.factionName || info.characterFaction || '';
    return (scenario.factions || []).find(function(fac) {
      return fac && (fac.isPlayer || (factionName && fac.name === factionName));
    }) || null;
  }

  function buildQuickTestReport(options) {
    var opts = options || {};
    validateScenario();
    var sc = state.scenario || {};
    var issues = (state.validations || []).map(function(issue) {
      return { level: issue.level, text: issue.text };
    });
    if (!Array.isArray(sc.characters) || !sc.characters.length) issues.push({ level: 'error', text: '正式沙盒至少需要 1 个人物。' });
    if (!Array.isArray(sc.factions) || !sc.factions.length) issues.push({ level: 'error', text: '正式沙盒至少需要 1 个势力。' });
    if (!findPlayerCharacter(sc)) issues.push({ level: 'warn', text: '未明确玩家人物；沙盒会使用正式运行时的兜底逻辑。' });
    if (!findPlayerFaction(sc)) issues.push({ level: 'warn', text: '未明确玩家势力；建议先在玩家设定工坊同步。' });
    var errors = issues.filter(function(issue) { return issue.level === 'error'; }).length;
    var warnings = issues.filter(function(issue) { return issue.level !== 'error'; }).length;
    state.quickTestReport = {
      id: uniqueId('quick_test'),
      createdAt: new Date().toISOString(),
      scenarioId: sc.id || '',
      scenarioName: sc.name || '未命名剧本',
      counts: scenarioRuntimeCounts(sc),
      issues: issues.slice(0, 36),
      errors: errors,
      warnings: warnings,
      canLaunch: errors === 0
    };
    renderQuickTestWorkbench();
    writeStoredDraft();
    if (!opts.silent) setStatus(state.quickTestReport.canLaunch ? '正式沙盒预检通过，可以启动。' : ('正式沙盒预检阻断：' + errors + ' 项错误'), state.quickTestReport.canLaunch ? (warnings ? 'warn' : 'good') : 'error');
    return clone(state.quickTestReport);
  }

  function buildSandboxScenario() {
    var sc = clone(state.scenario || {});
    var id = 'scenario-editor-sandbox-' + Date.now().toString(36);
    sc.id = id;
    sc.name = String(sc.name || '未命名剧本').replace(/（预览沙盒）$/, '') + '（预览沙盒）';
    sc.era = sc.era || (sc.gameSettings && sc.gameSettings.eraName) || '';
    sc.role = sc.role || (sc.playerInfo && sc.playerInfo.playerRole) || '沙盒测试';
    sc.background = sc.background || sc.overview || '由新剧本编辑器写入正式运行时的沙盒测试剧本。';
    if (!sc.opening || String(sc.opening).length < 80) {
      sc.opening = (sc.background || sc.overview || sc.name || '新剧本沙盒') + '\n\n这是从新剧本编辑器启动的正式运行时沙盒，用于检查人物、势力、地图、制度和事件数据能否进入游戏。';
    }
    sc.active = true;
    sc._scenarioEditorSandbox = true;
    sc._source = 'scenario-editor-reset-preview';
    ['characters', 'factions', 'classes', 'parties', 'items', 'events', 'rigidHistoryEvents', 'timeline'].forEach(function(field) {
      if (Array.isArray(sc[field])) {
        sc[field] = sc[field].map(function(row) {
          var next = clone(row);
          next.sid = id;
          next._scenarioEditorSandbox = true;
          return next;
        });
      }
    });
    return sc;
  }

  function formalSandboxUrl(payload) {
    return '../index.html?tmScenarioSandbox=' + encodeURIComponent(payload.id) + '&tmScenarioAutoStart=1';
  }

  function saveFormalSandboxPayload() {
    var report = buildQuickTestReport({ silent: true });
    var scenario = buildSandboxScenario();
    var payload = {
      id: scenario.id,
      createdAt: new Date().toISOString(),
      source: 'scenario-editor-reset-preview',
      report: report,
      scenario: scenario
    };
    try {
      localStorage.setItem(SANDBOX_STORAGE_KEY, JSON.stringify(payload));
    } catch (err) {
      setStatus('正式沙盒写入失败：' + (err && err.message || err), 'error');
      throw err;
    }
    state.sandboxLaunch = {
      id: payload.id,
      createdAt: payload.createdAt,
      url: formalSandboxUrl(payload),
      report: report
    };
    renderQuickTestWorkbench();
    writeStoredDraft();
    return clone(payload);
  }

  function launchFormalSandbox() {
    var report = buildQuickTestReport();
    if (!report.canLaunch) {
      setStatus('正式沙盒未启动：请先处理 ' + report.errors + ' 项错误。', 'error');
      return null;
    }
    var payload = saveFormalSandboxPayload();
    var url = formalSandboxUrl(payload);
    setStatus('已写入正式沙盒，正在打开正式游戏。', 'good');
    var opened = global.open ? global.open(url, '_blank', 'noopener') : null;
    if (!opened && global.location) global.location.href = url;
    return payload;
  }

  function buildRuntimeReturnScenario() {
    var sc = clone(state.scenario || {});
    sc.id = sc.id || uniqueId('scenario');
    sc.name = sc.name || '未命名剧本';
    sc.era = sc.era || (sc.gameSettings && sc.gameSettings.eraName) || '';
    sc.role = sc.role || (sc.playerInfo && sc.playerInfo.playerRole) || '';
    sc.background = sc.background || sc.overview || sc.desc || '';
    sc.active = sc.active !== false;
    ['characters', 'factions', 'parties', 'classes', 'items', 'relations', 'events', 'rigidHistoryEvents', 'timeline', 'families'].forEach(function(field) {
      if (!Array.isArray(sc[field])) return;
      sc[field] = sc[field].map(function(row) {
        var next = clone(row);
        next.sid = sc.id;
        delete next._scenarioEditorSandbox;
        return next;
      });
    });
    delete sc._scenarioEditorSandbox;
    return sc;
  }

  function saveRuntimeReturnPayload() {
    var scenario = buildRuntimeReturnScenario();
    var payload = {
      id: scenario.id,
      createdAt: new Date().toISOString(),
      source: 'scenario-editor-reset-preview',
      scenario: scenario,
      releaseNotes: buildReleaseNotes(),
      fieldNotes: clone(state.fieldNotes || {})
    };
    return putRuntimeReturnBody(payload).then(function(idbOk) {
      var manifest = {
        id: payload.id,
        createdAt: payload.createdAt,
        source: payload.source,
        scenarioName: scenario.name,
        storage: idbOk ? 'indexedDB' : 'localStorage',
        dbKey: runtimeReturnDbId(payload.id)
      };
      try {
        try { localStorage.removeItem(RUNTIME_RETURN_STORAGE_KEY); } catch (_) {}
        localStorage.setItem(RUNTIME_RETURN_STORAGE_KEY, JSON.stringify(idbOk ? manifest : payload));
      } catch (err) {
        setStatus('写回正式页失败：' + (err && err.message || err), 'error');
        throw err;
      }
      state.runtimeReturn = { id: payload.id, createdAt: payload.createdAt, scenarioName: scenario.name, storage: manifest.storage };
      writeStoredDraft();
      setStatus(idbOk ? ('已准备写回正式页：' + scenario.name + '（大剧本走本地库）') : ('已准备写回正式页：' + scenario.name), 'good');
      return clone(payload);
    });
  }

  function returnToFormalRuntime() {
    return saveRuntimeReturnPayload().then(function(payload) {
      if (global.location) global.location.href = '../index.html?tmScenarioEditorReturn=' + encodeURIComponent(payload.id);
      return payload;
    }).catch(function(err) {
      setStatus('写回正式页失败：' + (err && err.message || err), 'error');
      return null;
    });
  }

  // ── 地图编辑器跳转往返（刀3·①）·复用 MapEditorBridge(刀2) + applyMapPatch(刀1) ──
  function launchMapEditor() {
    var Bridge = global.MapEditorBridge || {};
    var toME = Bridge.convertScenarioToMapEditor || global.convertScenarioToMapEditor;
    if (typeof toME !== 'function') {
      setStatus('地图编辑器桥未加载（map-editor-to-game.js 缺失），无法跳转。', 'error');
      return null;
    }
    var native;
    try { native = toME(state.scenario); }
    catch (err) { setStatus('转换地图给编辑器失败：' + (err && err.message || err), 'error'); return null; }
    var payload = {
      id: (state.scenario && state.scenario.id) || uniqueId('scenario'),
      createdAt: new Date().toISOString(),
      source: 'scenario-editor-reset-preview',
      native: native
    };
    try { localStorage.setItem(MAP_HANDOFF_KEY, JSON.stringify(payload)); }
    catch (err) { setStatus('写入地图交接失败（可能过大）：' + (err && err.message || err), 'error'); return null; }
    ensureMapReturnListener();
    var divCount = (native.divisions || []).length;
    var url = '../map-editor.html?tmFromJuben=1';
    var opened = global.open ? global.open(url, '_blank') : null;
    if (!opened && global.location) global.location.href = url;
    setStatus('已把 ' + divCount + ' 个地块交接给地图编辑器，正在打开。画完点「返回剧本」即可写回。', 'good');
    return payload;
  }

  var _mapReturnListenerArmed = false;
  function ensureMapReturnListener() {
    if (_mapReturnListenerArmed || !global.addEventListener) return;
    _mapReturnListenerArmed = true;
    global.addEventListener('storage', function(e) {
      if (e && e.key === MAP_RETURN_KEY && e.newValue) ingestMapReturn();
    });
    global.addEventListener('focus', function() {
      try { if (localStorage.getItem(MAP_RETURN_KEY)) ingestMapReturn(); } catch (err) {}
    });
  }

  function clearMapReturn() {
    try { localStorage.removeItem(MAP_RETURN_KEY); } catch (err) {}
    try { deleteMapReturnBody(); } catch (err) {}
  }

  function applyReturnedNative(native) {
    var Bridge = global.MapEditorBridge || {};
    var toGame = Bridge.convertMapEditorToGame || global.convertMapEditorToGame;
    var toAdmin = Bridge.convertMapEditorToAdminHierarchy || global.convertMapEditorToAdminHierarchy;
    if (typeof toGame !== 'function') { setStatus('地图编辑器桥未加载，无法读回地图。', 'error'); return null; }
    var gm, ah;
    try {
      gm = toGame(native);
      ah = typeof toAdmin === 'function' ? toAdmin(native) : null;
    } catch (err) { setStatus('读回地图失败：' + (err && err.message || err), 'error'); return null; }
    if (!isObject(state.scenario.map)) state.scenario.map = { regions: [], oceans: [] };
    if (ah) state.scenario.adminHierarchy = ah;
    return applyMapPatch(function(map) {
      map.regions = (Array.isArray(gm.regions) ? gm.regions : []).map(function(r) {
        if (r && r.owner && !r.ownerKey) r.ownerKey = r.owner;
        return r;
      });
      if (gm.width) map.width = gm.width;
      if (gm.height) map.height = gm.height;
      if (gm.name) map.name = gm.name;
      if (gm._v2) map._v2 = gm._v2;
    }, { field: 'map', label: '地图编辑器返回', detail: (gm.regions || []).length + ' 地块', status: '已从地图编辑器载入地图：' + (gm.regions || []).length + ' 地块 · ' + (ah ? Object.keys(ah).length + ' 势力行政' : '无行政层') });
  }

  function ingestMapReturn() {
    var raw;
    try { raw = localStorage.getItem(MAP_RETURN_KEY); } catch (err) { return null; }
    if (!raw) return null;
    var payload;
    try { payload = JSON.parse(raw); } catch (err) { clearMapReturn(); return null; }
    // 大地图走 IndexedDB（payload 只是小信号 {idb:true}）；旧版内联 payload.native 仍兼容。
    if (payload && payload.idb) {
      getMapReturnBody().then(function(body) {
        var native = body && body.native;
        if (!native || !native.divisions) { clearMapReturn(); return; }
        applyReturnedNative(native);
        clearMapReturn();
      });
      return null;
    }
    var native = payload && payload.native;
    if (!native || !native.divisions) { clearMapReturn(); return null; }
    var applied = applyReturnedNative(native);
    clearMapReturn();
    return applied;
  }

  function renderQuickTestWorkbench() {
    var box = document.getElementById('quick-test-list');
    if (!box) return;
    var report = state.quickTestReport;
    var launch = state.sandboxLaunch;
    if (!report) {
      var counts = scenarioRuntimeCounts(state.scenario);
      box.innerHTML = '<div class="quick-test-summary"><strong>待预检</strong><span>' + counts.fields + ' 字段 · ' + counts.characters + ' 人物 · ' + counts.factions + ' 势力 · ' + counts.mapRegions + ' 地块</span></div><p>运行快速预检后，可把当前草稿写入正式游戏沙盒。</p>';
      return;
    }
    var rows = report.issues.slice(0, 10).map(function(issue) {
      return '<div class="quick-test-row" data-level="' + escapeHtml(issue.level) + '">' + escapeHtml(issue.text) + '</div>';
    }).join('');
    box.innerHTML = [
      '<div class="quick-test-summary" data-level="' + (report.canLaunch ? (report.warnings ? 'warn' : 'ok') : 'error') + '"><strong>' + escapeHtml(report.canLaunch ? '可启动' : '需修复') + '</strong><span>' + report.counts.fields + ' 字段 · ' + report.counts.characters + ' 人物 · ' + report.counts.factions + ' 势力 · 错误 ' + report.errors + ' · 提醒 ' + report.warnings + '</span></div>',
      rows || '<div class="quick-test-row" data-level="ok">正式沙盒预检未发现阻断项。</div>',
      launch && launch.url ? '<div class="sandbox-status"><b>最近沙盒</b><span>' + escapeHtml(launch.id) + '</span><a href="' + escapeHtml(launch.url) + '" target="_blank" rel="noopener">重新打开</a></div>' : ''
    ].join('');
  }

  var actionLabels = {
    generate: '生成草稿',
    polish: '润色文风',
    validate: '校验冲突',
    derive: '拆解推导',
    'fill-field': '补齐字段',
    batch: '批量生成',
    'seed-from-map': '从地图生成',
    'seed-from-old-ui': '从旧 UI 迁移',
    regenerate: '重生一版',
    'accept-draft': '纳入草稿',
    'compare-diff': '比对差异',
    'cite-source': '标注来源',
    'ai-task-response': 'AI 回填草稿',
    'api-generation': 'API 生成草稿',
    'ai-fix-loop': 'AI 核验修复'
  };

  function aiReferencePromptBlock() {
    return (state.aiReferences || []).slice(0, 8).map(function(ref) {
      return '【' + (ref.name || 'reference') + '】\n' + String(ref.text || '').slice(0, 3200);
    }).filter(Boolean).join('\n\n');
  }

  function renderAiReferenceControls() {
    var refs = state.aiReferences || [];
    var rows = refs.slice(0, 8).map(function(ref) {
      return '<div class="ai-reference-row" data-ai-reference-id="' + escapeHtml(ref.id) + '"><div><b>' + escapeHtml(ref.name) + '</b><span>' + escapeHtml((ref.chars || 0) + ' 字 · ' + (ref.updatedAt || '').slice(0, 16).replace('T', ' ')) + '</span></div><button class="mini-ai" data-editor-command="remove-ai-reference" data-ai-reference-id="' + escapeHtml(ref.id) + '">移除</button></div>';
    }).join('');
    return [
      '<div class="ai-reference-list">',
      '<div class="editor-field-meta"><b>本机参考材料</b><span>' + (refs.length ? ('已载入 ' + refs.length + ' 份，会随任务包提交给 API') : '可导入 txt/md/json/csv，不写入剧本正文') + '</span></div>',
      rows || '<p>暂无参考材料。适合放史料摘录、设定纲要、人物小传或旧稿。</p>',
      '<input id="ai-reference-file-input" type="file" accept=".txt,.md,.json,.csv,text/*,application/json" multiple hidden>',
      '<div class="prompt-row"><button class="mini-ai" data-editor-command="select-ai-reference-files">导入参考文件</button><button class="mini-ai" data-editor-command="clear-ai-references">清空参考</button></div>',
      '</div>'
    ].join('');
  }

  function readAiReferenceFile(file) {
    return new Promise(function(resolve, reject) {
      var reader = new FileReader();
      reader.onload = function() {
        resolve({
          id: uniqueId('ai_ref'),
          name: file.name || 'reference.txt',
          text: String(reader.result || '').slice(0, 28000),
          chars: String(reader.result || '').length,
          updatedAt: new Date().toISOString()
        });
      };
      reader.onerror = function() { reject(reader.error || new Error('参考文件读取失败')); };
      reader.readAsText(file, 'utf-8');
    });
  }

  async function importAiReferenceFiles(files) {
    var list = Array.prototype.slice.call(files || []).filter(Boolean);
    if (!list.length) return [];
    var refs = await Promise.all(list.slice(0, 8).map(readAiReferenceFile));
    state.aiReferences = refs.concat(state.aiReferences || []).slice(0, 12);
    writeStoredDraft();
    renderDetailApp();
    setStatus('已导入 AI 参考材料：' + refs.length + ' 份', 'good');
    return clone(refs);
  }

  function removeAiReference(id) {
    var before = (state.aiReferences || []).length;
    state.aiReferences = (state.aiReferences || []).filter(function(ref) { return ref.id !== id; });
    writeStoredDraft();
    renderDetailApp();
    setStatus(before === state.aiReferences.length ? '未找到参考材料。' : '已移除参考材料。', before === state.aiReferences.length ? 'warn' : 'good');
    return clone(state.aiReferences);
  }

  function clearAiReferences() {
    state.aiReferences = [];
    writeStoredDraft();
    renderDetailApp();
    setStatus('AI 参考材料已清空。', 'warn');
    return [];
  }

  function aiFixFieldFromIssue(issue) {
    var text = String(issue && issue.text || issue || '');
    var fieldMatch = text.match(/字段[：:]\s*([A-Za-z0-9_]+)/) || text.match(/field[：:\s]+([A-Za-z0-9_]+)/i);
    if (fieldMatch) return fieldMatch[1];
    if (/characters|人物|角色/.test(text)) return 'characters';
    if (/factions|势力|派系|党派/.test(text)) return 'factions';
    if (/rigidHistoryEvents|硬历史/.test(text)) return 'rigidHistoryEvents';
    if (/events|事件/.test(text)) return 'events';
    if (/timeline|时间线/.test(text)) return 'timeline';
    if (/mapData|map|地图|行政/.test(text)) return isObject(state.scenario.map) ? 'map' : 'mapData';
    if (/officeTree|官制|官职/.test(text)) return 'officeTree';
    if (/variables|变量/.test(text)) return 'variables';
    return state.selectedField || ((findModule(state.selectedModuleId).topLevelKeys || [])[0]) || 'name';
  }

  function pushAiFixIssue(groups, field, text, priority) {
    var key = field || 'name';
    if (!groups[key]) groups[key] = { field: key, issues: [], priority: 0 };
    groups[key].issues.push(String(text || '').slice(0, 420));
    groups[key].priority = Math.max(groups[key].priority, priority || 1);
  }

  function buildAiFixPlan(options) {
    var opts = options || {};
    if (!state.validationRan) validateScenario();
    var groups = {};
    (state.validations || []).forEach(function(issue) {
      pushAiFixIssue(groups, aiFixFieldFromIssue(issue), issue.text, issue.level === 'error' ? 4 : 2);
    });
    collectMissingReferences().slice(0, 24).forEach(function(row) {
      var field = row.kind === 'faction' ? 'factions' : 'characters';
      var source = row.sources && row.sources[0] || {};
      pushAiFixIssue(groups, field, '断裂引用：' + row.ref + ' 被 ' + row.sourceCount + ' 处引用，首个来源 ' + (source.field || '-') + (source.key ? ' / ' + source.key : '') + ' / ' + (source.label || '-'), 3);
    });
    var items = Object.keys(groups).map(function(field) {
      var group = groups[field];
      var module = findModule(inferModuleForField(field));
      return {
        id: uniqueId('ai_fix_item'),
        field: field,
        moduleId: module.id,
        moduleTitle: moduleTitle(module),
        priority: group.priority,
        issues: group.issues.slice(0, 8),
        issueCount: group.issues.length
      };
    }).sort(function(a, b) {
      return b.priority - a.priority || b.issueCount - a.issueCount || a.field.localeCompare(b.field);
    });
    state.aiFixPlan = {
      id: uniqueId('ai_fix_plan'),
      createdAt: new Date().toISOString(),
      issueCount: items.reduce(function(sum, item) { return sum + item.issueCount; }, 0),
      items: items.slice(0, 12)
    };
    renderAiFixPlan();
    writeStoredDraft();
    if (!opts.silent) {
      setStatus(items.length ? ('AI 修复计划已生成：' + items.length + ' 个字段') : '预检没有发现需要 AI 修复的阻断项。', items.length ? 'good' : 'neutral');
    }
    return clone(state.aiFixPlan);
  }

  function buildAiFixPrompt(pkg, item) {
    return pkg.prompt + [
      '',
      '【AI 智能核验自动修复】',
      '请只修复下面列出的跨模块问题，不要发散重写无关字段。',
      '返回值必须仍然是目标字段的新值，或使用 {"value": ...} 包裹。',
      '如果需要补齐人物/势力，请给出可直接进入游戏运行的字段，并保留已有 id/name 引用。',
      '问题清单：',
      item.issues.map(function(text, index) { return (index + 1) + '. ' + text; }).join('\n'),
      '',
      '修复约束：优先保持历史语境、引用名称、数组结构和正式游戏可读取字段；不确定的信息请用“待补”标注，而不是删除引用。'
    ].join('\n');
  }

  function createAiFixJob(item) {
    var pkg = buildAiTaskPackage(item.field, { persist: false });
    pkg.prompt = buildAiFixPrompt(pkg, item);
    pkg.fixPlanItemId = item.id;
    pkg.fixIssues = item.issues.slice(0, 8);
    return createAiJob(item.field, { package: pkg, action: 'ai-fix-loop' });
  }

  function queueAiFixLoop() {
    var plan = state.aiFixPlan && Array.isArray(state.aiFixPlan.items) ? state.aiFixPlan : buildAiFixPlan({ silent: true });
    var activeKeys = (state.aiJobs || []).filter(function(job) {
      return job.action === 'ai-fix-loop' && (job.status === 'queued' || job.status === 'running');
    }).map(function(job) { return job.field; });
    var jobs = (plan.items || []).filter(function(item) {
      return activeKeys.indexOf(item.field) < 0;
    }).map(createAiFixJob);
    if (!jobs.length) {
      setStatus((plan.items || []).length ? 'AI 修复任务已在队列中。' : '没有需要入队的 AI 修复项。', 'warn');
      renderAiFixPlan();
      return [];
    }
    state.aiJobs = state.aiJobs.concat(jobs).slice(-40);
    renderQueue();
    renderAiFixPlan();
    writeStoredDraft();
    setStatus('AI 修复任务已入队：' + jobs.length + ' 项', 'good');
    return jobs;
  }

  async function runAiFixLoop() {
    var jobs = queueAiFixLoop();
    if (!jobs.length) return [];
    return runAiQueue();
  }

  function renderAiFixPlanHtml() {
    var plan = state.aiFixPlan;
    if (!plan || !Array.isArray(plan.items) || !plan.items.length) {
      return '<div id="ai-fix-plan-list"><p>尚未生成 AI 修复计划。运行预检后可把错误、提醒和断裂引用转成 API 修复队列。</p></div>';
    }
    var rows = plan.items.slice(0, 8).map(function(item) {
      return '<div class="ai-fix-row" data-ai-fix-field="' + escapeHtml(item.field) + '"><div><b>' + escapeHtml(item.field) + '</b><span>' + escapeHtml(item.moduleTitle + ' · ' + item.issueCount + ' 项 · 优先级 ' + item.priority) + '</span></div><em>' + escapeHtml(item.issues[0] || '') + '</em></div>';
    }).join('');
    return '<div id="ai-fix-plan-list"><div class="preflight-summary" data-level="warn"><strong>AI 修复计划</strong><span>' + plan.items.length + ' 个字段 · ' + plan.issueCount + ' 项问题 · 草稿仍需人工纳入</span></div>' + rows + '</div>';
  }

  function renderAiFixPlan() {
    var box = document.getElementById('ai-fix-plan-list');
    if (!box) return;
    var holder = document.createElement('div');
    holder.innerHTML = renderAiFixPlanHtml();
    var next = holder.firstElementChild;
    if (next) box.replaceWith(next);
  }

  // Per-tradition prompt context. 天启 v48 leans on Ming-late vocabulary
  // and the flat-by-faction adminHierarchy; 绍宋 v1.6-D leans on Song
  // post-Jingkang vocabulary and the kinded variables/recursive admin tree.
  // Surfacing the tradition keeps AI generations on-schema and stylistically
  // consistent with whichever scenario the creator is editing.
  var SCENARIO_TRADITION_HINTS = {
    tianqi: '剧本传统：天启七年（v48 旧 schema）·明末晚明·朝代「明」·variables 用扁平数组·globalRules 用一段长文·rigidTriggers 用 key→object·adminHierarchy 用 23 派系容器扁平结构·语境偏向「党争·阉祸·辽东边事·江南税赋」。生成时优先使用此风格用词，并保持上述数据形态。',
    shaosong: '剧本传统：绍宋·建炎元年（v1.6-D 新 schema）·南渡草创·朝代「宋」·variables 用 {base,other,formulas} 分组对象·globalRules 用字符串数组（每条独立规则）·rigidTriggers / timeline 用数组·adminHierarchy 用单派系递归 children 树·语境偏向「靖康余孽·三派分立·南渡定都·中兴未竟」。生成时优先使用此风格用词，并保持上述数据形态。',
    mixed: '剧本传统：混合（同时检测到天启 + 绍宋 词表）。请保留两套词表共存，不要强行归一；生成新内容时优先继承现有键的命名风格。',
    unknown: '剧本传统：自定义/无法确定。请根据已有字段推断风格，保持现有字段命名与数据形态。'
  };

  function detectScenarioTradition(scenario) {
    if (!isObject(scenario)) return 'unknown';
    var id = String(scenario.id || '');
    var version = String(scenario._version || '');
    var dynasty = String(scenario.dynasty || '');
    var tianqiSignals = 0;
    var shaosongSignals = 0;
    if (id.indexOf('tianqi') >= 0) tianqiSignals += 3;
    if (id.indexOf('shaosong') >= 0 || id.indexOf('jianyan') >= 0) shaosongSignals += 3;
    if (/^v4[0-9]/.test(version)) tianqiSignals += 2; // v40-49 = TQ era
    if (/^v1\.[0-9]/.test(version)) shaosongSignals += 2;
    if (dynasty === '明') tianqiSignals += 1;
    if (dynasty === '宋') shaosongSignals += 1;
    if (Array.isArray(scenario.variables)) tianqiSignals += 1;
    if (isObject(scenario.variables) && !Array.isArray(scenario.variables)) shaosongSignals += 1;
    if (typeof scenario.globalRules === 'string') tianqiSignals += 1;
    if (Array.isArray(scenario.globalRules)) shaosongSignals += 1;
    var era = isObject(scenario.eraState) ? detectEraStateOrigin(scenario.eraState) : 'empty';
    if (era === 'tianqi') tianqiSignals += 2;
    if (era === 'shaosong') shaosongSignals += 2;
    if (era === 'mixed') return 'mixed';
    if (tianqiSignals === 0 && shaosongSignals === 0) return 'unknown';
    if (tianqiSignals > 0 && shaosongSignals > 0 && Math.abs(tianqiSignals - shaosongSignals) < 2) return 'mixed';
    return tianqiSignals > shaosongSignals ? 'tianqi' : 'shaosong';
  }

  function scenarioTraditionHint(scenario) {
    var tradition = detectScenarioTradition(scenario);
    return { tradition: tradition, text: SCENARIO_TRADITION_HINTS[tradition] || SCENARIO_TRADITION_HINTS.unknown };
  }

  // Slice 91 · action-aware prompt suffix. Each AI button (生成 / 润色 /
  // 校验 / 拆解 / 批量 …) feeds the same buildAiTaskPackage today, so the
  // AI doesn't know which mode it's in. This lookup gives one Chinese
  // instruction line per action; injected into the prompt as "当前操作：N
  // — …" right after the module strategy block.
  var AI_ACTION_INSTRUCTIONS = {
    'generate': '生成草案 — 在不破坏现有字段结构的前提下，输出一份完整、可直接纳入草稿审阅的新值。',
    'polish': '润色文风 — 仅调整语言、修辞、节奏；不可更改事实、人物、数值或结构。',
    'validate': '校验冲突 — 不写入新值，列出与当前剧本不一致、与历史不符、或与运行时契约冲突的问题清单。',
    'derive': '拆解推导 — 把一段长文本或一组数据拆成更细的子条目，保留原意并补齐缺口字段。',
    'batch': '批量生成 — 一次生成多个同类条目（人物/势力/事件等），每条目独立、可直接入库，不要互相重复。',
    'fill-field': '补字段 — 仅围绕目标字段补值，不动其它字段；若该字段是数组，只追加 / 完善，不替换全部条目。',
    'regenerate': '重生一版 — 完全推翻上一版草稿，从头给出风格 / 立意都不同的另一种写法。',
    'compare-diff': '比对差异 — 输出差异要点，不要输出新值；只标记哪些字段会被覆盖、哪些是新增。',
    'cite-source': '标注来源 — 为当前字段或草稿，挑选最相关的 2-3 段参考材料，列出引用片段 + 影响位置。',
    'seed-from-map': '从地图反推 — 基于现有 mapData 地块，推导合理的行政区划绑定、势力归属和治所建议。',
    'seed-from-old-ui': '从旧 UI 迁移 — 把旧编辑器某个标签页的字段映射到新版蓝图，给出补齐草稿。',
    'accept-draft': '纳入草稿 — 不生成新内容；只确认草稿可以入库，输出空对象 {}。',
    'compare-draft': '比对草稿 — 输出当前草稿对剧本各字段的修改差异，不写入新值。'
  };

  // Slice 92 · default system prompt. Pulled out of the inline promptLines
  // so downstream API code can pass it as the proper system role and so
  // creators can override it via tm.scenarioEditorReset.aiSystemPrompt.v1.
  var DEFAULT_AI_SYSTEM_PROMPT = '你是《天命》剧本编辑器的协作作者。\n严格遵守：\n1. 输出只包含合法 JSON，不要 Markdown、不要解释、不要前后引导词。\n2. 保持字段名 / 字段类型 / 数组顺序与现有剧本一致。\n3. 中文叙述使用与朝代相符的语体，不要现代用语和网络流行词。\n4. 涉及正史人物时，字号 / 生卒年 / 谥号 / 官位顺序 / 主要事迹必须与正史一致；自创人物在 desc 字段明确标注虚构。\n5. 当用户提供「参考材料」时，优先从材料中取证；冲突时以材料为准而不是训练记忆。';

  // Slice 89 · per-module AI strategy hint. Different modules have different
  // generation disciplines and the AI needs to know the constraint set for
  // each. Single short line so it stays cheap in tokens.
  var MODULE_AI_STRATEGY = {
    scenarioOpening: '开局类内容应锁定朝代、年号、皇帝、玩家身份；开场信用第一/第三人称依据场景；任何叙述必须能被运行时直接读取。',
    peopleLineages: '人物条目保持字号、生卒年、谥号与正史一致；自创人物标注虚构；家族节点要标父子/师徒关系；aiPersonaText 用 60-180 字。',
    factionsSociety: '势力档案附继承机制、AI 行为边界、外交倾向；势力关系矩阵需双向闭合；党派/阶层要标定影响系数。',
    courtInstitutions: '官制树用既有职官名；变量初值符合朝代财政基线；keju/postSystem 流程要可分阶段；内廷要含礼制约束。',
    adminMap: '新建区划必须落到既有 mapData 地块上；省/府/县父子之和不可超过父级；侨置/改革需带年份触发。',
    economyPopulation: '财赋/人口数字基于正史；环境系统含天气、灾害；文化系统含科举余荫与工程进度。',
    militaryFrontier: '军队条目要带驻地、兵种、装备；边防态势含游牧/朝贡邻邦；战斗规则要可由 mechanicsConfig 启停。',
    eventsChronicle: '事件必含触发条件 + 影响字段 + 可逆转判定；硬历史锁仅用于正史已发生事件；时间线按月份对齐。',
    rulesAi: '规则项要可被引擎读取；提示词不写敏感内容；modelRequirements 给出最低能力门槛。'
  };

  // Slice 87 · AI prompt template starters. Creators can pick a starter
  // from a dropdown rather than typing freeform from scratch. Each entry
  // gives a thematic Chinese kickoff that goes into #global-ai-prompt and
  // then layers over per-field dispatch via sessionPrompt (Slice 86).
  var AI_PROMPT_TEMPLATES = [
    { id: '', label: '— 选择一个起点 —', body: '' },
    { id: 'late-ming', label: '保持晚明史实风格', body: '基调：晚明天启七年，宦官当国、辽事危急、东林清议；风格冷峻克制、内含党争伏笔。所有人物以正史为底，对话不能用现代用语。' },
    { id: 'liaodong', label: '为辽东军政补人物 / 势力档案', body: '聚焦辽东军政：补齐辽东巡抚、总兵、参将；后金势力档案需含八旗结构 + 继承危机；同时给出明清前线的外交倾向与战事预备。' },
    { id: 'song-southern', label: '保持南宋绍兴-绍宋衍流', body: '基调：建炎/绍兴间南渡，宗室南奔、张邦昌伪楚刚倒、金军压境；语言典雅近《宋史》《建炎以来系年要录》；不可改变史实事件的发生顺序。' },
    { id: 'faction-matrix', label: '推导势力外交矩阵', body: '基于当前 factions 列表，推导 factionRelations 矩阵：每对势力给出 -100..+100 倾向值 + 一句话理由 + 可能的触发事件。结果保持双向闭合。' },
    { id: 'opening-letters', label: '扩写开场信 3 段', body: '为当前剧本生成 3 封开场信：1 封来自玩家上级 / 1 封来自盟友 / 1 封来自对立势力；每封 120-200 字，含具体地名、人物、矛盾点。' },
    { id: 'timeline-audit', label: '校验时间线一致性', body: '审查所有 events / rigidHistoryEvents / timeline：找出与 startYear/startMonth 冲突的条目、与人物生卒年冲突的角色、缺失触发条件或后果字段的事件。只返回问题清单，不改写数据。' },
    { id: 'npc-policy', label: '为势力生成 NPC 行为边界', body: '为每个势力生成 aiBehaviorPolicy：禁止做的事 / 必须做的事 / 受刺激时的反应阶梯 / 内部派系分歧。基调要符合该势力的历史形象。' },
    { id: 'admin-binding', label: '从地图反推行政区划', body: '读取 mapData 现有地块，反推合理的 adminHierarchy：省/府/县三级 + 治所地块 + 主要城市；游牧势力另用部族-牙帐结构而非府县。' },
    { id: 'event-chain', label: '把当前史料拆事件链', body: '把 aiReferences 里粘贴的史料段落拆成可触发事件：每事件含 trigger / preconditions / effects / 可逆转判定 / 史官记录词条。时间按月对齐。' }
  ];

  function buildAiTaskPackage(field, options) {
    var opts = options || {};
    var targetField = field || state.selectedField || (findModule(state.selectedModuleId).topLevelKeys || [])[0] || 'name';
    var value = Object.prototype.hasOwnProperty.call(state.scenario || {}, targetField) ? state.scenario[targetField] : inferMissingFieldTemplate(targetField);
    var module = findModule(inferModuleForField(targetField));
    var entity = Array.isArray(value) ? value[state.selectedEntityIndex] : (isObject(value) ? value : null);
    var note = currentFieldNote(targetField);
    var schema = entity && isObject(entity) ? specialistSchema(targetField, entity) : [];
    var referenceBlock = aiReferencePromptBlock();
    var traditionInfo = scenarioTraditionHint(state.scenario);
    // Slice 91 · which AI button (or call site) triggered this build. Used
    // to inject the action-specific instruction and surfaced on the package
    // for downstream renderers / audit log entries.
    var action = opts.action || (opts.trigger && opts.trigger.dataset && opts.trigger.dataset.aiAction) || 'generate';
    var actionInstruction = AI_ACTION_INSTRUCTIONS[action] || '';
    // Slice 92 · system prompt (default + creator override) is now built
    // as a distinct string so callAiChatCompletion can pass it as the
    // system role rather than concatenating with the user prompt.
    var systemPrompt = (state.aiSystemPromptOverride && state.aiSystemPromptOverride.trim()) || DEFAULT_AI_SYSTEM_PROMPT;
    var responseShape = Array.isArray(value)
      ? (entity && isObject(entity) ? schema.reduce(function(acc, key) { acc[key] = entity[key] == null ? '' : entity[key]; return acc; }, {}) : { name: '新条目', desc: '说明' })
      : value;
    // Slice 86 · creator's global session prompt (typed into #global-ai-prompt
    // in the AI 共创案台) now layers over every per-field AI dispatch as an
    // "本次会话总指令" block. Persists to state.globalAiPrompt so re-renders
    // don't blow it away.
    var sessionPrompt = (state.globalAiPrompt || '').trim();
    // Slice 89 · module-aware strategy hint. Each module has its own
    // generation discipline ("characters must keep 字号/生卒年 consistent",
    // "events must include 触发条件 + 影响字段", etc.). Inject as a
    // dedicated "模块策略" line so the AI knows what to weight for this
    // particular section.
    var moduleStrategy = MODULE_AI_STRATEGY[module && module.id] || '';
    // Slice 92 · the user-role prompt no longer carries the long system
    // preamble; that lives in `systemPrompt` above and is passed to the
    // API in its own role. The user prompt is purely task context + data.
    var userPromptLines = [
      traditionInfo.text,
      sessionPrompt ? ('本次会话总指令（创作者填写）：' + sessionPrompt) : '',
      '目标模块：' + moduleTitle(module),
      moduleStrategy ? ('模块策略：' + moduleStrategy) : '',
      actionInstruction ? ('当前操作：' + (actionLabels[action] || action) + ' — ' + actionInstruction) : '',
      '目标字段：' + targetField + '（' + fieldType(value) + ' · ' + fieldCount(value) + '）',
      Array.isArray(value) ? ('当前选中实体序号：' + state.selectedEntityIndex + '；若要改写该实体，请返回单个对象；若要重写整个字段，请返回数组。') : '请返回该字段的新值。',
      schema.length ? ('常用字段：' + schema.join(', ')) : '',
      note && note.text ? ('制作札记：' + note.text) : '',
      referenceBlock ? ('参考材料（来自本机，不写入剧本正文）：\n' + referenceBlock) : '',
      '当前值或选中实体：',
      pretty(entity || value).slice(0, 9000),
      '建议返回形状示例：',
      pretty(responseShape).slice(0, 2600)
    ].filter(Boolean).join('\n\n');
    // Keep the legacy `prompt` field as system + user concatenated so any
    // downstream code that still reads pkg.prompt sees the full instruction
    // set. The split fields are authoritative for API dispatch.
    var promptLines = systemPrompt + '\n\n' + userPromptLines;
    var pkg = {
      id: uniqueId('ai_task'),
      field: targetField,
      moduleId: module.id,
      moduleTitle: moduleTitle(module),
      fieldType: fieldType(value),
      fieldCount: fieldCount(value),
      selectedEntityIndex: Array.isArray(value) ? state.selectedEntityIndex : -1,
      schema: schema,
      note: note && note.text || '',
      tradition: traditionInfo.tradition,
      sessionPrompt: sessionPrompt,
      moduleStrategy: moduleStrategy,
      action: action,
      actionInstruction: actionInstruction,
      references: (state.aiReferences || []).slice(0, 8).map(function(ref) { return { id: ref.id, name: ref.name, chars: ref.chars || 0 }; }),
      systemPrompt: systemPrompt,
      userPrompt: userPromptLines,
      prompt: promptLines,
      createdAt: new Date().toISOString()
    };
    if (opts.persist !== false) state.aiTaskPackage = pkg;
    return pkg;
  }

  function jsonCandidateFromText(text) {
    var trimmed = String(text == null ? '' : text).trim();
    var fenced = trimmed.match(/^```(?:json|javascript|js)?\s*([\s\S]*?)\s*```$/i);
    if (fenced) return fenced[1].trim();
    var firstObject = trimmed.indexOf('{');
    var lastObject = trimmed.lastIndexOf('}');
    var firstArray = trimmed.indexOf('[');
    var lastArray = trimmed.lastIndexOf(']');
    if (firstObject >= 0 && lastObject > firstObject && (firstArray < 0 || firstObject < firstArray)) return trimmed.slice(firstObject, lastObject + 1);
    if (firstArray >= 0 && lastArray > firstArray) return trimmed.slice(firstArray, lastArray + 1);
    return trimmed;
  }

  function normalizeAiTaskResponse(raw, field) {
    var text = String(raw == null ? '' : raw).trim();
    if (!text) throw new Error('AI 回填为空');
    var parsed = JSON.parse(jsonCandidateFromText(text));
    if (parsed && isObject(parsed) && Object.prototype.hasOwnProperty.call(parsed, 'value')) return parsed.value;
    if (parsed && isObject(parsed) && field && Object.prototype.hasOwnProperty.call(parsed, field)) return parsed[field];
    if (parsed && isObject(parsed) && parsed.field && Object.prototype.hasOwnProperty.call(parsed, parsed.field)) return parsed[parsed.field];
    return parsed;
  }

  function extractTextContent(content) {
    if (typeof content === 'string') return content;
    if (!Array.isArray(content)) return '';
    return content.map(function(part) {
      if (typeof part === 'string') return part;
      if (!part || typeof part !== 'object') return '';
      return part.text || part.output_text || '';
    }).filter(Boolean).join('\n');
  }

  function extractAiMessageContent(payload) {
    if (typeof payload === 'string') return payload;
    if (!payload || typeof payload !== 'object') return '';
    if (typeof payload.output_text === 'string') return payload.output_text;
    if (Array.isArray(payload.choices) && payload.choices.length) {
      var choice = payload.choices[0] || {};
      if (choice.message) {
        var messageText = extractTextContent(choice.message.content);
        if (messageText) return messageText;
      }
      if (typeof choice.text === 'string') return choice.text;
    }
    if (Array.isArray(payload.output)) {
      var pieces = [];
      payload.output.forEach(function(item) {
        if (!item || typeof item !== 'object') return;
        if (typeof item.content === 'string') pieces.push(item.content);
        if (Array.isArray(item.content)) {
          item.content.forEach(function(part) {
            var text = extractTextContent(part && part.content);
            if (text) pieces.push(text);
            else if (part && (part.text || part.output_text)) pieces.push(part.text || part.output_text);
          });
        }
      });
      if (pieces.length) return pieces.join('\n');
    }
    if (Object.prototype.hasOwnProperty.call(payload, 'value')) return JSON.stringify(payload);
    return '';
  }

  function buildAiRequestPayload(pkg, settings) {
    var normalized = normalizeApiSettings(settings || state.apiSettings || readApiSettings());
    // Slice 92 · prefer the split system / user prompt fields when present
    // (newer packages from buildAiTaskPackage). Fall back to the legacy
    // combined `pkg.prompt` if an older package shape arrives so we don't
    // break API dispatch for any code path that still hand-builds a pkg.
    var systemText = pkg.systemPrompt || '你是《天命》剧本编辑器的协作作者。只返回可被 JSON.parse 解析的 JSON，不要 Markdown，不要解释。';
    var userText = (pkg.userPrompt || pkg.prompt) + '\n\n输出要求：返回目标字段的新值；如果需要包装，请使用 {"value": ...}。';
    if (/\/responses(?:\?|$)/.test(normalized.main.url || '')) {
      return {
        model: normalized.main.model || 'gpt-4o',
        temperature: 0.4,
        input: [
          { role: 'system', content: systemText },
          { role: 'user', content: userText }
        ]
      };
    }
    return {
      model: normalized.main.model || 'gpt-4o',
      temperature: 0.4,
      messages: [
        { role: 'system', content: systemText },
        { role: 'user', content: userText }
      ]
    };
  }

  function createAiJob(field, options) {
    var opts = options || {};
    var pkg = opts.package || buildAiTaskPackage(field || state.selectedField, { persist: false });
    if (opts.prompt) pkg.prompt = opts.prompt;
    return {
      id: uniqueId('ai_job'),
      field: pkg.field,
      moduleId: pkg.moduleId,
      moduleTitle: pkg.moduleTitle,
      action: opts.action || 'api-generation',
      package: pkg,
      status: 'queued',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      error: '',
      draftId: '',
      responsePreview: ''
    };
  }

  function enqueueAiTask(field, options) {
    var job = createAiJob(field, options);
    state.aiJobs.push(job);
    state.aiJobs = state.aiJobs.slice(-40);
    renderQueue();
    writeStoredDraft();
    setStatus('AI 任务已入队：' + job.field, 'good');
    return job;
  }

  function queueModuleAiTasks(moduleId) {
    return queueModuleAiTasksFiltered(moduleId, 'all');
  }

  // Cross-module combo: queue every missing field across every module and
  // (optionally) immediately run the queue. Wraps two existing primitives so
  // the most common "make my scenario complete" workflow is a single click.
  async function aiFillAllMissing(options) {
    var opts = options || {};
    var modules = state.modules || [];
    if (!modules.length) {
      setStatus('当前没有可处理的模块。', 'warn');
      return { queued: 0, modules: 0, drafts: [] };
    }
    var queuedTotal = 0;
    var perModule = [];
    modules.forEach(function(mod) {
      var jobs = queueModuleAiTasksFiltered(mod.id, 'missing');
      queuedTotal += jobs.length;
      if (jobs.length) perModule.push({ moduleId: mod.id, count: jobs.length });
    });
    if (!queuedTotal) {
      setStatus('所有模块的字段都已填齐，没有缺失字段可补。', 'good');
      return { queued: 0, modules: 0, drafts: [] };
    }
    setStatus('已批量入队 ' + queuedTotal + ' 个缺失字段（涉及 ' + perModule.length + ' 个模块）' + (opts.run ? '·正在运行' : '·尚未运行'), 'good');
    pushStatusLog('AI 补齐缺失：' + queuedTotal + ' 项入队 / ' + perModule.length + ' 模块', 'good');
    if (!opts.run) return { queued: queuedTotal, modules: perModule.length, drafts: [] };
    var drafts = await runAiQueue();
    return { queued: queuedTotal, modules: perModule.length, drafts: drafts };
  }

  // Granular variant: queue only the subset of a module's fields matching
  // the given filter. 'missing' = fields the scenario lacks; 'present' =
  // fields it already has (for re-polishing); 'watched' = the creator's
  // pinned watch-list intersected with this module; 'all' = the original
  // behaviour. De-dupes against already-queued / running jobs.
  function queueModuleAiTasksFiltered(moduleId, filterId) {
    var module = findModule(moduleId || state.selectedModuleId);
    var activeFields = (state.aiJobs || []).filter(function(job) {
      return job.status === 'queued' || job.status === 'running';
    }).map(function(job) { return job.field; });
    var allFields = module.topLevelKeys || [];
    var fields;
    var filterLabel;
    if (filterId === 'missing') {
      fields = allFields.filter(function(f) { return !(f in state.scenario); });
      filterLabel = '缺失字段';
    } else if (filterId === 'present') {
      fields = allFields.filter(function(f) { return f in state.scenario; });
      filterLabel = '已有字段（再润色）';
    } else if (filterId === 'watched') {
      var watch = ensureWatchList();
      fields = allFields.filter(function(f) { return watch.indexOf(f) >= 0; });
      filterLabel = '关注字段';
    } else {
      fields = allFields.slice();
      filterLabel = '全部字段';
    }
    fields = fields.filter(function(field) {
      return field && activeFields.indexOf(field) < 0;
    });
    if (!fields.length) {
      setStatus('当前模块「' + filterLabel + '」下没有新的 AI 任务可入队。', 'warn');
      return [];
    }
    var jobs = fields.map(function(field) {
      return createAiJob(field, { action: 'api-generation' });
    });
    state.aiJobs = state.aiJobs.concat(jobs).slice(-40);
    renderQueue();
    writeStoredDraft();
    setStatus('已加入模块 AI 队列：' + moduleTitle(module) + ' · ' + filterLabel + ' · ' + jobs.length + ' 项', 'good');
    return jobs;
  }

  async function callAiChatCompletion(pkg, settings) {
    var normalized = normalizeApiSettings(settings || state.apiSettings || readApiSettings());
    if (!normalized.main.key) throw new Error('请先在 API 设置中保存主 API Key');
    if (!global.fetch) throw new Error('当前浏览器不支持 fetch，无法调用 API');
    var response = await global.fetch(normalized.main.url || 'https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: 'Bearer ' + normalized.main.key
      },
      body: JSON.stringify(buildAiRequestPayload(pkg, normalized))
    });
    var text = await response.text();
    if (!response.ok) throw new Error('API ' + response.status + '：' + text.slice(0, 240));
    var payload = text ? JSON.parse(text) : {};
    var content = extractAiMessageContent(payload);
    if (!content) throw new Error('API 返回中没有可读取的文本内容');
    return { payload: payload, content: content };
  }

  // AI call log ring buffer. Captures every API roundtrip so creators can
  // audit token-equivalent traffic, find slow calls, and trace failures.
  // Bounded so a long session doesn't bloat memory or localStorage drafts.
  var AI_CALL_LOG_CAPACITY = 40;

  function pushAiCallEntry(entry) {
    if (!state.aiCallLog) state.aiCallLog = [];
    state.aiCallLog.unshift(entry);
    if (state.aiCallLog.length > AI_CALL_LOG_CAPACITY) state.aiCallLog.length = AI_CALL_LOG_CAPACITY;
    renderAiCallLog();
  }

  function clearAiCallLog() {
    state.aiCallLog = [];
    renderAiCallLog();
    setStatus('AI 调用日志已清空', 'neutral');
  }

  function renderAiCallLog() {
    var mount = document.querySelector('[data-panel="ai-call-log"]');
    if (!mount) return;
    var entries = state.aiCallLog || [];
    var head = '<h3>AI 调用日志 <small>' + entries.length + ' / ' + AI_CALL_LOG_CAPACITY + '</small></h3>' +
      '<div class="ai-call-log-toolbar"><button class="mini-ai" data-editor-command="clear-ai-call-log">清空日志</button>' +
      '<span class="ai-call-log-hint">记录每次 API 调用：字段、动作、请求/响应字符数、耗时、状态。</span></div>';
    var listHtml = entries.length
      ? '<div class="ai-call-log-list">' + entries.map(function(entry) {
          var time = '';
          try { time = new Date(entry.at).toLocaleTimeString(); } catch (_) { time = entry.at; }
          var meta = [
            entry.action || '',
            entry.requestChars != null ? '请求 ' + entry.requestChars + ' 字符' : '',
            entry.responseChars != null ? '响应 ' + entry.responseChars + ' 字符' : '',
            entry.durationMs != null ? entry.durationMs + ' ms' : ''
          ].filter(Boolean).join(' · ');
          return '<div class="ai-call-log-entry" data-ai-call-status="' + escapeHtml(entry.status || 'pending') + '">' +
            '<span class="ai-call-log-time">' + escapeHtml(time) + '</span>' +
            '<span class="ai-call-log-field"><strong>' + escapeHtml(entry.field || '') + '</strong>' +
              (entry.error ? '<small>' + escapeHtml(entry.error) + '</small>' : '<small>' + escapeHtml(meta) + '</small>') +
            '</span>' +
            '<span class="ai-call-log-status">' + escapeHtml(entry.status || 'pending') + '</span>' +
          '</div>';
        }).join('') + '</div>'
      : '<div class="empty-state-card" data-empty-state="ai-call-log"><span class="empty-state-glyph" aria-hidden="true">问</span><div><b>暂无 AI 调用记录</b><span>运行任意 AI 任务后，这里会按时间倒序记录耗时、调用方、命中状态。</span></div></div>';
    mount.innerHTML = head + listHtml;
  }

  async function runAiJob(job) {
    if (!job) return null;
    job.status = 'running';
    job.updatedAt = new Date().toISOString();
    job.error = '';
    renderQueue();
    setStatus('正在调用 AI API：' + job.field, 'neutral');
    var startedAt = Date.now();
    var requestChars = job.package && job.package.prompt ? String(job.package.prompt).length : 0;
    try {
      var result = await callAiChatCompletion(job.package, state.apiSettings);
      var draft = applyAiTaskResponse(result.content, { package: job.package, field: job.field, source: 'api-generation', action: job.action || 'api-generation' });
      job.status = 'draft';
      job.draftId = draft.id;
      job.responsePreview = String(result.content || '').slice(0, 1200);
      job.updatedAt = new Date().toISOString();
      pushAiCallEntry({
        at: new Date().toISOString(),
        field: job.field,
        action: job.action || 'api-generation',
        status: 'draft',
        requestChars: requestChars,
        responseChars: String(result.content || '').length,
        durationMs: Date.now() - startedAt,
        draftId: draft.id
      });
      renderQueue();
      writeStoredDraft();
      setStatus('AI API 已生成待审草稿：' + job.field, 'good');
      return draft;
    } catch (err) {
      job.status = 'error';
      job.error = err && err.message || String(err);
      job.updatedAt = new Date().toISOString();
      pushAiCallEntry({
        at: new Date().toISOString(),
        field: job.field,
        action: job.action || 'api-generation',
        status: 'error',
        requestChars: requestChars,
        responseChars: 0,
        durationMs: Date.now() - startedAt,
        error: job.error
      });
      renderQueue();
      writeStoredDraft();
      setStatus('AI API 生成失败：' + job.error, 'error');
      throw err;
    }
  }

  async function runAiTaskPackage(field) {
    var promptInput = document.getElementById('ai-task-prompt');
    var job = enqueueAiTask(field || state.selectedField, { action: 'api-generation', prompt: promptInput ? promptInput.value : '' });
    return runAiJob(job);
  }

  async function runAiQueue() {
    var jobs = (state.aiJobs || []).filter(function(job) { return job.status === 'queued'; });
    if (!jobs.length) {
      setStatus('AI 队列为空，先加入当前字段或当前模块。', 'warn');
      return [];
    }
    var drafts = [];
    for (var i = 0; i < jobs.length; i += 1) {
      try {
        var draft = await runAiJob(jobs[i]);
        if (draft) drafts.push(draft);
      } catch (_) {
        // Keep running later queued jobs so one bad response does not block the whole module.
      }
    }
    setStatus('AI 队列运行完成：生成 ' + drafts.length + ' 个待审草稿', drafts.length ? 'good' : 'warn');
    return drafts;
  }

  function clearAiQueue() {
    state.aiJobs = [];
    renderQueue();
    writeStoredDraft();
    setStatus('AI API 任务队列已清空，待审草稿保留。', 'warn');
    return [];
  }

  function applyAiTaskResponse(raw, options) {
    var opts = options || {};
    var pkg = opts.package || state.aiTaskPackage || buildAiTaskPackage(state.selectedField);
    var field = opts.field || pkg.field || state.selectedField;
    var value = normalizeAiTaskResponse(raw, field);
    var current = state.scenario[field];
    var draft = {
      id: uniqueId('draft'),
      action: 'ai-task-response',
      field: field,
      value: value,
      targetIndex: Array.isArray(current) && isObject(value) && !Array.isArray(value) ? (Number.isFinite(pkg.selectedEntityIndex) ? pkg.selectedEntityIndex : state.selectedEntityIndex) : -1,
      createdAt: new Date().toISOString(),
      status: 'review-required',
      source: opts.source || 'ai-task-package'
    };
    if (opts.action) draft.action = opts.action;
    state.drafts.unshift(draft);
    state.drafts = state.drafts.slice(0, 40);
    renderDraft(draft, { source: draft.source });
    renderQueue();
    writeStoredDraft();
    setStatus('AI 回填已进入草稿：' + field, 'good');
    return draft;
  }

  function copyAiTaskPackage() {
    var pkg = state.aiTaskPackage || buildAiTaskPackage(state.selectedField);
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(pkg.prompt).then(function() {
        setStatus('AI 任务包已复制', 'good');
      }).catch(function() {
        setStatus('复制失败，请手动复制任务包', 'warn');
      });
    } else {
      setStatus('当前环境不支持剪贴板，请手动复制任务包', 'warn');
    }
    return pkg.prompt;
  }

  function buildDraftValue(field, action) {
    var current = state.scenario[field];
    var stamp = new Date().toLocaleString('zh-CN', { hour12: false });
    if (Array.isArray(current)) return { id: field + '_ai_' + Date.now().toString(36), name: 'AI 新条目草稿', desc: '由“' + (actionLabels[action] || action) + '”生成，时间：' + stamp, source: 'scenario-editor-reset-preview' };
    if (isObject(current)) {
      var nextObject = clone(current);
      nextObject._aiDraftNote = 'AI 草稿补充：请人工审阅后保留或删改。' + stamp;
      return nextObject;
    }
    if (typeof current === 'number' || typeof current === 'boolean') return current;
    return (current ? String(current) + '\n\n' : '') + '【AI 草稿】围绕当前模块补充一段可编辑内容；建议先核对史实、人物关系与规则影响。生成时间：' + stamp;
  }

  function simulateAiDraft(trigger) {
    var triggerAction = typeof trigger === 'string' ? trigger : null;
    var triggerDataset = trigger && trigger.dataset ? trigger.dataset : {};
    var action = triggerAction || triggerDataset.aiAction || 'generate';
    if (action === 'validate') validateScenario();
    var module = findModule(state.selectedModuleId);
    var field = triggerDataset.fieldAi || state.selectedField || (module.topLevelKeys || [])[0];
    var draft = { id: 'draft_' + Date.now().toString(36), action: action, field: field, value: buildDraftValue(field, action), createdAt: new Date().toISOString(), status: 'review-required' };
    state.drafts.unshift(draft);
    state.drafts = state.drafts.slice(0, 40);
    renderDraft(draft);
    renderQueue();
    writeStoredDraft();
    setStatus('已生成草稿：' + field, 'good');
    return draft;
  }

  function rejectDraft(id) {
    if (!id) return null;
    var idx = state.drafts.findIndex(function(item) { return item.id === id; });
    if (idx < 0) return null;
    var removed = state.drafts.splice(idx, 1)[0];
    writeStoredDraft();
    renderQueue();
    setStatus('已拒绝草稿：' + (removed && removed.field || id), 'warn');
    return removed;
  }

  function acceptAllDrafts(filterField) {
    var pending = state.drafts.filter(function(d) {
      if (d.status && d.status !== 'review-required') return false;
      if (filterField && d.field !== filterField) return false;
      return true;
    });
    if (!pending.length) {
      setStatus('没有可纳入的待审草稿' + (filterField ? '（字段 ' + filterField + '）' : ''), 'warn');
      return 0;
    }
    var accepted = 0;
    pending.forEach(function(draft) {
      try {
        acceptDraft(draft.id);
        accepted += 1;
      } catch (_) {}
    });
    setStatus('已批量纳入 ' + accepted + ' 个草稿' + (filterField ? '（字段 ' + filterField + '）' : ''), 'good');
    return accepted;
  }

  function rejectAllDrafts(filterField) {
    var pending = state.drafts.filter(function(d) {
      if (d.status && d.status !== 'review-required') return false;
      if (filterField && d.field !== filterField) return false;
      return true;
    });
    if (!pending.length) {
      setStatus('没有可拒绝的待审草稿' + (filterField ? '（字段 ' + filterField + '）' : ''), 'warn');
      return 0;
    }
    var rejected = 0;
    pending.forEach(function(draft) {
      var idx = state.drafts.findIndex(function(d) { return d.id === draft.id; });
      if (idx >= 0) {
        state.drafts.splice(idx, 1);
        rejected += 1;
      }
    });
    writeStoredDraft();
    renderQueue();
    setStatus('已批量拒绝 ' + rejected + ' 个草稿' + (filterField ? '（字段 ' + filterField + '）' : ''), 'warn');
    return rejected;
  }

  function acceptDraft(id) {
    var draft = id ? state.drafts.find(function(item) { return item.id === id; }) : state.drafts[0];
    if (!draft) return;
    var current = state.scenario[draft.field];
    if (Array.isArray(current) && typeof draft.targetIndex === 'number' && draft.targetIndex >= 0 && draft.targetIndex < current.length) current[draft.targetIndex] = clone(draft.value);
    else if (Array.isArray(current)) current.push(clone(draft.value));
    else state.scenario[draft.field] = clone(draft.value);
    draft.status = 'accepted';
    state.selectedField = draft.field;
    state.selectedModuleId = inferModuleForField(draft.field);
    if (Array.isArray(current) && typeof draft.targetIndex === 'number' && draft.targetIndex >= 0) state.selectedEntityIndex = draft.targetIndex;
    recordHistory('纳入 AI 草稿', draft.field);
    renderAll();
    renderDraft(draft);
  }

  // Structured draft diff. Returns one of three diff shapes depending on the
  // value types so the UI can render row-level coloring instead of a raw
  // pre-pre pair. Detection cascade: identical → same; string vs string →
  // line diff; object vs object → key diff; array vs array → length+head
  // diff; everything else → JSON pretty comparison row.
  function buildDraftDiff(current, drafted) {
    var stableCur = stableString(current == null ? null : current);
    var stableDraft = stableString(drafted == null ? null : drafted);
    if (stableCur === stableDraft) return { kind: 'identical', rows: [] };
    if (typeof current === 'string' && typeof drafted === 'string') {
      return { kind: 'lines', rows: diffLines(current, drafted) };
    }
    if (isObject(current) && isObject(drafted)) {
      return { kind: 'keys', rows: diffObjectKeys(current, drafted) };
    }
    if (Array.isArray(current) && Array.isArray(drafted)) {
      return { kind: 'array', rows: diffArrayHead(current, drafted) };
    }
    return {
      kind: 'fallback',
      rows: [
        { side: 'current', preview: pretty(current).slice(0, 1600) },
        { side: 'draft', preview: pretty(drafted).slice(0, 1600) }
      ]
    };
  }

  function diffLines(a, b) {
    var aLines = String(a).split(/\r?\n/);
    var bLines = String(b).split(/\r?\n/);
    var bSet = new Set(bLines);
    var aSet = new Set(aLines);
    var rows = [];
    aLines.forEach(function(line) {
      rows.push({ side: bSet.has(line) ? 'same' : 'removed', text: line });
    });
    bLines.forEach(function(line) {
      if (!aSet.has(line)) rows.push({ side: 'added', text: line });
    });
    return rows.slice(0, 200);
  }

  function diffObjectKeys(a, b) {
    var keys = Array.from(new Set(Object.keys(a).concat(Object.keys(b)))).sort();
    return keys.map(function(key) {
      var inA = Object.prototype.hasOwnProperty.call(a, key);
      var inB = Object.prototype.hasOwnProperty.call(b, key);
      if (!inA) return { key: key, status: 'added', before: '', after: pretty(b[key]).slice(0, 200) };
      if (!inB) return { key: key, status: 'removed', before: pretty(a[key]).slice(0, 200), after: '' };
      if (stableString(a[key]) === stableString(b[key])) return { key: key, status: 'same', before: pretty(a[key]).slice(0, 60), after: pretty(b[key]).slice(0, 60) };
      return { key: key, status: 'changed', before: pretty(a[key]).slice(0, 200), after: pretty(b[key]).slice(0, 200) };
    });
  }

  function diffArrayHead(a, b) {
    var rows = [];
    var max = Math.max(a.length, b.length);
    for (var i = 0; i < Math.min(max, 12); i += 1) {
      var hasA = i < a.length;
      var hasB = i < b.length;
      if (!hasA) rows.push({ index: i, status: 'added', before: '', after: pretty(b[i]).slice(0, 160) });
      else if (!hasB) rows.push({ index: i, status: 'removed', before: pretty(a[i]).slice(0, 160), after: '' });
      else if (stableString(a[i]) === stableString(b[i])) rows.push({ index: i, status: 'same', before: pretty(a[i]).slice(0, 60), after: pretty(b[i]).slice(0, 60) });
      else rows.push({ index: i, status: 'changed', before: pretty(a[i]).slice(0, 160), after: pretty(b[i]).slice(0, 160) });
    }
    if (max > 12) rows.push({ index: -1, status: 'truncated', before: '...', after: '后续 ' + (max - 12) + ' 项已省略' });
    return rows;
  }

  function renderDraftDiff(diff) {
    if (diff.kind === 'identical') {
      return '<div class="draft-diff"><p class="draft-diff-empty">草稿与当前值完全相同。</p></div>';
    }
    if (diff.kind === 'lines') {
      var rowsHtml = diff.rows.map(function(row) {
        var sign = row.side === 'added' ? '+' : row.side === 'removed' ? '-' : ' ';
        return '<div class="draft-diff-line" data-draft-diff-side="' + escapeHtml(row.side) + '"><span class="draft-diff-sign">' + sign + '</span><span class="draft-diff-text">' + escapeHtml(row.text) + '</span></div>';
      }).join('');
      return '<div class="draft-diff draft-diff--lines"><h4>文本行级 diff</h4>' + (rowsHtml || '<p>空行集。</p>') + '</div>';
    }
    if (diff.kind === 'keys') {
      var rowsHtmlK = diff.rows.map(function(row) {
        return '<div class="draft-diff-key" data-draft-diff-side="' + escapeHtml(row.status) + '">' +
          '<strong>' + escapeHtml(row.key) + '</strong>' +
          '<span class="draft-diff-status">' + escapeHtml(row.status) + '</span>' +
          '<span class="draft-diff-before">' + escapeHtml(row.before) + '</span>' +
          '<span class="draft-diff-arrow">→</span>' +
          '<span class="draft-diff-after">' + escapeHtml(row.after) + '</span>' +
        '</div>';
      }).join('');
      return '<div class="draft-diff draft-diff--keys"><h4>对象键级 diff</h4>' + rowsHtmlK + '</div>';
    }
    if (diff.kind === 'array') {
      var rowsHtmlA = diff.rows.map(function(row) {
        var idx = row.index === -1 ? '…' : '#' + row.index;
        return '<div class="draft-diff-array-row" data-draft-diff-side="' + escapeHtml(row.status) + '">' +
          '<span class="draft-diff-idx">' + escapeHtml(idx) + '</span>' +
          '<span class="draft-diff-status">' + escapeHtml(row.status) + '</span>' +
          '<span class="draft-diff-before">' + escapeHtml(row.before) + '</span>' +
          '<span class="draft-diff-arrow">→</span>' +
          '<span class="draft-diff-after">' + escapeHtml(row.after) + '</span>' +
        '</div>';
      }).join('');
      return '<div class="draft-diff draft-diff--array"><h4>数组逐项 diff（前 12 项）</h4>' + rowsHtmlA + '</div>';
    }
    // fallback
    return '<div class="draft-diff draft-diff--fallback"><h4>类型变化</h4>' +
      '<div><strong>当前值</strong><pre>' + escapeHtml(diff.rows[0].preview) + '</pre></div>' +
      '<div><strong>草稿值</strong><pre>' + escapeHtml(diff.rows[1].preview) + '</pre></div>' +
    '</div>';
  }

  function compareDraft(id) {
    var draft = id ? state.drafts.find(function(item) { return item.id === id; }) : state.drafts[0];
    if (!draft) return;
    var diff = buildDraftDiff(state.scenario[draft.field], draft.value);
    renderDraft(draft, { extra: renderDraftDiff(diff) });
  }

  function citeDraft(id) {
    var draft = id ? state.drafts.find(function(item) { return item.id === id; }) : state.drafts[0];
    if (!draft) return;
    draft.source = DATA.source || 'official scenario snapshot';
    renderDraft(draft, { source: draft.source });
    writeStoredDraft();
  }

  function renderDraft(draft, options) {
    var preview = document.getElementById('ai-result-preview');
    if (!preview || !draft) return;
    preview.dataset.draftStatus = draft.status || 'review-required';
    preview.dataset.currentDraftId = draft.id;
    var editable = draft.status === 'review-required';
    var editableHtml = editable
      ? '<div class="draft-edit-block">' +
        '<label class="draft-edit-label">草稿值（可编辑后保存再纳入）</label>' +
        '<textarea class="draft-edit-textarea" data-draft-edit-id="' + escapeHtml(draft.id) + '" spellcheck="false">' + escapeHtml(pretty(draft.value)) + '</textarea>' +
        '<div class="prompt-row"><button class="mini-ai" data-editor-command="save-draft-edit" data-draft-id="' + escapeHtml(draft.id) + '">保存草稿编辑</button>' +
        '<button class="mini-ai" data-ai-action="accept-draft" data-draft-id="' + escapeHtml(draft.id) + '">纳入草稿</button></div>' +
      '</div>'
      : '<pre>' + escapeHtml(pretty(draft.value)) + '</pre>';
    preview.innerHTML = [
      '<strong>草稿审阅 · ' + escapeHtml(actionLabels[draft.action] || draft.action) + '</strong>',
      '<p>目标字段：<b>' + escapeHtml(draft.field) + '</b> · 状态：' + escapeHtml(draft.status || 'review-required') + '</p>',
      editableHtml,
      options && options.source ? '<p>来源：' + escapeHtml(options.source) + '</p>' : '',
      options && options.extra ? options.extra : ''
    ].join('');
  }

  function saveDraftEdit(id) {
    var draft = id ? state.drafts.find(function(item) { return item.id === id; }) : state.drafts[0];
    if (!draft) {
      setStatus('未找到要保存的草稿。', 'warn');
      return null;
    }
    var textarea = document.querySelector('[data-draft-edit-id="' + (draft.id || id) + '"]');
    if (!textarea) {
      setStatus('未找到草稿编辑框。', 'warn');
      return null;
    }
    var raw = textarea.value;
    var parsed;
    try {
      parsed = JSON.parse(raw);
    } catch (_) {
      // If the draft.value was a plain string (not JSON), accept raw text.
      if (typeof draft.value === 'string') {
        parsed = raw;
      } else {
        setStatus('草稿编辑解析失败：请确保是合法 JSON。如要保存为纯文本，请把目标字段类型改为 string。', 'error');
        return null;
      }
    }
    draft.value = parsed;
    draft.editedAt = new Date().toISOString();
    writeStoredDraft();
    renderDraft(draft);
    setStatus('草稿编辑已保存（仍需点「纳入」才会写回剧本）', 'good');
    return clone(draft.value);
  }

  function hasText(value) {
    return String(value == null ? '' : value).trim() !== '';
  }

  function pickFirstExistingField(fields) {
    for (var i = 0; i < fields.length; i += 1) {
      if (Object.prototype.hasOwnProperty.call(state.scenario || {}, fields[i])) return fields[i];
    }
    return fields[0] || '';
  }

  function scenarioMapRegions(sc) {
    var map = isObject(sc && sc.map) ? sc.map : (isObject(sc && sc.mapData) ? sc.mapData : {});
    return []
      .concat(Array.isArray(map.regions) ? map.regions : [])
      .concat(Array.isArray(map.landRegions) ? map.landRegions : [])
      .concat(Array.isArray(map.seaRegions) ? map.seaRegions : [])
      .concat(Array.isArray(map.oceans) ? map.oceans : []);
  }

  function missingCoverageRows(field) {
    var report = analyzeFieldCoverage(field);
    if (!report.supported) return 0;
    return report.rows.filter(function(row) { return row.missingKeys.length; }).length;
  }

  function countMissingMapBindings(regions) {
    return (regions || []).filter(function(region) {
      if (!isObject(region)) return false;
      var hasOwner = hasText(region.ownerKey) || hasText(region.currentOwnerKey) || hasText(region.controllerKey) || hasText(region.owner) || hasText(region.currentOwner) || hasText(region.factionName);
      var hasAdmin = hasText(region.adminBinding) || hasText(region.admin) || hasText(region.divisionId) || hasText(region.prefecture);
      return !hasOwner || !hasAdmin;
    }).length;
  }

  function productionTask(id, level, title, detail, field, index, panel, actionLabel) {
    return {
      id: id,
      level: level,
      title: title,
      detail: detail,
      field: field || '',
      index: Number.isFinite(Number(index)) ? Number(index) : 0,
      panel: panel || 'field-editor',
      actionLabel: actionLabel || '定位'
    };
  }

  function buildScenarioProductionChecklist() {
    var sc = state.scenario || {};
    var expected = blueprintKeys();
    var missingBlueprint = expected.filter(function(key) { return !(key in sc); });
    var characters = Array.isArray(sc.characters) ? sc.characters : [];
    var factions = Array.isArray(sc.factions) ? sc.factions : [];
    var events = []
      .concat(Array.isArray(sc.events) ? sc.events : [])
      .concat(Array.isArray(sc.rigidHistoryEvents) ? sc.rigidHistoryEvents : [])
      .concat(Array.isArray(sc.timeline) ? sc.timeline : []);
    var regions = scenarioMapRegions(sc);
    var officePositions = collectOfficePositionRows(Array.isArray(sc.officeTree) ? sc.officeTree : []);
    var refs = collectMissingReferences();
    var pendingDrafts = (state.drafts || []).filter(function(draft) { return draft.status !== 'accepted'; }).length;
    var diff = buildScenarioDiff();
    var validationErrors = (state.validations || []).filter(function(issue) { return issue.level === 'error'; }).length;
    var validationWarnings = (state.validations || []).filter(function(issue) { return issue.level !== 'error'; }).length;
    var tasks = [];
    var identityMissing = [];
    if (!hasText(sc.id)) identityMissing.push('id');
    if (!hasText(sc.name)) identityMissing.push('name');
    if (!hasText(sc.era || sc.dynasty || sc.yearLabel)) identityMissing.push('时代');
    if (!hasText(sc.background || sc.overview || sc.summary)) identityMissing.push('背景');
    if (!hasText(sc.opening || sc.openingText || sc.openingLetter)) identityMissing.push('开场');
    tasks.push(productionTask(
      'identity',
      identityMissing.indexOf('id') >= 0 || identityMissing.indexOf('name') >= 0 ? 'error' : (identityMissing.length ? 'warn' : 'ok'),
      '剧本身份',
      identityMissing.length ? ('待补 ' + identityMissing.join('、')) : '名称、时代、背景和开场信息已具备。',
      identityMissing.indexOf('name') >= 0 ? 'name' : pickFirstExistingField(['name', 'era', 'background', 'opening']),
      0,
      'field-editor'
    ));
    tasks.push(productionTask(
      'characters',
      characters.length < 1 ? 'error' : (missingCoverageRows('characters') || refs.some(function(row) { return row.kind === 'character'; }) ? 'warn' : 'ok'),
      '人物库',
      characters.length + ' 人物 · ' + missingCoverageRows('characters') + ' 条有空键 · ' + refs.filter(function(row) { return row.kind === 'character'; }).length + ' 个断裂人物引用',
      'characters',
      0,
      'specialist-editor'
    ));
    tasks.push(productionTask(
      'factions',
      factions.length < 1 ? 'error' : (missingCoverageRows('factions') || refs.some(function(row) { return row.kind === 'faction'; }) ? 'warn' : 'ok'),
      '势力库',
      factions.length + ' 势力 · ' + missingCoverageRows('factions') + ' 条有空键 · ' + refs.filter(function(row) { return row.kind === 'faction'; }).length + ' 个断裂势力引用',
      'factions',
      0,
      'specialist-editor'
    ));
    tasks.push(productionTask(
      'events',
      events.length ? (refs.some(function(row) { return row.sources.some(function(source) { return /events|timeline/i.test(source.field || ''); }); }) ? 'warn' : 'ok') : 'warn',
      '事件链',
      events.length ? (events.length + ' 条事件/时间线 · 事件引用可继续复核') : '尚无事件或时间线，正式剧本容易缺少推进节奏。',
      pickFirstExistingField(['events', 'rigidHistoryEvents', 'timeline']),
      0,
      'specialist-editor'
    ));
    tasks.push(productionTask(
      'map-admin',
      regions.length ? (countMissingMapBindings(regions) ? 'warn' : 'ok') : 'warn',
      '地图区划',
      regions.length + ' 个地块 · ' + countMissingMapBindings(regions) + ' 个归属/行政绑定待补',
      pickFirstExistingField(['map', 'mapData', 'adminHierarchy']),
      0,
      'structured-workbench'
    ));
    tasks.push(productionTask(
      'office',
      officePositions.length ? 'ok' : 'warn',
      '官制任免',
      officePositions.length ? (officePositions.length + ' 个官职可编辑任免、员额、俸禄和权责。') : '官制树尚未形成可任免官职。',
      pickFirstExistingField(['officeTree', 'government', 'officeConfig']),
      0,
      'structured-workbench'
    ));
    var player = isObject(sc.playerInfo) ? sc.playerInfo : {};
    var playerMissing = [];
    if (!hasText(player.factionName || player.characterFaction)) playerMissing.push('玩家势力');
    if (!hasText(player.characterName || player.factionLeader)) playerMissing.push('玩家角色');
    tasks.push(productionTask(
      'player',
      playerMissing.length ? 'warn' : 'ok',
      '玩家入口',
      playerMissing.length ? ('待补 ' + playerMissing.join('、') + '，可同步到人物/势力库。') : '玩家势力与角色入口已配置。',
      'playerInfo',
      0,
      'structured-workbench'
    ));
    var rulesReady = Array.isArray(sc.variables) && sc.variables.length && (isObject(sc.mechanicsConfig) || hasText(sc.customPrompt) || hasText(sc.globalRules));
    tasks.push(productionTask(
      'rules',
      rulesReady ? 'ok' : 'warn',
      '规则与 AI 边界',
      (Array.isArray(sc.variables) ? sc.variables.length : 0) + ' 条变量 · ' + (rulesReady ? '机制/提示边界已可编辑' : '建议补机制配置或全局提示约束'),
      pickFirstExistingField(['variables', 'mechanicsConfig', 'customPrompt', 'globalRules', 'rules']),
      0,
      'structured-workbench'
    ));
    tasks.push(productionTask(
      'release',
      validationErrors ? 'error' : (missingBlueprint.length || validationWarnings || pendingDrafts ? 'warn' : 'ok'),
      '发布出口',
      '缺蓝图字段 ' + missingBlueprint.length + ' · 校验错误 ' + validationErrors + ' · 提醒 ' + validationWarnings + ' · 待审草稿 ' + pendingDrafts + ' · 改动字段 ' + diff.length,
      missingBlueprint[0] || (diff[0] && diff[0].key) || 'name',
      0,
      'preflight-gate'
    ));
    var ok = tasks.filter(function(task) { return task.level === 'ok'; }).length;
    var warnings = tasks.filter(function(task) { return task.level === 'warn'; }).length;
    var errors = tasks.filter(function(task) { return task.level === 'error'; }).length;
    var score = tasks.length ? Math.round(ok / tasks.length * 100) : 100;
    return { score: score, ok: ok, warnings: warnings, errors: errors, tasks: tasks, missingBlueprint: missingBlueprint };
  }

  function renderProductionDashboard() {
    var box = document.getElementById('production-dashboard-list');
    if (!box) return;
    var report = buildScenarioProductionChecklist();
    var level = report.errors ? 'error' : (report.warnings ? 'warn' : 'ok');
    var rows = report.tasks.map(function(task) {
      return '<div class="production-task-row" data-production-task="' + escapeHtml(task.id) + '" data-level="' + escapeHtml(task.level) + '">' +
        '<div><b>' + escapeHtml(task.title) + '</b><span>' + escapeHtml(task.detail) + '</span></div>' +
        '<div class="production-task-actions"><button class="mini-ai" data-editor-command="apply-production-task-fix" data-production-task-fix="' + escapeHtml(task.id) + '">处理</button><button class="mini-ai" data-editor-command="jump-production-task" data-production-field="' + escapeHtml(task.field) + '" data-production-index="' + task.index + '" data-production-panel="' + escapeHtml(task.panel) + '">' + escapeHtml(task.actionLabel) + '</button></div>' +
      '</div>';
    }).join('');
    box.innerHTML = [
      '<div class="production-score" data-level="' + level + '"><strong>' + report.score + '%</strong><span>' + report.ok + ' 项就绪 · ' + report.warnings + ' 项提醒 · ' + report.errors + ' 项阻断</span></div>',
      '<div class="production-actions"><button class="mini-ai" data-editor-command="apply-all-production-task-fixes">一键处理待办</button><button class="mini-ai" data-editor-command="prepare-release-readiness">准备发布字段</button><button class="mini-ai" data-editor-command="validate">运行校验</button><button class="mini-ai" data-editor-command="build-ai-fix-plan">生成修复计划</button><button class="mini-ai" data-editor-command="scaffold-production-minimum">补核心骨架</button></div>',
      '<div class="production-task-list">' + rows + '</div>'
    ].join('');
  }

  function buildCreatorWorkflow() {
    var production = buildScenarioProductionChecklist();
    var taskById = {};
    production.tasks.forEach(function(task) { taskById[task.id] = task; });
    var steps = CREATOR_WORKFLOW_STEPS.map(function(step) {
      var tasks = step.tasks.map(function(id) { return taskById[id]; }).filter(Boolean);
      var level = tasks.some(function(task) { return task.level === 'error'; }) ? 'error' : (tasks.some(function(task) { return task.level === 'warn'; }) ? 'warn' : 'ok');
      var detail = tasks.map(function(task) { return task.title + '：' + task.detail; }).join(' / ') || step.detail;
      return Object.assign({}, step, { level: level, taskDetails: detail, taskCount: tasks.length });
    });
    var done = steps.filter(function(step) { return step.level === 'ok'; }).length;
    var next = steps.find(function(step) { return step.level !== 'ok'; }) || steps[steps.length - 1];
    return { steps: steps, done: done, total: steps.length, next: next, production: production };
  }

  function renderCreatorWorkflow() {
    var box = document.getElementById('creator-workflow-list');
    if (!box) return;
    var workflow = buildCreatorWorkflow();
    var summaryLevel = workflow.production.errors ? 'error' : (workflow.production.warnings ? 'warn' : 'ok');
    var rows = workflow.steps.map(function(step) {
      var attrs = 'data-editor-command="' + escapeHtml(step.command) + '"';
      if (step.field) attrs += ' data-shortcut-field="' + escapeHtml(step.field) + '"';
      if (step.panel) attrs += ' data-shortcut-panel="' + escapeHtml(step.panel) + '"';
      if (step.runtimePanel) attrs += ' data-runtime-panel="' + escapeHtml(step.runtimePanel) + '"';
      var marker = step.level === 'ok' ? '就绪' : (step.level === 'error' ? '阻断' : '提醒');
      return '<article class="workflow-step-card" data-workflow-step="' + escapeHtml(step.id) + '" data-level="' + escapeHtml(step.level) + '">' +
        '<div><b>' + escapeHtml(step.title) + '</b><span>' + escapeHtml(step.detail) + '</span><small>' + escapeHtml(step.taskDetails) + '</small></div>' +
        '<em>' + escapeHtml(marker) + '</em><div class="workflow-step-actions"><button class="mini-ai" data-editor-command="apply-creator-workflow-step" data-workflow-step-fix="' + escapeHtml(step.id) + '">处理</button><button class="mini-ai" ' + attrs + '>' + escapeHtml(step.label) + '</button></div>' +
      '</article>';
    }).join('');
    box.innerHTML = [
      '<div class="workflow-summary" data-level="' + summaryLevel + '" data-workflow-next="' + escapeHtml(workflow.next ? workflow.next.id : 'release') + '"><strong>' + workflow.done + '/' + workflow.total + '</strong><span>下一步：' + escapeHtml(workflow.next ? workflow.next.title : '发布') + ' · 制作分 ' + workflow.production.score + '%</span><div class="workflow-summary-actions"><button class="mini-ai" data-editor-command="continue-creator-workflow">继续下一步</button><button class="mini-ai" data-editor-command="apply-next-creator-workflow">处理下一步</button><button class="mini-ai" data-editor-command="apply-all-production-task-fixes">一键处理待办</button><button class="mini-ai" data-editor-command="prepare-release-readiness">准备发布字段</button><button class="mini-ai" data-editor-command="scaffold-production-minimum">补核心骨架</button></div></div>',
      '<div class="workflow-step-list">' + rows + '</div>'
    ].join('');
  }

  function activateCreatorWorkflowStep(id) {
    var workflow = buildCreatorWorkflow();
    var step = workflow.steps.find(function(item) { return item.id === id; }) || workflow.next;
    if (!step) return null;
    if (step.command === 'jump-field-workbench') return jumpFieldWorkbench(step.field, step.panel);
    if (step.command === 'focus-runtime-panel') return focusRuntimePanel(step.runtimePanel);
    if (step.command === 'run-preflight') {
      runPreflight();
      return focusRuntimePanel('preflight-gate');
    }
    setStatus('未知制作流程动作：' + step.command, 'warn');
    return null;
  }

  function continueCreatorWorkflow() {
    var workflow = buildCreatorWorkflow();
    return activateCreatorWorkflowStep(workflow.next && workflow.next.id);
  }

  function applyCreatorWorkflowStep(id) {
    var workflow = buildCreatorWorkflow();
    var step = workflow.steps.find(function(item) { return item.id === id; }) || workflow.next;
    if (!step) return null;
    var taskById = {};
    workflow.production.tasks.forEach(function(task) { taskById[task.id] = task; });
    var results = [];
    step.tasks.forEach(function(taskId) {
      var task = taskById[taskId];
      if (!task || task.level === 'ok') return;
      var result = applyProductionTaskFix(taskId);
      if (result) results.push(result);
    });
    var changed = results.reduce(function(total, result) { return total + (Number(result.changed) || 0); }, 0);
    activateCreatorWorkflowStep(step.id);
    if (results.length) {
      setStatus('已处理流程步骤：' + step.title + ' · ' + changed + ' 项', changed ? 'good' : 'neutral');
    } else {
      setStatus('流程步骤已就绪：' + step.title, 'neutral');
    }
    return { id: step.id, changed: changed, results: results, next: buildCreatorWorkflow().next && buildCreatorWorkflow().next.id };
  }

  function applyNextCreatorWorkflow() {
    var workflow = buildCreatorWorkflow();
    return applyCreatorWorkflowStep(workflow.next && workflow.next.id);
  }

  function firstNamed(rows) {
    return (rows || []).find(function(row) { return row && hasText(row.name || row.id || row.sid); }) || null;
  }

  function ensureProductionIdentity() {
    var changed = [];
    if (!hasText(state.scenario.id)) {
      state.scenario.id = uniqueId('scenario');
      changed.push('id');
    }
    if (!hasText(state.scenario.name)) {
      state.scenario.name = '未命名剧本';
      changed.push('name');
    }
    if (!hasText(state.scenario.era || state.scenario.dynasty || state.scenario.yearLabel)) {
      state.scenario.era = state.scenario.era || '待定时代';
      changed.push('era');
    }
    if (!hasText(state.scenario.background || state.scenario.overview || state.scenario.summary)) {
      state.scenario.background = state.scenario.background || '待补剧本背景';
      changed.push('background');
    }
    if (!hasText(state.scenario.opening || state.scenario.openingText || state.scenario.openingLetter)) {
      state.scenario.opening = state.scenario.opening || '待补开场白';
      changed.push('opening');
    }
    if (changed.length) recordHistory('处理制作待办', '剧本身份 · ' + changed.join(', '));
    state.selectedField = changed[0] || 'name';
    state.selectedModuleId = inferModuleForField(state.selectedField);
    state.activeWorkbenchPanel = 'field-editor';
    return changed.length;
  }

  function ensureProductionEntityList(field) {
    if (!Array.isArray(state.scenario[field])) state.scenario[field] = [];
    var changed = 0;
    if (!state.scenario[field].length) {
      state.scenario[field].push(buildEntityTemplate(field));
      changed += 1;
      recordHistory('处理制作待办', field + ' · 新增模板条目');
    }
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    state.selectedEntityIndex = 0;
    state.activeWorkbenchPanel = 'coverage-inspector';
    renderAll();
    return changed;
  }

  function ensureProductionEvents() {
    var field = pickFirstExistingField(['events', 'rigidHistoryEvents', 'timeline']) || 'events';
    if (!Array.isArray(state.scenario[field])) state.scenario[field] = [];
    var changed = 0;
    if (!state.scenario[field].length) {
      state.scenario[field].push(buildEntityTemplate(field));
      changed += 1;
      recordHistory('处理制作待办', '事件链 · 新增起始事件');
    }
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    state.selectedEntityIndex = 0;
    state.activeWorkbenchPanel = 'specialist-editor';
    if (!changed) validateScenario();
    return changed;
  }

  function ensureProductionMapAdmin() {
    var scaffoldChanged = ensureProductionMapScaffold();
    var field = 'map';
    if (field === 'adminHierarchy' && !Object.prototype.hasOwnProperty.call(state.scenario || {}, 'map')) {
      state.scenario.map = { regions: [], oceans: [], source: 'scenario-editor-reset-scaffold' };
      field = 'map';
      recordHistory('处理制作待办', '地图区划 · 新增地图骨架');
    } else if (!Object.prototype.hasOwnProperty.call(state.scenario || {}, field)) {
      state.scenario[field] = inferMissingFieldTemplate(field);
      recordHistory('处理制作待办', '地图区划 · 新增 ' + field);
    }
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    state.activeWorkbenchPanel = 'structured-workbench';
    if (isMapWorkbenchField(field, state.scenario[field])) {
      var before = countMissingMapBindings(scenarioMapRegions(state.scenario));
      normalizeMapBindings();
      var after = countMissingMapBindings(scenarioMapRegions(state.scenario));
      return scaffoldChanged + Math.max(0, before - after);
    }
    renderAll();
    return scaffoldChanged;
  }

  function ensureProductionOffice() {
    if (!Array.isArray(state.scenario.officeTree)) state.scenario.officeTree = [];
    var changed = 0;
    if (!state.scenario.officeTree.length) {
      state.scenario.officeTree.push({
        id: uniqueId('office'),
        name: '中枢机构',
        desc: '待补机构说明',
        positions: [{ id: uniqueId('office_pos'), name: '主官', rank: '待定', establishedCount: 1, vacancyCount: 0, holder: '', salary: 0, duties: '待补职责', powers: { appointment: false, impeach: false, supervise: false } }],
        subs: []
      });
      changed += 1;
      recordHistory('处理制作待办', '官制任免 · 新增中枢机构');
    }
    state.selectedField = 'officeTree';
    state.selectedModuleId = inferModuleForField('officeTree');
    state.activeWorkbenchPanel = 'structured-workbench';
    renderAll();
    return changed;
  }

  function ensureProductionPlayer() {
    if (!isObject(state.scenario.playerInfo)) state.scenario.playerInfo = {};
    var info = state.scenario.playerInfo;
    var faction = firstNamed(Array.isArray(state.scenario.factions) ? state.scenario.factions : []);
    var character = firstNamed(Array.isArray(state.scenario.characters) ? state.scenario.characters : []);
    var changed = 0;
    if (!hasText(info.factionName || info.characterFaction) && faction) {
      info.factionName = faction.name || faction.id || faction.sid;
      changed += 1;
    }
    if (!hasText(info.characterName || info.factionLeader) && character) {
      info.characterName = character.name || character.id || character.sid;
      changed += 1;
    }
    state.selectedField = 'playerInfo';
    state.selectedModuleId = inferModuleForField('playerInfo');
    state.activeWorkbenchPanel = 'structured-workbench';
    if (changed) recordHistory('处理制作待办', '玩家入口 · 同步首个人物/势力');
    renderAll();
    return changed;
  }

  function ensureProductionRules() {
    var changed = 0;
    if (!Array.isArray(state.scenario.variables)) {
      state.scenario.variables = [];
      changed += 1;
    }
    if (!state.scenario.variables.length) {
      state.scenario.variables.push({ id: uniqueId('var'), name: '核心变量', value: 50, min: 0, max: 100, cat: '开局', visible: true, desc: '待补变量说明' });
      changed += 1;
    }
    if (!isObject(state.scenario.mechanicsConfig)) {
      state.scenario.mechanicsConfig = { notes: '待补机制边界', enabled: true };
      changed += 1;
    }
    state.selectedField = 'variables';
    state.selectedModuleId = inferModuleForField('variables');
    state.activeWorkbenchPanel = 'structured-workbench';
    if (changed) recordHistory('处理制作待办', '规则与 AI 边界 · 补变量/机制骨架');
    renderAll();
    return changed;
  }

  function applyProductionTaskFix(id) {
    var key = String(id || '').trim();
    var changed = 0;
    if (key === 'identity') changed = ensureProductionIdentity();
    else if (key === 'characters') changed = ensureProductionEntityList('characters');
    else if (key === 'factions') changed = ensureProductionEntityList('factions');
    else if (key === 'events') changed = ensureProductionEvents();
    else if (key === 'map-admin') changed = ensureProductionMapAdmin();
    else if (key === 'office') changed = ensureProductionOffice();
    else if (key === 'player') changed = ensureProductionPlayer();
    else if (key === 'rules') changed = ensureProductionRules();
    else if (key === 'release') {
      runPreflight();
      state.activeWorkbenchPanel = 'all';
      changed = 0;
    } else {
      setStatus('未知制作待办：' + key, 'warn');
      return null;
    }
    state.dirty = changed > 0 || state.dirty;
    state.validationRan = false;
    writeStoredDraft();
    renderAll();
    setStatus(changed ? ('制作待办已处理：' + key + ' · ' + changed + ' 项') : ('制作待办已复核：' + key), changed ? 'good' : 'neutral');
    return { id: key, changed: changed, scenario: clone(state.scenario) };
  }

  function prepareReleaseReadiness() {
    var created = [];
    blueprintKeys().forEach(function(key) {
      if (Object.prototype.hasOwnProperty.call(state.scenario || {}, key)) return;
      state.scenario[key] = inferMissingFieldTemplate(key);
      created.push(key);
    });
    var runtimeReport = buildRuntimeFieldAudit({ filter: 'all', query: '' });
    runtimeReport.rows.forEach(function(row) {
      if (row.present || !row.required) return;
      if (Object.prototype.hasOwnProperty.call(state.scenario || {}, row.field)) return;
      state.scenario[row.field] = inferMissingFieldTemplate(row.field);
      created.push(row.field);
    });
    if (created.length) {
      state.selectedField = created[0];
      state.selectedModuleId = inferModuleForField(created[0]);
      state.selectedEntityIndex = 0;
      recordHistory('准备发布字段', created.length + ' 项 · ' + created.slice(0, 10).join(', '));
    }
    var issues = validateScenario();
    var preflight = runPreflight();
    state.activeWorkbenchPanel = 'all';
    focusRuntimePanel('preflight-gate');
    var report = buildScenarioProductionChecklist();
    setStatus(created.length ? ('已准备发布字段：' + created.length + ' 项 · 制作分 ' + report.score + '%') : ('发布字段已复核 · 制作分 ' + report.score + '%'), issues.length ? 'warn' : 'good');
    return { created: clone(created), issues: clone(issues), preflight: preflight, report: report };
  }

  function applyAllProductionTaskFixes() {
    var results = [];
    var refRows = collectMissingReferences();
    if (refRows.length) {
      var refResult = createAllReferencePlaceholders('all');
      if (refResult && refResult.created && refResult.created.length) {
        results.push({ id: 'references', changed: refResult.created.length, detail: '断裂引用占位' });
      }
    }
    var guard = 0;
    while (guard < 3) {
      guard += 1;
      var report = buildScenarioProductionChecklist();
      var pending = report.tasks.filter(function(task) {
        return task.level !== 'ok' && task.id !== 'release';
      });
      if (!pending.length) break;
      var changedThisPass = 0;
      pending.forEach(function(task) {
        var result = applyProductionTaskFix(task.id);
        if (!result) return;
        var changed = Number(result.changed) || 0;
        changedThisPass += changed;
        results.push({ id: result.id, changed: changed });
      });
      if (!changedThisPass) break;
    }
    ['characters', 'factions', 'events'].forEach(function(field) {
      if (!Array.isArray(state.scenario[field]) || !state.scenario[field].length) return;
      var missing = missingCoverageRows(field);
      if (!missing) return;
      var fill = fillMissingKeys(field);
      if (fill && fill.changed) results.push({ id: field + '-coverage', changed: fill.changed, detail: '字段完整度' });
    });
    var releaseResult = prepareReleaseReadiness();
    if (releaseResult && releaseResult.created && releaseResult.created.length) {
      results.push({ id: 'release-readiness', changed: releaseResult.created.length, detail: '发布字段' });
    }
    validateScenario();
    var finalReport = buildScenarioProductionChecklist();
    var next = finalReport.tasks.find(function(task) { return task.level !== 'ok'; }) || null;
    var focusReleaseGate = !next;
    if (next) {
      state.selectedField = next.field || state.selectedField || 'name';
      state.selectedModuleId = inferModuleForField(state.selectedField);
      state.selectedEntityIndex = next.index || 0;
      state.activeWorkbenchPanel = next.panel || activeWorkbenchPanel();
    } else {
      state.activeWorkbenchPanel = 'all';
    }
    var changedTotal = results.reduce(function(total, result) { return total + (Number(result.changed) || 0); }, 0);
    state.dirty = changedTotal > 0 || state.dirty;
    state.validationRan = true;
    writeStoredDraft();
    renderAll();
    if (focusReleaseGate) focusRuntimePanel('preflight-gate');
    setStatus(changedTotal ? ('已一键处理制作待办：' + changedTotal + ' 项 · 当前制作分 ' + finalReport.score + '%') : ('制作待办已复核：当前制作分 ' + finalReport.score + '%'), changedTotal ? 'good' : 'neutral');
    return { changed: changedTotal, results: clone(results), score: finalReport.score, next: next && next.id, report: finalReport };
  }

  function jumpProductionTask(field, index, panel) {
    var targetField = field || state.selectedField || 'name';
    state.selectedField = targetField;
    state.selectedModuleId = inferModuleForField(targetField);
    var value = state.scenario[targetField];
    var targetIndex = Number(index);
    state.selectedEntityIndex = Array.isArray(value) && Number.isFinite(targetIndex) ? Math.max(0, Math.min(targetIndex, value.length - 1)) : 0;
    state.activeWorkbenchPanel = workbenchPanelExists(panel) ? panel : activeWorkbenchPanel();
    state.search = '';
    renderAll();
    setStatus('已定位制作待办：' + targetField, 'good');
    setTimeout(function() {
      var targetPanel = panel ? document.querySelector('[data-panel="' + panel + '"]') : null;
      if (targetPanel && targetPanel.scrollIntoView) targetPanel.scrollIntoView({ block: 'center', behavior: 'smooth' });
    }, 30);
    return { field: state.selectedField, index: state.selectedEntityIndex, panel: panel || '' };
  }

  function scaffoldProductionMinimum() {
    var created = [];
    function ensureField(key, value) {
      if (Object.prototype.hasOwnProperty.call(state.scenario || {}, key)) return;
      state.scenario[key] = clone(value);
      created.push(key);
    }
    ensureField('id', uniqueId('scenario'));
    ensureField('name', '未命名剧本');
    ensureField('era', '待定时代');
    ensureField('background', '待补剧本背景');
    ensureField('opening', '待补开场白');
    ensureField('gameSettings', { startYear: 1, startMonth: 1, startDay: 1, daysPerTurn: 30, turnUnit: '月', enabledSystems: {} });
    ensureField('playerInfo', { factionName: '', characterName: '', playerRole: '', factionGoal: '', coreContradictions: [] });
    ensureField('characters', []);
    ensureField('factions', []);
    ensureField('events', []);
    ensureField('map', { regions: [], oceans: [], source: 'scenario-editor-reset-scaffold' });
    ensureField('officeTree', []);
    if (!Array.isArray(state.scenario.characters)) state.scenario.characters = [];
    if (!state.scenario.characters.length) {
      state.scenario.characters.push(buildEntityTemplate('characters'));
      created.push('characters[0]');
    }
    if (!Array.isArray(state.scenario.factions)) state.scenario.factions = [];
    if (!state.scenario.factions.length) {
      state.scenario.factions.push(buildEntityTemplate('factions'));
      created.push('factions[0]');
    }
    if (ensureProductionMapScaffold()) created.push('map scaffold');
    if (!Array.isArray(state.scenario.events)) state.scenario.events = [];
    if (!state.scenario.events.length) {
      state.scenario.events.push(buildEntityTemplate('events'));
      created.push('events[0]');
    }
    state.selectedField = created.indexOf('characters[0]') >= 0 ? 'characters' : (created[0] || state.selectedField || 'name');
    state.selectedModuleId = inferModuleForField(state.selectedField);
    state.selectedEntityIndex = 0;
    recordHistory('补核心制作骨架', created.length ? created.join(', ') : '无新增');
    renderAll();
    setStatus(created.length ? ('已补核心制作骨架：' + created.length + ' 项') : '核心制作骨架已存在', created.length ? 'good' : 'neutral');
    return { created: created, scenario: clone(state.scenario) };
  }

  function openDrawerForApp() {
    var drawer = document.getElementById('ai-drawer');
    var backdrop = document.getElementById('ai-drawer-backdrop');
    if (drawer) drawer.classList.add('open');
    if (backdrop) backdrop.classList.add('open');
  }

  function renderScenarioDashboard() {
    var sc = state.scenario || {};
    var orig = state.original || {};
    var expected = blueprintKeys();
    var present = expected.filter(function(key) { return key in sc; });
    var missing = expected.filter(function(key) { return !(key in sc); });
    var mapCount = sc.map ? countCollection(sc.map) : sc.mapData ? countCollection(sc.mapData) : 0;
    var origMapCount = orig.map ? countCollection(orig.map) : orig.mapData ? countCollection(orig.mapData) : 0;
    setLiveMetric('top-level-keys', Object.keys(sc).length, Object.keys(orig).length);
    setLiveMetric('characters', countCollection(sc.characters), countCollection(orig.characters));
    setLiveMetric('factions', countCollection(sc.factions), countCollection(orig.factions));
    setLiveMetric('admin-systems', countCollection(sc.adminHierarchy), countCollection(orig.adminHierarchy));
    setLiveMetric('map-regions', mapCount, origMapCount);
    setLiveMetric('admin-map-regions', mapCount, origMapCount);
    setLiveMetric('field-coverage', present.length + '/' + expected.length);
    setLiveMetric('missing-blueprint-fields', missing.length);
    setLiveMetric('validation-issues', state.validations.length);
  }

  function formatMetricDelta(current, baseline) {
    if (baseline == null || typeof baseline !== 'number' || typeof current !== 'number') return String(current);
    var delta = current - baseline;
    if (delta === 0) return String(current);
    return String(current) + (delta > 0 ? ' (+' + delta + ')' : ' (' + delta + ')');
  }

  function setLiveMetric(name, value, baseline) {
    var rendered = (typeof value === 'number' && typeof baseline === 'number')
      ? formatMetricDelta(value, baseline)
      : String(value);
    document.querySelectorAll('[data-live-metric="' + name + '"]').forEach(function(node) {
      node.textContent = rendered;
      // Tag delta direction so CSS can color the chip.
      if (typeof value === 'number' && typeof baseline === 'number') {
        var delta = value - baseline;
        node.dataset.metricDelta = delta === 0 ? 'zero' : delta > 0 ? 'up' : 'down';
      } else {
        delete node.dataset.metricDelta;
      }
    });
  }

  function searchDocument(value) {
    if (value == null) return '';
    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') return String(value);
    try {
      return stableString(value);
    } catch (_) {
      return String(value);
    }
  }

  function buildGlobalSearchIndex() {
    var scenario = state.scenario || {};
    var rows = [];
    Object.keys(scenario).forEach(function(field) {
      var value = scenario[field];
      var moduleId = inferModuleForField(field);
      rows.push({
        type: 'field',
        field: field,
        index: -1,
        moduleId: moduleId,
        label: field,
        summary: fieldType(value) + ' · ' + fieldCount(value),
        text: [field, fieldType(value), fieldCount(value), searchDocument(value).slice(0, 2600)].join(' ')
      });
      if (Array.isArray(value)) {
        value.forEach(function(item, index) {
          var label = labelOf(item, index);
          var summary = itemSummary(item);
          rows.push({
            type: 'entity',
            field: field,
            index: index,
            moduleId: moduleId,
            label: label,
            summary: summary,
            text: [field, label, summary, searchDocument(item)].join(' ')
          });
        });
        return;
      }
      if (isObject(value)) {
        Object.keys(value).forEach(function(key) {
          rows.push({
            type: 'object-key',
            field: field,
            index: -1,
            objectKey: key,
            moduleId: moduleId,
            label: field + '.' + key,
            summary: fieldType(value[key]) + ' · ' + fieldCount(value[key]),
            text: [field, key, fieldType(value[key]), fieldCount(value[key]), searchDocument(value[key]).slice(0, 1600)].join(' ')
          });
        });
      }
    });
    return rows;
  }

  function runGlobalSearch(query, limit) {
    var max = limit || 40;
    var trimmed = String(query == null ? state.globalSearchQuery : query).trim();
    var index = buildGlobalSearchIndex();
    if (!trimmed) {
      return index.filter(function(row) { return row.type === 'field'; }).slice(0, max);
    }
    var terms = trimmed.toLowerCase().split(/\s+/).filter(Boolean);
    return index.map(function(row) {
      var label = String(row.label || '').toLowerCase();
      var field = String(row.field || '').toLowerCase();
      var summary = String(row.summary || '').toLowerCase();
      var text = String(row.text || '').toLowerCase();
      var score = 0;
      terms.forEach(function(term) {
        if (label === term) score += 48;
        if (label.indexOf(term) >= 0) score += 24;
        if (field.indexOf(term) >= 0) score += 12;
        if (summary.indexOf(term) >= 0) score += 8;
        if (text.indexOf(term) >= 0) score += 3;
      });
      if (row.type === 'entity') score += 4;
      if (row.type === 'field') score += 1;
      return Object.assign({}, row, { score: score });
    }).filter(function(row) {
      return row.score > 0;
    }).sort(function(a, b) {
      return b.score - a.score || (a.type === 'entity' ? -1 : 1) || a.field.localeCompare(b.field);
    }).slice(0, max);
  }

  function jumpToSearchResult(field, index) {
    if (!field || !Object.prototype.hasOwnProperty.call(state.scenario || {}, field)) return null;
    var value = state.scenario[field];
    state.selectedField = field;
    state.selectedModuleId = inferModuleForField(field);
    var nextIndex = Number(index);
    state.selectedEntityIndex = Array.isArray(value) && Number.isFinite(nextIndex) && nextIndex >= 0 && nextIndex < value.length ? nextIndex : 0;
    state.search = '';
    renderAll();
    setStatus('已定位：' + field + (Array.isArray(value) ? '[' + state.selectedEntityIndex + ']' : ''), 'good');
    return {
      field: state.selectedField,
      index: state.selectedEntityIndex,
      moduleId: state.selectedModuleId,
      value: Array.isArray(value) ? value[state.selectedEntityIndex] : value
    };
  }

  function jumpFieldWorkbench(field, panel) {
    var targetField = field || state.selectedField || 'name';
    state.selectedField = targetField;
    state.selectedModuleId = inferModuleForField(targetField);
    state.selectedEntityIndex = 0;
    state.search = '';
    state.activeWorkbenchPanel = workbenchPanelExists(panel) ? panel : activeWorkbenchPanel();
    renderAll();
    setStatus('已打开制作入口：' + targetField + ' · ' + activeWorkbenchPanel(), 'good');
    setTimeout(function() {
      var target = document.getElementById('module-detail');
      if (target && target.scrollIntoView) target.scrollIntoView({ block: 'start', behavior: 'smooth' });
    }, 30);
    return { field: state.selectedField, moduleId: state.selectedModuleId, panel: activeWorkbenchPanel() };
  }

  function focusRuntimePanel(panelId) {
    var key = String(panelId || '').trim();
    var target = key ? document.querySelector('[data-panel="' + key + '"]') : null;
    if (!target) {
      setStatus('未找到制作面板：' + key, 'warn');
      return null;
    }
    document.querySelectorAll('[data-runtime-focus="true"]').forEach(function(node) {
      node.removeAttribute('data-runtime-focus');
    });
    target.setAttribute('data-runtime-focus', 'true');
    if (target.scrollIntoView) target.scrollIntoView({ block: 'start', behavior: 'smooth' });
    setTimeout(function() { target.removeAttribute('data-runtime-focus'); }, 1800);
    setStatus('已定位制作面板：' + key, 'good');
    return key;
  }

  function renderGlobalSearch() {
    var input = document.getElementById('global-search-input');
    var box = document.getElementById('global-search-results');
    if (!box) return;
    if (input && input.value !== state.globalSearchQuery) input.value = state.globalSearchQuery;
    var rows = runGlobalSearch(state.globalSearchQuery, 36);
    var summary = state.globalSearchQuery ? ('命中 ' + rows.length + ' 条 · 可跨人物、势力、地图、字段跳转') : ('索引 ' + buildGlobalSearchIndex().length + ' 项 · 输入关键词开始定位');
    box.innerHTML = '<div class="global-search-summary">' + escapeHtml(summary) + '</div>' + (rows.map(function(row) {
      return '<button class="global-search-row" data-result-type="' + escapeHtml(row.type) + '" data-editor-command="jump-global-search" data-search-field="' + escapeHtml(row.field) + '" data-search-index="' + row.index + '"><div><b>' + escapeHtml(row.label) + '</b><span>' + escapeHtml(row.field + ' · ' + row.type + ' · ' + row.summary) + '</span></div><em>' + escapeHtml(moduleTitle(findModule(row.moduleId))) + '</em></button>';
    }).join('') || '<p>没有命中。可以搜人物名、势力名、id、官职、地块名或字段名。</p>');
  }

  function renderCreatorShortcuts() {
    var grid = document.querySelector('[data-panel="creator-shortcuts"] .shortcut-grid');
    if (!grid) return;
    grid.innerHTML = CREATOR_SHORTCUTS.map(function(item) {
      var attrs = 'data-editor-command="' + escapeHtml(item.command) + '"';
      if (item.field) attrs += ' data-shortcut-field="' + escapeHtml(item.field) + '"';
      if (item.panel) attrs += ' data-shortcut-panel="' + escapeHtml(item.panel) + '"';
      if (item.runtimePanel) attrs += ' data-runtime-panel="' + escapeHtml(item.runtimePanel) + '"';
      return '<article class="shortcut-card" data-creator-shortcut="' + escapeHtml(item.id) + '">' +
        '<span class="shortcut-icon">' + escapeHtml(item.icon) + '</span>' +
        '<span><strong>' + escapeHtml(item.title) + '</strong>' + escapeHtml(item.detail) + '</span>' +
        '<div class="shortcut-actions"><button class="ai-button" ' + attrs + '>' + escapeHtml(item.label) + '</button></div>' +
      '</article>';
    }).join('');
  }

  function renderScenarioStarters() {
    var box = document.getElementById('new-scenario-starter-list');
    if (!box) return;
    var blankCards = SCENARIO_STARTER_TEMPLATES.map(function(template) {
      var stats = [
        (template.characters || []).length + ' 人物',
        (template.factions || []).length + ' 势力',
        (template.events || []).length + ' 事件',
        (template.regions || []).length + ' 地块'
      ].join(' · ');
      return '<article class="starter-template-card" data-starter-template="' + escapeHtml(template.id) + '">' +
        '<div><strong>' + escapeHtml(template.title) + '</strong><span>' + escapeHtml(template.detail) + '</span><small>' + escapeHtml(stats) + '</small></div>' +
        '<button class="mini-ai" data-editor-command="create-new-scenario" data-scenario-template="' + escapeHtml(template.id) + '">从此开始</button>' +
      '</article>';
    }).join('');
    var officialCards = OFFICIAL_SCENARIOS.map(function(entry) {
      return '<article class="starter-template-card starter-template-card--official" data-official-scenario="' + escapeHtml(entry.id) + '">' +
        '<div><strong>' + escapeHtml(entry.title) + '</strong><span>' + escapeHtml(entry.detail) + '</span><small>' + escapeHtml(entry.dynasty + ' · ' + entry.era + ' · ' + entry.schema) + '</small></div>' +
        '<button class="mini-ai" data-editor-command="load-official-scenario" data-official-scenario="' + escapeHtml(entry.id) + '">载入官方</button>' +
      '</article>';
    }).join('');
    box.innerHTML = '<h4 class="starter-section-title">官方剧本基线</h4><div class="starter-template-grid">' + officialCards + '</div>' +
      '<h4 class="starter-section-title">从模板新建</h4><div class="starter-template-grid">' + blankCards + '</div>';
  }

  // Perf overlay state. Toggled by Ctrl+Shift+P. Captures last renderAll
  // duration, cumulative count, scenario serialized size, and draft / job
  // counts. Hidden by default; lazy-rendered when state.perfOverlay.active.
  var PERF_OVERLAY_KEY = 'tm.scenarioEditorReset.perfOverlay.v1';

  function ensurePerfState() {
    if (!state.perfOverlay) {
      var stored = false;
      try { stored = global.localStorage && global.localStorage.getItem(PERF_OVERLAY_KEY) === 'true'; } catch (_) {}
      state.perfOverlay = { active: stored, lastMs: 0, totalRenders: 0 };
    }
    return state.perfOverlay;
  }

  function togglePerfOverlay() {
    var perf = ensurePerfState();
    perf.active = !perf.active;
    try {
      if (global.localStorage) global.localStorage.setItem(PERF_OVERLAY_KEY, perf.active ? 'true' : 'false');
    } catch (_) {}
    var node = document.getElementById('perf-overlay');
    if (node) node.dataset.active = perf.active ? 'true' : 'false';
    renderPerfOverlay();
    setStatus(perf.active ? '已开启性能浮层（Ctrl+Shift+P 关）' : '已关闭性能浮层', 'neutral');
  }

  function renderPerfOverlay() {
    var perf = ensurePerfState();
    var node = document.getElementById('perf-overlay');
    if (!node) {
      node = document.createElement('div');
      node.id = 'perf-overlay';
      node.dataset.active = perf.active ? 'true' : 'false';
      document.body.appendChild(node);
    }
    if (!perf.active) {
      node.dataset.active = 'false';
      return;
    }
    var size;
    try { size = JSON.stringify(state.scenario || {}).length; } catch (_) { size = 0; }
    var sizeStr = size > 1024 * 1024 ? (size / 1048576).toFixed(2) + ' MB' : size > 1024 ? (size / 1024).toFixed(1) + ' KB' : size + ' B';
    var draftCount = (state.drafts || []).filter(function(d) { return !d.status || d.status === 'review-required'; }).length;
    var jobCount = (state.aiJobs || []).filter(function(j) { return j.status === 'queued' || j.status === 'running'; }).length;
    node.dataset.active = 'true';
    node.innerHTML = [
      '<strong>性能浮层</strong>',
      '<span>渲染耗时 ' + perf.lastMs.toFixed(1) + ' ms · 累计 ' + perf.totalRenders + ' 次</span>',
      '<span>剧本体积 ' + sizeStr + '</span>',
      '<span>待审草稿 ' + draftCount + ' · AI 队列 ' + jobCount + '</span>',
      '<small>Ctrl+Shift+P 切换</small>'
    ].join('');
  }

  // Slice 68 · keyboard shortcut cheatsheet.
  // Centered overlay that lists every binding grouped by category. Built
  // lazily on first toggle; subsequent toggles flip a data attribute
  // instead of rebuilding the DOM. Dismissed by Esc (handled in the
  // existing keydown handler), Shift+? again, or clicking the backdrop.
  var SHORTCUT_GROUPS = [
    {
      title: '导航',
      items: [
        { keys: 'Alt+1 .. Alt+9', desc: '直接跳到第 N 章模块（按当前栏内顺序）' },
        { keys: 'Alt+← / Alt+→', desc: '在当前模块字段内顺序切换' },
        { keys: 'j / k', desc: '在当前实体列表内上下移动选中项（vim 风格）' },
        { keys: 'Esc', desc: '关闭剧本下拉 / 关闭 AI 抽屉' }
      ]
    },
    {
      title: '编辑',
      items: [
        { keys: 'Ctrl+S', desc: '保存当前工作台 / 字段（自动找最近的 save-* 按钮）' },
        { keys: 'Ctrl+Z', desc: '撤销上一步编辑' },
        { keys: 'Ctrl+Y / Ctrl+Shift+Z', desc: '重做上一步撤销' }
      ]
    },
    {
      title: 'AI / 校验',
      items: [
        { keys: '顶栏「验」', desc: '校验剧本冲突，写入运行态' },
        { keys: '顶栏「预」', desc: '运行发布预检（导出守门）' },
        { keys: '顶栏「补齐并运行」', desc: '一键 AI 补齐所有缺失字段' }
      ]
    },
    {
      title: '搜索 / 工具',
      items: [
        { keys: '/', desc: '聚焦实体搜索框（在实体列表工作台下）' },
        { keys: 'Ctrl+Shift+P', desc: '切换性能浮层（渲染耗时、剧本体积、队列）' },
        { keys: 'Shift+?', desc: '打开 / 关闭本快捷键面板' }
      ]
    }
  ];

  function ensureShortcutCheatsheetNode() {
    var node = document.getElementById('shortcut-cheatsheet');
    if (node) return node;
    node = document.createElement('div');
    node.id = 'shortcut-cheatsheet';
    node.setAttribute('role', 'dialog');
    node.setAttribute('aria-modal', 'true');
    node.setAttribute('aria-label', '键盘快捷键参考');
    node.dataset.active = 'false';
    var inner = '<div class="shortcut-cheatsheet-card">' +
      '<div class="shortcut-cheatsheet-head">' +
        '<h2>键盘快捷键</h2>' +
        '<button type="button" class="drawer-close" data-editor-command="close-shortcut-cheatsheet" aria-label="关闭快捷键面板">×</button>' +
      '</div>' +
      '<div class="shortcut-cheatsheet-grid">' +
        SHORTCUT_GROUPS.map(function(group) {
          return '<section class="shortcut-cheatsheet-group">' +
            '<h3>' + escapeHtml(group.title) + '</h3>' +
            '<ul>' + group.items.map(function(item) {
              return '<li><kbd>' + escapeHtml(item.keys) + '</kbd><span>' + escapeHtml(item.desc) + '</span></li>';
            }).join('') + '</ul>' +
          '</section>';
        }).join('') +
      '</div>' +
      '<p class="shortcut-cheatsheet-foot">Esc · Shift+? · 点背景 都可关闭。</p>' +
    '</div>';
    node.innerHTML = '<div class="shortcut-cheatsheet-backdrop" data-editor-command="close-shortcut-cheatsheet"></div>' + inner;
    document.body.appendChild(node);
    return node;
  }

  function toggleShortcutCheatsheet(forceState) {
    var node = ensureShortcutCheatsheetNode();
    var next;
    if (typeof forceState === 'boolean') {
      next = forceState ? 'true' : 'false';
    } else {
      next = node.dataset.active === 'true' ? 'false' : 'true';
    }
    node.dataset.active = next;
    if (next === 'true') {
      var card = node.querySelector('.shortcut-cheatsheet-card');
      if (card) card.focus();
    }
  }

  function renderAll() {
    var perf = ensurePerfState();
    var startedAt = typeof performance !== 'undefined' && performance.now ? performance.now() : Date.now();
    renderAllInner();
    var endedAt = typeof performance !== 'undefined' && performance.now ? performance.now() : Date.now();
    perf.lastMs = endedAt - startedAt;
    perf.totalRenders += 1;
    if (perf.active) renderPerfOverlay();
    // Slice 84 · panels are continually re-injected by various renderers
    // (runtime-editor in particular replaces innerHTML on most updates),
    // so reapply the persisted collapse state after every renderAll pass.
    applyPanelCollapseState();
  }

