      var kind = wrap.getAttribute('data-oc-pan'); var ocs = orgChartState(kind);
      pan = { kind: kind, ocs: ocs, sx: e.clientX, sy: e.clientY, px: ocs.panX, py: ocs.panY, inner: wrap.querySelector('[data-oc-inner="' + kind + '"]') };
