      '<div class="prompt-row"><button class="ai-button" data-editor-command="save-city-registry">保存城市登记</button><button class="ai-button" data-editor-command="add-city-row">新增城市</button><button class="ai-button" data-ai-action="derive" data-field-ai="cities">AI 梳理城市库</button></div>',
