    partyRelations: '党派关系', internalParties: '内部党派', naturalAllies: '天然盟友', history: '历史沿革', strengths: '优势', weaknesses: '劣势', victoryConditions: '胜利条件', defeatConditions: '失败条件', offendThresholds: '触怒阈值',
