  // Keyboard shortcut handler. Save (Ctrl+S) and Undo/Redo always work; field
  // navigation (Alt+←/→) only when focus is outside a text input so typing in
  // an input doesn't jump fields. "/" focuses the entity search input. Esc
  // closes the scenario pill dropdown if open.
  function handleKeydown(event) {
    var isInput = event.target && (
      event.target.tagName === 'INPUT' ||
      event.target.tagName === 'TEXTAREA' ||
      event.target.isContentEditable
    );
    var ctrl = event.ctrlKey || event.metaKey;
    // Save current workbench / field. Always works.
    if (ctrl && (event.key === 's' || event.key === 'S')) {
      event.preventDefault();
      var activeSave = document.querySelector('[data-editor-command^="save-"]');
      if (activeSave) {
        handleEditorCommand(activeSave.dataset.editorCommand, activeSave);
      } else {
        saveSelectedField();
      }
      return;
    }
    // Undo / Redo.
    if (ctrl && !event.shiftKey && (event.key === 'z' || event.key === 'Z')) {
      event.preventDefault();
      undoEdit();
      return;
    }
    if (ctrl && (event.key === 'y' || event.key === 'Y' || (event.shiftKey && (event.key === 'z' || event.key === 'Z')))) {
      event.preventDefault();
      redoEdit();
      return;
    }
    // Ctrl+Shift+P toggles the perf overlay.
    if (ctrl && event.shiftKey && (event.key === 'p' || event.key === 'P')) {
      event.preventDefault();
      togglePerfOverlay();
      return;
    }
    // Slice 68 · Shift+? toggles the keyboard cheatsheet overlay.
    // Layout note: most keyboards emit "?" as the shifted key, so we test
    // both the shifted character and a fallback ("/" + shift = "?" on US).
    if (event.shiftKey && !ctrl && (event.key === '?' || (event.key === '/' && event.shiftKey))) {
      event.preventDefault();
      toggleShortcutCheatsheet();
      return;
    }
    // Esc closes the scenario pill dropdown / shortcut cheatsheet.
    if (event.key === 'Escape') {
      var cheatsheet = document.getElementById('shortcut-cheatsheet');
      if (cheatsheet && cheatsheet.dataset.active === 'true') {
        event.preventDefault();
        toggleShortcutCheatsheet(false);
        return;
      }
      var pill = document.getElementById('scenario-pill');
      if (pill && pill.getAttribute('aria-expanded') === 'true') {
        event.preventDefault();
        toggleScenarioPillMenu(false);
        return;
      }
    }
    if (isInput) return;
    // Prev / next field within current module.
    if (event.altKey && (event.key === 'ArrowLeft' || event.key === 'ArrowRight')) {
      event.preventDefault();
      var module = findModule(state.selectedModuleId);
      var fields = moduleFieldsForDetail(module);
      var idx = fields.indexOf(state.selectedField);
      if (idx < 0) return;
      var next = event.key === 'ArrowLeft' ? (idx - 1 + fields.length) % fields.length : (idx + 1) % fields.length;
      state.selectedField = fields[next];
      state.selectedEntityIndex = 0;
      renderAll();
      return;
    }
    // Slice 60 · Alt+1..Alt+9 jump to Nth module in the current rail order.
    // Honors the user's persisted moduleOrder (Slice 48) by reading DOM order
    // rather than the blueprint order. Skipped when typing into form fields
    // (already filtered above by the isInput guard).
    if (event.altKey && !ctrl && !event.shiftKey && /^[1-9]$/.test(event.key)) {
      var n = parseInt(event.key, 10);
      var tiles = document.querySelectorAll('#module-rail .module-tile[data-module-id]');
      var target = tiles[n - 1];
      if (target && target.dataset.moduleId !== state.selectedModuleId) {
        event.preventDefault();
        state.selectedModuleId = target.dataset.moduleId;
        state.selectedField = (findModule(state.selectedModuleId).topLevelKeys || [])[0];
        state.selectedEntityIndex = 0;
        state.search = '';
        setStatus('已跳转到第 ' + n + ' 章：' + (findModule(state.selectedModuleId).label || state.selectedModuleId), 'neutral');
        renderAll();
        return;
      } else if (target) {
        // Already on this module — still consume the key so it doesn't bubble.
        event.preventDefault();
        return;
      }
    }
    // "/" focuses the entity search box.
    if (event.key === '/' && !ctrl && !event.altKey) {
      var search = document.getElementById('entity-search');
      if (search) {
        event.preventDefault();
        search.focus();
        if (search.setSelectionRange) search.setSelectionRange(search.value.length, search.value.length);
      }
    }
    // Slice 78 · j / k vim navigation in the entity grid.
    // Steps state.selectedEntityIndex by ±1 within the active field's list,
    // wraps at bounds, announces the new position. Active when the focused
    // module has an array-valued selected field (characters / factions / etc.)
    // and the user isn't typing into any input (guarded above).
    if (!ctrl && !event.altKey && !event.shiftKey && (event.key === 'j' || event.key === 'k' || event.key === 'J' || event.key === 'K')) {
      var listValue = state.scenario[state.selectedField];
      if (Array.isArray(listValue) && listValue.length > 0) {
        event.preventDefault();
        var direction = (event.key === 'j' || event.key === 'J') ? 1 : -1;
        var current = typeof state.selectedEntityIndex === 'number' ? state.selectedEntityIndex : 0;
        var total = listValue.length;
        var next = (current + direction + total) % total;
        state.selectedEntityIndex = next;
        renderDetailApp();
        setStatus('已选中 ' + (next + 1) + ' / ' + total + ' · ' + state.selectedField, 'neutral');
        return;
      }
    }
  }

  function wireEvents() {
    document.addEventListener('keydown', handleKeydown);
    document.addEventListener('click', function(event) {
      var railBtn = event.target.closest('#rail-collapse-btn');
      if (railBtn) {
        event.preventDefault();
        toggleRailCollapsed();
        return;
      }
      var inspectorBtn = event.target.closest('#inspector-collapse-btn');
      if (inspectorBtn) {
        event.preventDefault();
        toggleInspectorCollapsed();
        return;
      }
      var pillButton = event.target.closest('#scenario-pill');
      if (pillButton) {
        event.preventDefault();
        toggleScenarioPillMenu();
        return;
      }
      // Clicking outside the pill host should close any open menu.
      // Slice 109 · also close when the click lands on the dropdown's own
      // empty/background area (i.e. inside #scenario-pill-menu but NOT on
      // a menu item, the head row, or the close button). Without this,
      // clicks in the gap between items would silently do nothing and the
      // user perceives the menu as stuck.
      var pillHost = event.target.closest('#scenario-pill-host');
      var pillMenu = event.target.closest('#scenario-pill-menu');
      var menuItem = event.target.closest('.scenario-pill-menu-item, .scenario-pill-menu-head, .scenario-pill-menu-close, .scenario-pill-menu-title');
      if (!pillHost || (pillMenu && !menuItem)) {
        var menu = document.getElementById('scenario-pill-menu');
        var openPill = document.getElementById('scenario-pill');
        if (menu && openPill && openPill.getAttribute('aria-expanded') === 'true') {
          toggleScenarioPillMenu(false);
        }
      }
      var fieldButton = event.target.closest('[data-field-pick]');
      if (fieldButton) {
        // Inner spans (star, AI mini-button) handle their own commands; if
        // the click landed on one of them, skip the field-pick switch so
        // clicking the star only toggles the watch list.
        if (event.target.closest('[data-editor-command]') || event.target.closest('[data-ai-action]')) {
          // Let the command/action handlers below take this event.
        } else {
          event.preventDefault();
          state.selectedField = fieldButton.dataset.fieldPick;
          state.selectedModuleId = inferModuleForField(state.selectedField);
          state.selectedEntityIndex = 0;
          renderAll();
          return;
        }
      }
      var moduleTile = event.target.closest('[data-module-id]');
      if (moduleTile) {
        event.preventDefault();
        state.selectedModuleId = moduleTile.dataset.moduleId;
        state.selectedField = (findModule(state.selectedModuleId).topLevelKeys || [])[0];
        state.selectedEntityIndex = 0;
        state.search = '';
        renderAll();
        return;
      }
      var entityButton = event.target.closest('[data-entity-index]');
      if (entityButton) {
        event.preventDefault();
        state.selectedEntityIndex = Number(entityButton.dataset.entityIndex) || 0;
        renderAll();
        return;
      }
      var refJump = event.target.closest('[data-ref-jump-field]');
      if (refJump) {
        event.preventDefault();
        state.selectedField = refJump.dataset.refJumpField;
        state.selectedModuleId = inferModuleForField(state.selectedField);
        state.selectedEntityIndex = Number(refJump.dataset.refJumpIndex) || 0;
        state.search = '';
        renderAll();
        return;
      }
      var command = event.target.closest('[data-editor-command]');
      if (command) {
        event.preventDefault();
        handleEditorCommand(command.dataset.editorCommand, command);
      }
    });
    document.addEventListener('change', function(event) {
      var fel = event.target && event.target.closest && event.target.closest('[data-folio-char]');
      if (fel) { saveCharFolioField(Number(fel.dataset.folioChar), fel.dataset.folioField, fel.type === 'checkbox' ? fel.checked : fel.value); return; }
      var tadd = event.target && event.target.closest && event.target.closest('[data-folio-trait-add]');
      if (tadd && tadd.value) { addCharTrait(tadd.value); return; }
      var ffel = event.target && event.target.closest && event.target.closest('[data-fac-field]');
      if (ffel) { saveFacFolioField(Number(ffel.dataset.facI), ffel.dataset.facField, ffel.type === 'checkbox' ? ffel.checked : ffel.value); return; }
      var gel = event.target && event.target.closest && event.target.closest('[data-gen-field]');
      if (gel) { saveGenField(gel.dataset.genKind, Number(gel.dataset.genI), gel.dataset.genField, gel.type === 'checkbox' ? gel.checked : gel.value); return; }
      var oel = event.target && event.target.closest && event.target.closest('[data-office-field]');
      if (oel) { saveOfficeField(oel.dataset.officePath, oel.dataset.officeField, oel.value); return; }
      var abr = event.target && event.target.closest && event.target.closest('[data-admin-bind-region]');
      if (abr) { saveRegionAdminBinding(abr.dataset.adminBindRegion, abr.value); return; }
      var ppf = event.target && event.target.closest && event.target.closest('[data-player-pick-faction]');
      if (ppf) { pickFactionForPlayer(ppf.value); return; }
      var ppc = event.target && event.target.closest && event.target.closest('[data-player-pick-char]');
      if (ppc) { pickCharacterForPlayer(ppc.value); return; }
      var cfl = event.target && event.target.closest && event.target.closest('[data-roster-filter]');
      if (cfl) { rosterTBState(cfl.getAttribute('data-roster-filter')).filter = cfl.value; reRenderModulePrimary(); return; }
      var cso = event.target && event.target.closest && event.target.closest('[data-roster-sort]');
      if (cso) { rosterTBState(cso.getAttribute('data-roster-sort')).sort = cso.value; reRenderModulePrimary(); return; }
      var afe = event.target && event.target.closest && event.target.closest('[data-admin-faction]');
      if (afe) { state._adminFaction = afe.value; state._adminDivId = null; reRenderModulePrimary(); }
    });
    document.addEventListener('change', function(event) {
      var rel = event.target && event.target.closest && event.target.closest('[data-frel-edit]');
      if (!rel) return;
      saveFactionRelationField(Number(rel.dataset.frelEdit), rel.dataset.frelField, rel.value);
    });
    document.addEventListener('input', function(event) {
      var csr = event.target && event.target.closest && event.target.closest('[data-roster-search]');
      if (csr) {
        var rkind = csr.getAttribute('data-roster-search');
        rosterTBState(rkind).q = csr.value || '';
        var caret = (typeof csr.selectionStart === 'number') ? csr.selectionStart : (csr.value || '').length;
        reRenderModulePrimary();
        var again = document.querySelector('[data-roster-search="' + rkind + '"]');
        if (again) { again.focus(); try { again.setSelectionRange(caret, caret); } catch (e) {} }
        return;
      }
      if (event.target && event.target.id === 'entity-search') {
        state.search = event.target.value || '';
        renderDetailApp();
      }
      if (event.target && event.target.id === 'global-search-input') {
        state.globalSearchQuery = event.target.value || '';
        renderGlobalSearch();
      }
      if (event.target && event.target.id === 'runtime-field-search') {
        setRuntimeAuditQuery(event.target.value || '');
      }
      // Slice 85 · live text filter on the field cloud — re-render as the
      // creator types so the chip list narrows immediately. Change-event
      // path (above) still handles blur / Enter.
      if (event.target && event.target.dataset && event.target.dataset.fieldFilter === 'text') {
        if (!state.fieldCloudFilter) state.fieldCloudFilter = { provenance: 'all', presence: 'all', text: '' };
        state.fieldCloudFilter.text = event.target.value || '';
        renderDetailApp();
        // Restore focus + caret so typing continues after the re-render.
        var refocus = document.querySelector('[data-field-filter="text"]');
        if (refocus) {
          refocus.focus();
          if (refocus.setSelectionRange && typeof refocus.selectionStart === 'number') {
            var pos = refocus.value.length;
            refocus.setSelectionRange(pos, pos);
          }
        }
      }
      // eraState slider/number live sync — typing one updates the other so
      // both stay in lockstep before the user clicks save.
      if (event.target && event.target.dataset && event.target.dataset.eraStateKey && event.target.dataset.eraStateType === 'range01') {
        var sibling = document.querySelector(
          '[data-era-state-key="' + event.target.dataset.eraStateKey +
          '"][data-era-state-role="' + (event.target.dataset.eraStateRole === 'slider' ? 'number' : 'slider') +
          '"]'
        );
        if (sibling && sibling !== event.target) {
          var raw = event.target.value === '' ? '' : Number(event.target.value);
          if (raw === '' || Number.isFinite(raw)) sibling.value = raw;
        }
      }
    });
    document.addEventListener('change', function(event) {
      if (event.target && event.target.dataset && event.target.dataset.folioField) {
        saveFolioField(event.target.dataset.folioField, event.target.value, event.target);
      }
      if (event.target && event.target.dataset.editorControl === 'workbench-panel-select') {
        setWorkbenchPanel(event.target.value);
      }
      if (event.target && event.target.id === 'ai-reference-file-input') {
        importAiReferenceFiles(event.target.files).catch(function(err) {
          setStatus('AI 参考文件读取失败：' + (err && err.message || err), 'error');
        });
        event.target.value = '';
      }
      if (event.target && event.target.dataset && event.target.dataset.comparisonSide) {
        var side = event.target.dataset.comparisonSide;
        if (side === 'left') state.comparisonLeftId = event.target.value;
        if (side === 'right') state.comparisonRightId = event.target.value;
        renderOfficialComparison();
      }
      if (event.target && event.target.dataset && event.target.dataset.eventsMergeSource && event.target.dataset.eventsMergeKey) {
        toggleEventMergeSelection(event.target.dataset.eventsMergeSource, event.target.dataset.eventsMergeKey);
      }
      if (event.target && event.target.dataset && event.target.dataset.fieldFilter) {
        if (!state.fieldCloudFilter) state.fieldCloudFilter = { provenance: 'all', presence: 'all' };
        state.fieldCloudFilter[event.target.dataset.fieldFilter] = event.target.value;
        renderDetailApp();
      }
      if (event.target && event.target.dataset && event.target.dataset.apiPresetSelect != null) {
        applyApiPreset(event.target.value);
      }
    });
    document.addEventListener('click', function(event) {
      var trigger = event.target.closest('[data-ai-action]');
      if (!trigger) return;
      event.preventDefault();
      event.stopImmediatePropagation();
      var action = trigger.dataset.aiAction;
      if (action === 'accept-draft') acceptDraft();
      else if (action === 'compare-diff') compareDraft();
      else if (action === 'cite-source') citeDraft();
      else if (action === 'regenerate' || action === 'generate' || action === 'polish' || action === 'derive' || action === 'fill-field' || action === 'batch' || action === 'seed-from-map' || action === 'seed-from-old-ui' || action === 'validate') simulateAiDraft(trigger);
      openDrawerForApp();
    }, true);
    var input = document.getElementById('scenario-import-input');
    if (input) input.addEventListener('change', function() {
      importScenario(input.files && input.files[0]);
      input.value = '';
    });
    var packageInput = document.getElementById('project-package-import-input');
    if (packageInput) packageInput.addEventListener('change', function() {
      importProjectPackage(packageInput.files && packageInput.files[0]).catch(function(err) { setStatus('案卷包导入失败：' + (err && err.message || err), 'error'); });
      packageInput.value = '';
    });
  }

  function init() {
    bootstrapChrome();
    bootstrapSectionNav();
    bootstrapAiPromptControls();
    wireEvents();
    // 治 quota：localStorage 没草稿（大剧本可能存在 IndexedDB）时，先异步捞 IndexedDB 草稿再载入。
    if (!readStoredDraft() && global.indexedDB) {
      getDraftBody().then(function (idb) { idbDraftCache = idb || null; idbDraftActive = !!idb; finishInit(); })
        .catch(function () { finishInit(); });
    } else {
      finishInit();
    }
  }
  function finishInit() {
    loadScenario();
    setRailCollapsed(isRailCollapsed());
    setInspectorCollapsed(isInspectorCollapsed());
    applyModuleOrder();
    wireModuleDragHandlers();
    ensurePerfState();
    renderPerfOverlay();
    // Slice 73 · seed the save indicator with the last-saved timestamp
    // from localStorage so creators see "已保存 HH:MM:SS" immediately on
    // load rather than the pill appearing only after the next mutation.
    var stored = readStoredDraft();
    if (stored && stored.savedAt) {
      setSaveIndicator('saved', stored.savedAt);
    } else {
      setSaveIndicator('idle');
    }
    // Honor a #scenario=... share URL on first load.
    importScenarioFromHash();
    document.body.dataset.scenarioEditorResetApp = 'ready';
    ensureMapReturnListener();
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else init();

